    // --------------------------------------------------------
    // Spouse Status for UI
    // --------------------------------------------------------

    function getSpouseStatus() {
        if (!player.spouseId) return null;
        var spouse = Engine.findPerson(player.spouseId);
        if (!spouse || !spouse.alive) return null;
        initSpouseAI();
        var ai = player.spouseAI;
        return {
            name: spouse.firstName + ' ' + spouse.lastName,
            age: spouse.age, sex: spouse.sex,
            health: ai.health, condition: ai.condition,
            gold: ai.gold, activity: ai.activity,
            activityDetail: ai.activityDetail,
            totalEarned: ai.totalEarned,
            managedBuilding: ai.managedBuildingIdx >= 0 ? player.buildings[ai.managedBuildingIdx] : null,
            recentActions: ai.recentActions,
            personality: spouse.personality,
            quirks: spouse.quirks || [],
            relationship: getRelationship(player.spouseId).level
        };
    }

    // ========================================================
    // §11.6D REGENCY SYSTEM
    // ========================================================

    function calculateRegencyScore(spouse, relationshipLevel) {
        if (!spouse || !spouse.personality) return 0;
        const relWeight = (relationshipLevel || 0) * 0.5;
        const loyaltyWeight = (spouse.personality.loyalty || 0) * 0.2;
        const warmthWeight = (spouse.personality.warmth || 0) * 0.15;
        const honestyWeight = (spouse.personality.honesty || 0) * 0.15;
        let score = relWeight + loyaltyWeight + warmthWeight + honestyWeight;
        // Loyal heart quirk: +20 regency score bonus
        if (spouse.quirks && spouse.quirks.includes('loyal_heart')) score += 20;
        return Math.floor(Math.min(100, Math.max(0, score)));
    }

    function getRegencyThreshold(score) {
        if (typeof REGENCY_THRESHOLDS === 'undefined') return null;
        for (const t of REGENCY_THRESHOLDS) {
            if (score >= t.min && score <= t.max) return t;
        }
        return REGENCY_THRESHOLDS[REGENCY_THRESHOLDS.length - 1];
    }

    function enterRegency(spouse, heir) {
        const rel = getRelationship(player.spouseId);
        const regencyScore = calculateRegencyScore(spouse, rel.level);
        const threshold = getRegencyThreshold(regencyScore);

        player.regencyMode = true;
        player.regencyData = {
            spouseId: spouse.id,
            spouseName: spouse.firstName + ' ' + spouse.lastName,
            spouseAlive: true,
            spouseAge: spouse.age,
            spousePersonality: spouse.personality ? { ...spouse.personality } : {},
            spouseQuirks: spouse.quirks ? [...spouse.quirks] : [],
            heirId: heir.id,
            heirName: heir.firstName + ' ' + heir.lastName,
            heirAge: heir.age,
            heirSex: heir.sex,
            regencyScore,
            thresholdLabel: threshold ? threshold.label : 'Unknown',
            goldAtDeath: player.gold,
            buildingsAtDeath: player.buildings.length,
            buildingsCopy: JSON.parse(JSON.stringify(player.buildings)),
            reputationAtDeath: { ...player.reputation },
            monthlyUpdates: [],
            estateGold: player.gold,
            buildingsMaintained: player.buildings.length,
            dayStarted: Engine.getDay(),
            revealedAtDeath: player.revealedTraits[spouse.id] ? JSON.parse(JSON.stringify(player.revealedTraits[spouse.id])) : { traits: {}, quirks: [] },
        };

        Engine.logEvent(`${player.fullName} has passed. ${spouse.firstName} serves as regent for young ${heir.firstName}.`);
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast(`⚰️ You have passed. ${spouse.firstName} will raise ${heir.firstName} until they come of age.`, 'warning', 'my_actions');
        }
    }

    function tickRegency() {
        if (!player.regencyMode || !player.regencyData) return;
        const rd = player.regencyData;
        const rng = Engine.getRng();
        const day = Engine.getDay();

        // Age the heir (1 year per 360 game days)
        const daysSinceStart = day - rd.dayStarted;
        rd.heirAge = Math.floor((Engine.findPerson(rd.heirId) || {}).age || (rd.heirAge + daysSinceStart / 360));

        // Update heir age in the world
        const heir = Engine.findPerson(rd.heirId);
        if (heir) {
            rd.heirAge = heir.age;
        }

        // Check if heir is dead
        if (heir && !heir.alive && !window._godInvincible) {
            // All heirs dead — game over
            player.alive = false;
            player.regencyMode = false;
            player.regencyData = null;
            Engine.logEvent('The heir has died during regency. The legacy ends.');
            return;
        }

        // Check if spouse dies during regency
        if (rd.spouseAlive) {
            const spouse = Engine.findPerson(rd.spouseId);
            if (!spouse || !spouse.alive) {
                rd.spouseAlive = false;
                rd.regencyScore = Math.max(0, rd.regencyScore - 20);
                const threshold = getRegencyThreshold(rd.regencyScore);
                rd.thresholdLabel = threshold ? threshold.label : rd.thresholdLabel;
                rd.monthlyUpdates.push({ day, message: '⚰️ The regent has passed away. The heir is now orphaned.' });
                if (typeof UI !== 'undefined' && UI.toast) {
                    UI.toast('⚰️ Your spouse has died during regency!', 'danger', 'my_actions');
                }
            } else {
                // Check for random spouse death (frail_health quirk increases chance)
                if (rng) {
                    let deathChance = 0.0001;
                    if (rd.spouseQuirks.includes('frail_health')) deathChance *= 3;
                    if (spouse.age > 50) deathChance += 0.0002 * (spouse.age - 50);
                    if (rng.chance(deathChance)) {
                        spouse.alive = false;
                        rd.spouseAlive = false;
                        rd.regencyScore = Math.max(0, rd.regencyScore - 20);
                        const threshold = getRegencyThreshold(rd.regencyScore);
                        rd.thresholdLabel = threshold ? threshold.label : rd.thresholdLabel;
                        rd.monthlyUpdates.push({ day, message: '⚰️ The regent has passed away from illness.' });
                    }
                }
            }
        }

        // Monthly updates (every 30 days)
        if (daysSinceStart > 0 && daysSinceStart % 30 === 0) {
            const threshold = getRegencyThreshold(rd.regencyScore);
            if (!threshold) return;

            // Estate management based on threshold
            if (rd.regencyScore >= 80) {
                // Good management
                const income = Math.floor(rd.buildingsMaintained * 5 + 20);
                rd.estateGold += income;
                rd.monthlyUpdates.push({ day, message: `💰 ${rd.spouseName} maintained all businesses. Estate +${income}g.` });
            } else if (rd.regencyScore >= 60) {
                const income = Math.floor(rd.buildingsMaintained * 3 + 10);
                rd.estateGold += income;
                rd.monthlyUpdates.push({ day, message: `📊 ${rd.spouseName} managed the estate adequately. Estate +${income}g.` });
            } else if (rd.regencyScore >= 40) {
                // May sell buildings
                if (rng && rng.chance(0.15) && rd.buildingsMaintained > 0) {
                    rd.buildingsMaintained = Math.max(0, rd.buildingsMaintained - 1);
                    rd.estateGold += 50;
                    rd.monthlyUpdates.push({ day, message: `🏚️ ${rd.spouseName} sold one of the businesses.` });
                } else {
                    rd.monthlyUpdates.push({ day, message: `📊 ${rd.spouseName} reluctantly managed the household.` });
                }
            } else if (rd.regencyScore >= 20) {
                // Takes wealth
                const taken = Math.floor(rd.estateGold * 0.05);
                rd.estateGold = Math.max(0, rd.estateGold - taken);
                rd.monthlyUpdates.push({ day, message: `💸 ${rd.spouseName} took ${taken}g for personal expenses.` });
            } else {
                // Abandoned
                if (!rd._abandoned) {
                    rd._abandoned = true;
                    rd.estateGold = 0;
                    rd.buildingsMaintained = 0;
                    rd.monthlyUpdates.push({ day, message: `🚪 ${rd.spouseName} abandoned the child and left.` });
                }
            }

            // Quirk effects during regency
            if (rd.spouseAlive) {
                if (rd.spouseQuirks.includes('secret_gambler') && rng) {
                    const loss = rng.randInt(5, 50);
                    rd.estateGold = Math.max(0, rd.estateGold - loss);
                    rd.monthlyUpdates.push({ day, message: `🎲 ${rd.spouseName} gambled away ${loss}g.` });
                }
                if (rd.spouseQuirks.includes('devout')) {
                    const donation = Math.floor(rd.estateGold * 0.05);
                    rd.estateGold = Math.max(0, rd.estateGold - donation);
                    rd.monthlyUpdates.push({ day, message: `🙏 ${rd.spouseName} donated ${donation}g to the poor.` });
                }
            }

            // Heir learning messages
            if (heir && heir.alive) {
                const heirMsgs = [
                    `📖 ${rd.heirName} is learning to read.`,
                    `⚔️ ${rd.heirName} practices swordplay.`,
                    `🧮 ${rd.heirName} studies arithmetic.`,
                    `🐴 ${rd.heirName} learns to ride.`,
                    `📜 ${rd.heirName} studies the family ledgers.`,
                ];
                if (rng && rng.chance(0.3)) {
                    rd.monthlyUpdates.push({ day, message: rng.pick(heirMsgs) });
                }
            }
        }

        // Check if heir reaches COMING_OF_AGE
        if (heir && heir.alive && heir.age >= CONFIG.COMING_OF_AGE) {
            endRegency();
        }
    }

    function endRegency() {
        if (!player.regencyData) return;
        const rd = player.regencyData;
        const heir = Engine.findPerson(rd.heirId);
        if (!heir || !heir.alive) {
            if (!window._godInvincible) {
                player.alive = false;
                player.regencyMode = false;
                player.regencyData = null;
                return;
            }
        }

        const threshold = getRegencyThreshold(rd.regencyScore);
        if (!threshold) {
            player.regencyMode = false;
            player.regencyData = null;
            return;
        }

        // Transfer to heir (similar to handlePlayerDeath heir transfer)
        const oldName = player.fullName;
        player.firstName = heir.firstName;
        player.lastName = heir.lastName;
        player.sex = heir.sex;
        player.fullName = heir.firstName + ' ' + heir.lastName;
        player.age = heir.age;
        player.alive = true;
        player.spouseId = null;
        player.childrenIds = [];
        player.weapon = null;
        player.armor = null;
        player.smugglingSkill = 0;
        player.jailedUntilDay = 0;
        player.horses = []; // Horses don't transfer through regency
        player.storageContainer = null; // Reset container since no horses to pull wagon

        // Gold based on regency outcome
        player.gold = Math.floor(rd.estateGold * threshold.goldPct);

        // Buildings based on regency outcome
        if (threshold.buildingPct >= 1) {
            // Keep all buildings
        } else if (threshold.buildingPct > 0) {
            // Keep random fraction
            const rng = Engine.getRng();
            const keep = Math.ceil(player.buildings.length * threshold.buildingPct);
            if (rng) rng.shuffle(player.buildings);
            player.buildings = player.buildings.slice(0, keep);
        } else {
            player.buildings = [];
            player.employees = [];
        }

        // XP transfer
        const xpTransfer = Math.floor(player.xp / (XP_REWARDS.HEIR_TRANSFER_RATIO || 2));
        const prevGen = (player.achievementStats && player.achievementStats.generation) || 1;
        player.xp = xpTransfer;
        player.totalXp = xpTransfer;
        player.level = 1;
        var hadDynastyFounder = player.skills && player.skills['dynasty_founder'];
        player.skills = { keen_eye: true };
        player.achievements = {};
        player.hunger = HUNGER_CONFIG.START;
        player.marketIntel = {};

        // Skill points: base + threshold bonus + spouse personality bonuses
        let bonusPoints = threshold.bonusSkillPoints;
        const sp = rd.spousePersonality || {};

        if (sp.intelligence >= 70) bonusPoints += 2;
        else if (sp.intelligence < 30) bonusPoints -= 1;
        if (sp.warmth >= 70) bonusPoints += 1;
        else if (sp.warmth < 30) bonusPoints -= 1;

        // Quirk heir effects
        const quirks = rd.spouseQuirks || [];
        for (const qId of quirks) {
            const qDef = (typeof SPOUSE_QUIRKS !== 'undefined') ? SPOUSE_QUIRKS.find(q => q.id === qId) : null;
            if (!qDef) continue;
            switch (qId) {
                // Positive quirk heir effects
                case 'bookworm': bonusPoints += 3; break;
                case 'merchant_family': bonusPoints += 2; break;
                case 'natural_leader': bonusPoints += 2; break;
                case 'animal_lover': bonusPoints += 1; break;
                case 'charming_smile': bonusPoints += 1; break;
                case 'silver_tongue': bonusPoints += 1; break;
                case 'musical': bonusPoints += 1; break;
                case 'patient': bonusPoints += 1; break;
                case 'quick_learner': bonusPoints += 2; break;
                // Negative quirk heir effects
                case 'secret_gambler': bonusPoints -= 1; break;
                case 'violent_temper': bonusPoints -= 1; break;
                case 'paranoid': bonusPoints -= 1; break;
                case 'lazy': bonusPoints -= 1; break;
                case 'hot_headed': bonusPoints -= 1; break;
                // Mixed
                case 'stubborn': bonusPoints += 1; break;
                case 'criminal_past': bonusPoints += 1; break;
            }
            // Track heir traits from quirks
            if (qDef.heirEffect && qDef.heirEffect !== 'No effect') {
                player.heirTraits.push(qId);
            }
        }

        player.skillPoints = Math.max(0, (hadDynastyFounder ? 1 : 0) + bonusPoints);
        checkLevelUp();

        // Reputation
        for (const kId in player.reputation) {
            player.reputation[kId] = Math.floor((rd.reputationAtDeath[kId] || 50) * threshold.repMult);
        }

        // Heir traits
        player.heirTraits = player.heirTraits || [];
        if (rd.regencyScore >= 80) {
            player.heirTraits.push('well_raised');
        }
        if (rd.regencyScore <= 19) {
            player.heirTraits.push('orphan');
        }

        // Noble blood quirk — heir starts one rank higher
        if (quirks.includes('noble_blood') && player.citizenshipKingdomId) {
            const currentRank = player.socialRank[player.citizenshipKingdomId] || 0;
            player.socialRank[player.citizenshipKingdomId] = Math.min(currentRank + 1, 3);
        }

        // Loyal heart quirk — +20 regency score bonus (already factored into score if present)

        // Thrifty quirk — heir starts with 10% more gold
        if (quirks.includes('thrifty')) {
            player.gold = Math.floor(player.gold * 1.10);
        }

        // Diplomatic quirk — +10 reputation
        if (quirks.includes('diplomatic')) {
            for (const kId in player.reputation) {
                player.reputation[kId] = Math.min(100, (player.reputation[kId] || 50) + 10);
            }
        }

        // Manipulative quirk — -10 starting relationships
        if (quirks.includes('manipulative')) {
            const people = Engine.getPeople(player.townId);
            if (people) {
                for (const p of people.slice(0, 10)) {
                    modifyRelationship(p.id, -10);
                }
            }
        }

        // Forgiving quirk — better starting NPC relationships
        if (quirks.includes('forgiving')) {
            const people = Engine.getPeople(player.townId);
            if (people) {
                for (const p of people.slice(0, 10)) {
                    modifyRelationship(p.id, 10);
                }
            }
        }

        // Devout quirk — higher reputation (legacy support)
        if (quirks.includes('devout')) {
            for (const kId in player.reputation) {
                player.reputation[kId] = Math.min(100, (player.reputation[kId] || 50) + 10);
            }
        }

        // Warmth effect on relationships
        if (sp.warmth >= 70) {
            // Start with some positive relationships
            const people = Engine.getPeople(player.townId);
            if (people) {
                for (const p of people.slice(0, 10)) {
                    modifyRelationship(p.id, 15);
                }
            }
        } else if (sp.warmth < 30) {
            player.relationships = {};
        }

        // Reset achievement stats
        player.achievementStats = {
            totalSells: {}, totalBuys: {}, giftsGiven: 0,
            smuggleSuccesses: 0, smuggleStreak: 0, smuggleGoldEarned: 0,
            bribesGiven: 0, seaVoyagesCompleted: 0,
            kingdomsTraded: {}, resourcesTraded: {},
            caravanDestinations: {}, dailyProfit: 0, dailyProfitPrevGold: 0,
            generation: prevGen + 1, wasExiled: false,
        };
        player._xpAccumulator = 0;
        player.warAllegiances = {};
        player.topMerchantDays = 0;
        player.victoriesAchieved = {};
        player.belowMarketSales = 0;
        player.smugglingTaxSaved = 0;
        player.revealedTraits = {};
        player.spouseRelHighDays = 0;
        player.dateProgress = {};
        player.investigatorCaught = {};
        player.spouseProdMod = 1.0;
        player.spouseCostMod = 1.0;
        player.spouseRepMod = 1.0;
        player.spouseHungerMod = 1.0;
        player.spouseLuckMod = 1.0;
        player.spouseProtectMod = 1.0;

        player.regencyMode = false;
        player.regencyData = null;

        Engine.logEvent(`${player.fullName} has come of age and inherits the family legacy! (${threshold.label})`);
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast(`👑 ${player.fullName} comes of age! Regency outcome: ${threshold.label}`, 'success');
        }
    }

    // ========================================================
    // §11.7 PLAYER EQUIPMENT
    // ========================================================
    function getAvailableEquipment(type) {
        const town = Engine.getTown ? Engine.getTown(player.townId) : Engine.findTown(player.townId);
        if (!town) return [];

        const equipTypes = EQUIPMENT_TYPES[type];
        if (!equipTypes) return [];
        const results = [];

        for (const eq of equipTypes) {
            var marketSupply = (town.market && town.market.supply) ? (town.market.supply[eq.resource] || 0) : 0;
            var marketPrice = (town.market && town.market.prices) ? (town.market.prices[eq.resource] || 0) : 0;
            if (marketSupply <= 0) continue;

            const kingdom = Engine.getWorld ? Engine.getWorld().kingdoms.find(function(k) { return k.id === town.kingdomId; }) : null;
            const isBanned = kingdom && kingdom.laws && kingdom.laws.bannedGoods &&
                             kingdom.laws.bannedGoods.includes(eq.resource);
            if (isBanned) {
                var hasLic = player.licenses && player.licenses[kingdom.id] &&
                             player.licenses[kingdom.id].includes(eq.resource);
                if (!hasLic) continue;
            }

            var resType = Object.values(RESOURCE_TYPES).find(function(r) { return r.id === eq.resource; });
            var localPrice = marketPrice || (resType ? resType.basePrice : 35);
            var price = Math.round(localPrice * eq.priceMultiplier);

            results.push({
                id: eq.id,
                name: eq.name,
                resource: eq.resource,
                quality: eq.quality,
                combatBonus: eq.combatBonus,
                priceMultiplier: eq.priceMultiplier,
                price: price,
                isBanned: !!isBanned,
                available: true
            });
        }

        return results;
    }

    function equipWeapon(equipmentId) {
        if (!equipmentId) {
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('Select a weapon to equip.');
            return { success: false, message: 'No weapon selected.' };
        }

        var available = getAvailableEquipment('weapons');
        var eq = available.find(function(e) { return e.id === equipmentId; });
        if (!eq) return { success: false, message: 'That weapon is not available here.' };
        if (player.gold < eq.price) return { success: false, message: 'Not enough gold. Need ' + eq.price + 'g.' };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.equip || 2);

        player.gold -= eq.price;
        if (player.stats) player.stats.totalGoldSpent = (player.stats.totalGoldSpent || 0) + eq.price;

        var town = Engine.getTown ? Engine.getTown(player.townId) : Engine.findTown(player.townId);
        if (town && town.market && town.market.supply && town.market.supply[eq.resource]) {
            town.market.supply[eq.resource] = Math.max(0, town.market.supply[eq.resource] - 1);
        }

        player.weapon = { id: eq.id, name: eq.name, quality: eq.quality, combatBonus: eq.combatBonus };

        return { success: true, message: 'Equipped ' + eq.name + '! (+' + Math.round(eq.combatBonus * 100) + '% combat survival)' };
    }

    function equipArmor(equipmentId) {
        if (!equipmentId) {
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('Select armor to equip.');
            return { success: false, message: 'No armor selected.' };
        }

        var available = getAvailableEquipment('armor');
        var eq = available.find(function(e) { return e.id === equipmentId; });
        if (!eq) return { success: false, message: 'That armor is not available here.' };
        if (player.gold < eq.price) return { success: false, message: 'Not enough gold. Need ' + eq.price + 'g.' };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.equip || 2);

        player.gold -= eq.price;
        if (player.stats) player.stats.totalGoldSpent = (player.stats.totalGoldSpent || 0) + eq.price;

        var town = Engine.getTown ? Engine.getTown(player.townId) : Engine.findTown(player.townId);
        if (town && town.market && town.market.supply && town.market.supply[eq.resource]) {
            town.market.supply[eq.resource] = Math.max(0, town.market.supply[eq.resource] - 1);
        }

        player.armor = { id: eq.id, name: eq.name, quality: eq.quality, combatBonus: eq.combatBonus };

        return { success: true, message: 'Equipped ' + eq.name + '! (+' + Math.round(eq.combatBonus * 100) + '% combat survival)' };
    }

    function unequipWeapon() {
        if (!player.weapon) return { success: false, message: 'No weapon equipped.' };
        player.inventory.swords = (player.inventory.swords || 0) + 1;
        var oldName = (typeof player.weapon === 'object') ? player.weapon.name : 'Sword';
        player.weapon = null;
        return { success: true, message: 'Unequipped ' + oldName + '. Added to inventory.' };
    }

    function unequipArmor() {
        if (!player.armor) return { success: false, message: 'No armor equipped.' };
        player.inventory.armor = (player.inventory.armor || 0) + 1;
        var oldName = (typeof player.armor === 'object') ? player.armor.name : 'Armor';
        player.armor = null;
        return { success: true, message: 'Unequipped ' + oldName + '. Added to inventory.' };
    }

    /**
     * Player combat survival check (e.g., bandit attack on caravan they're traveling with).
     * Returns true if player survives.
     */
    function playerCombatSurvival() {
        let chance = 0.50;
        if (player.weapon) chance += (typeof player.weapon === 'object') ? player.weapon.combatBonus : 0.20;
        if (player.armor) chance += (typeof player.armor === 'object') ? player.armor.combatBonus : 0.30;
        if (hasSkill('battle_hardened')) chance += 0.30;
        else if (hasSkill('combat_trained')) chance += 0.15;
        const rng = Engine.getRng();
        const survived = rng ? rng.random() < chance : true;
        if (survived) {
            grantXP(XP_REWARDS.COMBAT_SURVIVE, 'combat');
            unlockAchievement('survivor');
        }
        return survived;
    }

    // ========================================================
    // §11.9 MILITARY CAREER SYSTEM
    // ========================================================

    function getCombatSurvivalMultiplier() {
        let mult = 1.0;
        if (player.weapon) mult += (typeof player.weapon === 'object') ? player.weapon.combatBonus : 0.20;
        if (player.armor) mult += (typeof player.armor === 'object') ? player.armor.combatBonus : 0.30;
        if (hasSkill('battle_hardened')) mult += 0.30;
        else if (hasSkill('combat_trained')) mult += 0.15;
        return mult;
    }

    function enlistAsSoldier(kingdomId) {
        if (player.militaryActive) return { success: false, message: 'Already enlisted.' };
        if (player.traveling) return { success: false, message: 'Cannot enlist while traveling.' };
        if (!player.alive) return { success: false, message: 'You are dead.' };

        // Females enlist as nurses, not soldiers
        var isNurse = (player.sex === 'F');

        // Check for active war involving this kingdom
        const wars = Engine.getActiveWars ? Engine.getActiveWars() : {};
        let hasWar = false;
        for (const wId in wars) {
            const w = wars[wId];
            if (w.kingdomA === kingdomId || w.kingdomB === kingdomId) { hasWar = true; break; }
        }
        if (!hasWar) return { success: false, message: 'No active war for this kingdom.' };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.enlist || 3);

        // If indentured servant, enlisting frees you from servitude but commits you to 4 years
        var wasIndentured = false;
        if (player.indentured && player.indentured.active) {
            wasIndentured = true;
            player.indentured.active = false;
            var kName = Engine.findKingdom(kingdomId) ? Engine.findKingdom(kingdomId).name : kingdomId;
            var roleLabel = isNurse ? 'medical corps' : 'army';
            Engine.logEvent('⚔️ ' + player.fullName + ' enlisted in ' + kName + '\'s ' + roleLabel + '! The military does not recognize servant contracts. Your servitude is over, but you must serve 4 years.');
            if (typeof UI !== 'undefined' && UI.toast) {
                UI.toast('⛓️➡️' + (isNurse ? '🏥' : '⚔️') + ' Servitude replaced with 4-year military commitment!', 'success', 'military');
            }
            if (typeof discoverEscape === 'function') discoverEscape('military_enlist');
            grantXP(30, 'military escape from servitude');
        }

        player.militaryActive = true;
        player.militaryKingdomId = kingdomId;
        player.militaryDayEnlisted = Engine.getDay();
        player.militaryRole = isNurse ? 'nurse' : 'soldier';

        if (isNurse) {
            if (!player.militaryRank) player.militaryRank = 'field_nurse';
        } else {
            if (!player.militaryRank) player.militaryRank = 'militiaman';
        }

        // Set mandatory service if freed from indenture (4 years = 1460 days)
        if (wasIndentured) {
            player.militaryMandatory = true;
            player.militaryServiceEndDay = Engine.getDay() + 1460;
        }

        const rng = Engine.getRng();
        player.militaryNextBattleDay = Engine.getDay() + (rng ? rng.randInt(3, 5) : 4);

        var rankLabel = isNurse ? NURSE_RANK_LABELS[player.militaryRank] : MILITARY_RANK_LABELS[player.militaryRank];
        if (!wasIndentured) {
            Engine.logEvent(player.fullName + ' enlisted as a ' + rankLabel + ' for ' + (Engine.findKingdom(kingdomId) ? Engine.findKingdom(kingdomId).name : kingdomId) + '!');
            if (typeof UI !== 'undefined' && UI.toast) {
                UI.toast((isNurse ? '🏥' : '⚔️') + ' Enlisted as ' + rankLabel + '!', 'success', 'military');
            }
        }
        return { success: true, message: wasIndentured
            ? 'Your servant contract is void! You must serve 4 years of mandatory military duty.'
            : 'Enlisted as ' + rankLabel + '.' };
    }

    function quitMilitary() {
        if (!player.militaryActive) return { success: false, message: 'Not currently enlisted.' };
        // Block quitting during border service — must reach Knight for citizenship
        if (player.militaryBorderService) {
            return { success: false, message: 'You enlisted to earn citizenship through military service. You must reach the rank of Knight before you can leave. Desertion means death.' };
        }
        // Block quitting during mandatory service (e.g. indentured servant escape)
        if (player.militaryMandatory) {
            var daysLeft = Math.max(0, (player.militaryServiceEndDay || 0) - Engine.getDay());
            return { success: false, message: 'You have a mandatory military commitment! ' + daysLeft + ' days remaining. Desertion means death.' };
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.quit_military || 2);
        player.militaryActive = false;
        player.militaryNextBattleDay = 0;
        Engine.logEvent(`${player.fullName} left military service as a ${MILITARY_RANK_LABELS[player.militaryRank] || 'soldier'}.`);
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast('🏠 Left military service. Rank preserved.', 'info', 'military');
        }
        return { success: true, message: 'Left military service. Your rank is preserved.' };
    }

    function tickMilitaryCareer() {
        if (!player.militaryActive || !player.alive) return;

        // Check if mandatory service has expired
        if (player.militaryMandatory && Engine.getDay() >= (player.militaryServiceEndDay || 0)) {
            player.militaryMandatory = false;
            player.militaryServiceEndDay = 0;
            var serviceType = player.militaryRole === 'nurse' ? 'medical' : 'military';
            Engine.logEvent('🎖️ ' + player.fullName + '\'s mandatory ' + serviceType + ' service is complete! You may now leave or continue serving.');
            if (typeof UI !== 'undefined' && UI.toast) {
                UI.toast('🎖️ Mandatory service complete! You are free to leave.', 'success');
            }
        }

        // Check war is still active
        const wars = Engine.getActiveWars ? Engine.getActiveWars() : {};
        let warActive = false;
        let enemyKingdomId = null;
        for (const wId in wars) {
            const w = wars[wId];
            if (w.kingdomA === player.militaryKingdomId || w.kingdomB === player.militaryKingdomId) {
                warActive = true;
                enemyKingdomId = w.kingdomA === player.militaryKingdomId ? w.kingdomB : w.kingdomA;
                break;
            }
        }
        if (!warActive) {
            if (player.militaryMandatory) {
                player.hunger = Math.max(player.hunger, HUNGER_CONFIG.START * 0.8);
                return;
            }
            player.militaryActive = false;
            player.militaryNextBattleDay = 0;
            Engine.logEvent('The war has ended. You are no longer enlisted.');
            if (typeof UI !== 'undefined' && UI.toast) {
                UI.toast('🕊️ War ended. Military service complete.', 'info', 'military');
            }
            return;
        }

        // Fed for free while enlisted
        player.hunger = Math.max(player.hunger, HUNGER_CONFIG.START * 0.8);

        // Check if it's battle/shift day
        const day = Engine.getDay();
        if (day < player.militaryNextBattleDay) return;

        const rng = Engine.getRng();
        var isNurse = (player.militaryRole === 'nurse');

        if (isNurse) {
            // ── NURSE SHIFT — treat wounded soldiers ──
            var nurseRank = player.militaryRank || 'field_nurse';
            var nurseDeath = NURSE_DEATH_CHANCE[nurseRank] || 0.0008;

            // Nurses have lower death chance but it's still possible (field hospitals get attacked)
            if (rng && rng.random() < nurseDeath && !window._godInvincible) {
                Engine.logEvent(player.fullName + ' was killed when the field hospital was attacked!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('☠️ Killed in a field hospital attack!', 'danger', 'critical');
                player.alive = false;
                player.militaryActive = false;
                return;
            }

            // Treat soldiers — generates unique benefits
            var soldiersHealed = rng ? rng.randInt(2, 8) : 4;
            var nursePay = NURSE_PAY[nurseRank] || 4;
            player.gold += nursePay;
            player.stats.totalGoldEarned += nursePay;

            // Nursing XP
            grantXP(XP_REWARDS.COMBAT_SURVIVE || 5, 'nursing');

            // Small injury risk from working with wounded (infection, exhaustion)
            if (rng && rng.chance(0.015)) {
                player.illnesses = player.illnesses || [];
                player.illnesses.push({ type: 'infection', severity: 'mild', dayOccurred: day, treated: false });
                Engine.logEvent('🤒 ' + player.fullName + ' contracted an infection while treating wounded soldiers.');
            }

            // Reputation gain (nurses are deeply respected)
            player.reputation[player.militaryKingdomId] = Math.min(100,
                (player.reputation[player.militaryKingdomId] || 50) + 3);

            // Herbalism / medicine skill training
            if (!player.jobExperience) player.jobExperience = {};
            player.jobExperience.nursing = (player.jobExperience.nursing || 0) + 1;

            // Promotion check (20% chance)
            if (rng && rng.chance(0.20)) {
                var curNurseIdx = NURSE_RANKS.indexOf(nurseRank);
                if (curNurseIdx >= 0 && curNurseIdx < NURSE_RANKS.length - 1) {
                    var newNurseRank = NURSE_RANKS[curNurseIdx + 1];
                    player.militaryRank = newNurseRank;
                    Engine.logEvent(player.fullName + ' promoted to ' + NURSE_RANK_LABELS[newNurseRank] + '!');
                    if (typeof UI !== 'undefined' && UI.toast) UI.toast('⬆️ Promoted to ' + NURSE_RANK_LABELS[newNurseRank] + '!', 'success', 'military');
                    // Chief Healer = automatic citizenship
                    if (newNurseRank === 'chief_healer' && player.militaryKingdomId) {
                        if (!player.socialRank[player.militaryKingdomId] || player.socialRank[player.militaryKingdomId] < 1) {
                            player.socialRank[player.militaryKingdomId] = 1;
                            player.rankSince[player.militaryKingdomId] = day;
                            if (!player.citizenshipKingdomId) player.citizenshipKingdomId = player.militaryKingdomId;
                            Engine.logEvent(player.fullName + ' granted citizenship as Chief Healer!');
                        }
                    }
                }
            }

            Engine.logEvent('🏥 Treated ' + soldiersHealed + ' wounded soldiers. Earned ' + nursePay + 'g as ' + NURSE_RANK_LABELS[nurseRank] + '.');
            player.militaryNextBattleDay = day + (rng ? rng.randInt(3, 5) : 4);

        } else {
            // ── SOLDIER BATTLE — original combat logic ──
            const rank = player.militaryRank || 'militiaman';
            const baseDeath = MILITARY_DEATH_CHANCE[rank] || 0.0025;
            const combatMult = getCombatSurvivalMultiplier();
            const deathChance = Math.max(0.0001, baseDeath / combatMult);
            var baseInjury = { militiaman: 0.04, footman: 0.03, sergeant: 0.02, knight: 0.01 };
            const injuryChance = Math.max(0.005, (baseInjury[rank] || 0.04) / combatMult);

            if (rng && rng.random() < deathChance && !window._godInvincible) {
                Engine.logEvent(player.fullName + ' was killed in battle as a ' + MILITARY_RANK_LABELS[rank] + '.');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('☠️ Killed in battle!', 'danger', 'critical');
                player.alive = false;
                player.militaryActive = false;
                return;
            }

            player.battlesSurvived++;
            player.battlesWon++;
            grantXP(XP_REWARDS.COMBAT_SURVIVE, 'battle');

            if (rng && rng.random() < injuryChance) {
                inflictRandomInjury('battle');
            }

            const pay = MILITARY_PAY[rank] || 5;
            player.gold += pay;
            player.stats.totalGoldEarned += pay;

            player.reputation[player.militaryKingdomId] = Math.min(100,
                (player.reputation[player.militaryKingdomId] || 50) + 2);
            if (enemyKingdomId) {
                player.reputation[enemyKingdomId] = Math.max(0,
                    (player.reputation[enemyKingdomId] || 50) - 1);
            }

            if (rng && rng.random() < 0.25) {
                const currentIdx = MILITARY_RANKS.indexOf(rank);
                if (currentIdx >= 0 && currentIdx < MILITARY_RANKS.length - 1) {
                    const newRank = MILITARY_RANKS[currentIdx + 1];
                    player.militaryRank = newRank;
                    Engine.logEvent(player.fullName + ' promoted to ' + MILITARY_RANK_LABELS[newRank] + '!');
                    if (typeof UI !== 'undefined' && UI.toast) UI.toast('⬆️ Promoted to ' + MILITARY_RANK_LABELS[newRank] + '!', 'success', 'military');
                    if (newRank === 'knight' && player.militaryKingdomId) {
                        if (!player.socialRank[player.militaryKingdomId] || player.socialRank[player.militaryKingdomId] < 1) {
                            player.socialRank[player.militaryKingdomId] = 1;
                            player.rankSince[player.militaryKingdomId] = day;
                            if (!player.citizenshipKingdomId) player.citizenshipKingdomId = player.militaryKingdomId;
                            Engine.logEvent(player.fullName + ' granted citizenship as a Knight!');
                        }
                        // Clear border service obligation — they earned citizenship
                        if (player.militaryBorderService) {
                            player.militaryBorderService = false;
                            player.militaryMandatory = false;
                            Engine.logEvent('🏰 ' + player.fullName + ' has earned citizenship through military service! Free to leave or continue serving.');
                            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🏰 Citizenship earned! You may now leave the military or continue serving.', 'success', 'military');
                        }
                    }
                }
            }

            Engine.logEvent('Battle survived! Earned ' + pay + 'g as ' + MILITARY_RANK_LABELS[rank] + '.');
            player.militaryNextBattleDay = day + (rng ? rng.randInt(3, 5) : 4);
        }
    }

    // ========================================================
    // §11.10 INJURY & ILLNESS SYSTEM
    // ========================================================

    function inflictRandomInjury(source) {
        const rng = Engine.getRng();
        if (!rng) return;
        const type = INJURY_TYPES[rng.randInt(0, INJURY_TYPES.length - 1)];
        let severity = type.severity;
        // Existing injuries increase chance of getting a worse injury
        const existingCount = player.injuries.length;
        if (existingCount > 0 && rng.random() < 0.15 * existingCount) {
            // Bump severity: minor→moderate, moderate→severe
            if (severity === 'minor') severity = 'moderate';
            else if (severity === 'moderate') severity = 'severe';
        }
        const injury = {
            type: type.id,
            name: type.name,
            severity: severity,
            dayOccurred: Engine.getDay(),
            treated: false,
            healDay: Engine.getDay() + type.healDays,
            source: source || 'unknown'
        };
        player.injuries.push(injury);
        Engine.logEvent(`${player.fullName} sustained ${type.name} (${severity}).`);
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast(`🩹 Injury: ${type.name} (${severity})`, 'danger');
        }
    }

    function inflictRandomIllness(source) {
        const rng = Engine.getRng();
        if (!rng) return;
        // Housing disease resistance — player's primary home reduces illness chance
        var dReduction = getHousingDiseaseReduction();
        if (dReduction > 0 && rng.chance(dReduction)) {
            Engine.logEvent(player.fullName + '\'s housing protected them from illness.');
            return;
        }
        const type = ILLNESS_TYPES[rng.randInt(0, ILLNESS_TYPES.length - 1)];
        const illness = {
            type: type.id,
            name: type.name,
            severity: type.severity,
            dayOccurred: Engine.getDay(),
            treated: false,
            healDay: Engine.getDay() + type.healDays,
            source: source || 'unknown'
        };
        player.illnesses.push(illness);
        Engine.logEvent(`${player.fullName} contracted ${type.name} (${type.severity}).`);
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast(`🤒 Illness: ${type.name} (${type.severity})`, 'warning');
        }
    }

    function inflictSpecificIllness(illnessId, source) {
        const type = ILLNESS_TYPES.find(t => t.id === illnessId);
        if (!type) return;
        // Housing disease resistance
        var dReduction = getHousingDiseaseReduction();
        var rng = Engine.getRng();
        if (dReduction > 0 && rng && rng.chance(dReduction)) {
            Engine.logEvent(player.fullName + '\'s housing protected them from ' + type.name + '.');
            return;
        }
        const illness = {
            type: type.id,
            name: type.name,
            severity: type.severity,
            dayOccurred: Engine.getDay(),
            treated: false,
            healDay: Engine.getDay() + type.healDays,
            source: source || 'unknown'
        };
        player.illnesses.push(illness);
        Engine.logEvent(`${player.fullName} contracted ${type.name}.`);
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast(`🤒 Illness: ${type.name}`, 'warning');
        }
    }

    function visitHospital(conditionIndex, isIllness) {
        const town = Engine.findTown(player.townId);
        if (!town) return { success: false, message: 'Not in a town.' };

        // Check for hospital: building type or city+
        const hasHospital = (town.buildings && town.buildings.some(b =>
            b.type === 'hospital' || (b.type && b.type.includes('medical'))
        )) || town.category === 'city' || town.category === 'capital_city';

        if (!hasHospital) return { success: false, message: 'No hospital in this town. Try a city or capital.' };

        const list = isIllness ? player.illnesses : player.injuries;
        if (conditionIndex < 0 || conditionIndex >= list.length) return { success: false, message: 'Invalid condition.' };

        const condition = list[conditionIndex];
        const typeDef = isIllness
            ? ILLNESS_TYPES.find(t => t.id === condition.type)
            : INJURY_TYPES.find(t => t.id === condition.type);
        if (!typeDef) return { success: false, message: 'Unknown condition type.' };

        const cost = typeDef.productCost * 5;
        if (player.gold < cost) return { success: false, message: `Not enough gold. Hospital costs ${cost}g.` };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.visit_hospital || 5);

        player.gold -= cost;
        player.stats.totalGoldSpent += cost;
        list.splice(conditionIndex, 1);

        Engine.logEvent(`${player.fullName} was treated at the hospital for ${condition.name} (${cost}g).`);
        return { success: true, message: `Treated ${condition.name} at the hospital for ${cost}g.` };
    }

    function selfTreat(conditionIndex, isIllness) {
        if (!hasSkill('doctor') && !hasSkill('first_aid') && !hasSkill('field_medic')) return { success: false, message: 'You need First Aid, Field Medic, or Doctor skill to self-treat.' };

        const list = isIllness ? player.illnesses : player.injuries;
        if (conditionIndex < 0 || conditionIndex >= list.length) return { success: false, message: 'Invalid condition.' };

        const condition = list[conditionIndex];
        const typeDef = isIllness
            ? ILLNESS_TYPES.find(t => t.id === condition.type)
            : INJURY_TYPES.find(t => t.id === condition.type);
        if (!typeDef) return { success: false, message: 'Unknown condition type.' };

        // first_aid: only minor injuries/illnesses. field_medic: minor+moderate. doctor: all.
        if (!hasSkill('doctor')) {
            if (condition.severity === 'severe') return { success: false, message: 'Only the Doctor skill can treat severe conditions.' };
            if (condition.severity === 'moderate' && !hasSkill('field_medic')) return { success: false, message: 'Need Field Medic or Doctor skill for moderate conditions.' };
        }

        // Check for product in inventory
        const productId = typeDef.product;
        if (!player.inventory[productId] || player.inventory[productId] < 1) {
            return { success: false, message: `Need ${productId} in inventory to self-treat.` };
        }

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.self_treat || 3);

        player.inventory[productId]--;
        condition.treated = true;
        var healDays = Math.ceil(typeDef.healDays / 2);
        if (hasSkill('first_aid')) healDays = Math.ceil(healDays * 0.75); // 25% faster with first_aid
        condition.healDay = Engine.getDay() + healDays;

        Engine.logEvent(`${player.fullName} self-treated ${condition.name} with ${productId}.`);
        return { success: true, message: `Self-treated ${condition.name}. Healing faster.` };
    }

    // Field Medic skill: treat injured NPCs in town for gold
    function treatOther() {
        if (!hasSkill('field_medic') && !hasSkill('doctor')) {
            return { success: false, message: 'You need the Field Medic or Doctor skill to treat others.' };
        }
        if (player.traveling) return { success: false, message: 'Cannot treat others while traveling.' };

        var town = Engine.findTown(player.townId);
        if (!town) return { success: false, message: 'No town found.' };

        // Find an injured/ill NPC in town
        var people = town.people || [];
        var patient = null;
        for (var i = 0; i < people.length; i++) {
            var p = people[i];
            if (!p || !p.alive) continue;
            if ((p.injuries && p.injuries.length > 0) || (p.illnesses && p.illnesses.length > 0)) {
                patient = p;
                break;
            }
        }

        if (!patient) {
            return { success: false, message: 'No one in town needs medical attention right now.' };
        }

        // Check we have medical supplies
        var supplies = ['bandages', 'herbal_remedy', 'healing_tonic', 'herbal_poultice', 'splint', 'fever_tonic', 'antidote'];
        var hasSupply = false;
        var usedSupply = '';
        for (var s = 0; s < supplies.length; s++) {
            if (player.inventory[supplies[s]] && player.inventory[supplies[s]] > 0) {
                hasSupply = true;
                usedSupply = supplies[s];
                break;
            }
        }
        if (!hasSupply) {
            return { success: false, message: 'You need medical supplies (bandages, remedies, tonics) to treat others.' };
        }

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.treat_other || 5);

        player.inventory[usedSupply]--;

        // Heal the NPC
        if (patient.injuries && patient.injuries.length > 0) {
            patient.injuries.shift();
        } else if (patient.illnesses && patient.illnesses.length > 0) {
            patient.illnesses.shift();
        }

        // Payment based on skill level
        var basePay = hasSkill('doctor') ? 25 : 15;
        // Nurse military rank bonus
        if (player.militaryRank === 'nurse') basePay = Math.floor(basePay * 1.5);
        player.gold += basePay;
        player.stats.totalGoldEarned += basePay;
        grantXP(5, 'medical');

        // Relationship boost
        modifyRelationship(patient.id, 10);

        Engine.logEvent(`⚕️ ${player.fullName} treated ${patient.name || 'a townsperson'} and earned ${basePay}g.`);
        return { success: true, message: `Treated ${patient.name || 'a townsperson'} using ${usedSupply}. Earned ${basePay}g.` };
    }

    function tickInjuriesAndIllnesses() {
        const day = Engine.getDay();
        const rng = Engine.getRng();

        // Process injuries
        for (let i = player.injuries.length - 1; i >= 0; i--) {
            const inj = player.injuries[i];
            if (inj.treated && day >= inj.healDay) {
                player.injuries.splice(i, 1);
                Engine.logEvent(`${player.fullName}'s ${inj.name} has healed.`);
                continue;
            }
            if (!inj.treated) {
                const daysUntreated = day - inj.dayOccurred;

                if (inj.severity === 'minor') {
                    // Minor: self-heals in 5-30 days (based on injury type healDays)
                    const typeDef = INJURY_TYPES.find(t => t.id === inj.type);
                    const healTime = typeDef ? Math.max(5, Math.min(30, typeDef.healDays * 2)) : 15;
                    if (daysUntreated >= healTime) {
                        player.injuries.splice(i, 1);
                        Engine.logEvent(`${player.fullName}'s ${inj.name} has naturally healed.`);
                        if (typeof UI !== 'undefined' && UI.toast) UI.toast(`💚 ${inj.name} healed naturally`, 'success');
                        continue;
                    }
                } else if (inj.severity === 'moderate') {
                    // Moderate: self-heals in 30-90 days, but small daily chance of becoming severe
                    const typeDef = INJURY_TYPES.find(t => t.id === inj.type);
                    const healTime = typeDef ? Math.max(30, Math.min(90, typeDef.healDays * 4)) : 60;
                    if (daysUntreated >= healTime) {
                        player.injuries.splice(i, 1);
                        Engine.logEvent(`${player.fullName}'s ${inj.name} has naturally healed.`);
                        if (typeof UI !== 'undefined' && UI.toast) UI.toast(`💚 ${inj.name} healed naturally`, 'success');
                        continue;
                    }
                    // 1% daily chance of worsening to severe if untreated
                    if (daysUntreated >= 10 && rng && rng.random() < 0.01) {
                        inj.severity = 'severe';
                        Engine.logEvent(`${player.fullName}'s ${inj.name} has worsened to severe!`);
                        if (typeof UI !== 'undefined' && UI.toast) UI.toast(`⚠️ ${inj.name} is now severe!`, 'danger');
                    }
                } else if (inj.severity === 'severe') {
                    // Severe: NO self-healing. Kills in 30-90 days (~1.5% daily death = ~50% by day 45)
                    if (daysUntreated >= 30 && rng && rng.random() < 0.015 && !window._godInvincible) {
                        Engine.logEvent(`${player.fullName} died from untreated ${inj.name}.`);
                        if (typeof UI !== 'undefined' && UI.toast) UI.toast(`☠️ Died from untreated ${inj.name}!`, 'danger', 'critical');
                        player.alive = false;
                        return;
                    }
                }
            }
        }

        // Process illnesses
        for (let i = player.illnesses.length - 1; i >= 0; i--) {
            const ill = player.illnesses[i];
            if (ill.treated && day >= ill.healDay) {
                player.illnesses.splice(i, 1);
                Engine.logEvent(`${player.fullName} recovered from ${ill.name}.`);
                continue;
            }
            if (!ill.treated) {
                const daysUntreated = day - ill.dayOccurred;
                if (ill.severity === 'minor' && daysUntreated >= 10) {
                    ill.severity = 'moderate';
                    Engine.logEvent(`${player.fullName}'s ${ill.name} has worsened!`);
                } else if (ill.severity === 'moderate' && daysUntreated >= 25) {
                    ill.severity = 'severe';
                    Engine.logEvent(`${player.fullName}'s ${ill.name} is now severe!`);
                } else if (ill.severity === 'severe') {
                    const typeDef = ILLNESS_TYPES.find(t => t.id === ill.type);
                    const deathRisk = (typeDef && typeDef.deathRisk) ? typeDef.deathRisk : 0.05;
                    if (rng && rng.random() < deathRisk && !window._godInvincible) {
                        Engine.logEvent(`${player.fullName} died from ${ill.name}.`);
                        if (typeof UI !== 'undefined' && UI.toast) UI.toast(`☠️ Died from ${ill.name}!`, 'danger', 'critical');
                        player.alive = false;
                        return;
                    }
                }
            }
        }
    }

    function getWorstConditionSeverity() {
        let worst = null;
        const severities = { minor: 1, moderate: 2, severe: 3 };
        for (const inj of player.injuries) {
            if (!worst || severities[inj.severity] > severities[worst]) worst = inj.severity;
        }
        for (const ill of player.illnesses) {
            if (!worst || severities[ill.severity] > severities[worst]) worst = ill.severity;
        }
        return worst;
    }

    function getWorkEfficiencyModifier() {
        let modifier = 1.0;
        for (const inj of player.injuries) {
            const typeDef = INJURY_TYPES.find(t => t.id === inj.type);
            if (typeDef && typeDef.debuffs && typeDef.debuffs.workEfficiency) {
                modifier += typeDef.debuffs.workEfficiency;
            }
        }
        for (const ill of player.illnesses) {
            const sev = ill.severity;
            if (sev === 'severe') modifier -= 0.50;
            else if (sev === 'moderate') modifier -= 0.25;
            else if (sev === 'minor') modifier -= 0.10;
        }
        return Math.max(0.10, modifier); // minimum 10% efficiency
    }

    function canDoPhysicalWork() {
        const sev = getWorstConditionSeverity();
        if (sev === 'severe') return false;
        // Broken bones block physical work
        for (const inj of player.injuries) {
            const typeDef = INJURY_TYPES.find(t => t.id === inj.type);
            if (typeDef && typeDef.debuffs && typeDef.debuffs.blocksPhysical) return false;
        }
        return true;
    }

    function canDoAnyWork() {
        const sev = getWorstConditionSeverity();
        return sev !== 'severe';
    }

    // Get combined injury debuff effects for use by other systems
    function getInjuryDebuffs() {
        const result = { hungerRate: 1.0, travelSpeed: 0, xpMult: 1.0, tradePenalty: 0, goldDrain: 0 };
        for (const inj of player.injuries) {
            const typeDef = INJURY_TYPES.find(t => t.id === inj.type);
            if (!typeDef || !typeDef.debuffs) continue;
            const d = typeDef.debuffs;
            if (d.hungerRate) result.hungerRate = Math.max(result.hungerRate, d.hungerRate);
            if (d.travelSpeed) result.travelSpeed = Math.min(result.travelSpeed, d.travelSpeed);
            if (d.xpMult) result.xpMult = Math.min(result.xpMult, d.xpMult);
            if (d.tradePenalty) result.tradePenalty = Math.min(result.tradePenalty, d.tradePenalty);
            if (d.goldDrain) result.goldDrain += d.goldDrain;
        }
        return result;
    }

    // ========================================================
    // §11.11 SKILL POINT PASSING TO CHILDREN
    // ========================================================

    function teachChild(childId, skillId) {
        if (!player.alive) return { success: false, message: 'You are dead.' };
        if (player.skillPoints < 3) return { success: false, message: 'Need 3 skill points to teach (gives child 1 SP).' };
        if (!hasSkill(skillId)) return { success: false, message: 'You must know the skill to teach it.' };

        const child = Engine.findPerson ? Engine.findPerson(childId) : null;
        if (!child || !child.alive) return { success: false, message: 'Child not found or not alive.' };
        if (!player.childrenIds.includes(childId)) return { success: false, message: 'Not your child.' };
        if (child.age < 10) return { success: false, message: 'Child must be at least 10 years old.' };

        const passed = player.skillPointsPassedToChild[childId] || 0;
        if (passed >= 5) return { success: false, message: 'Already taught maximum (5) skill points to this child.' };

        player.skillPoints -= 3;
        player.skillPointsPassedToChild[childId] = passed + 1;

        // Store taught skills on the child NPC
        if (!child.taughtSkills) child.taughtSkills = [];
        child.taughtSkills.push(skillId);

        Engine.logEvent(`${player.fullName} taught ${child.firstName} about ${skillId} (3 SP → 1 SP for heir).`);
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast(`📚 Taught ${child.firstName}! (${passed + 1}/5 points)`, 'success');
        }
        return { success: true, message: `Taught ${child.firstName}. ${passed + 1}/5 skill points passed.` };
    }

    // ========================================================
    // §11.12 JOB EXPERIENCE & SKILL LEARNING
    // ========================================================

    function trackJobExperience(jobType, days) {
        if (!jobType) return;
        player.jobExperience[jobType] = (player.jobExperience[jobType] || 0) + days;

        // Check if threshold reached for free skill
        const threshold = JOB_SKILL_THRESHOLDS[jobType];
        if (threshold && player.jobExperience[jobType] >= threshold.days && !hasSkill(threshold.skill)) {
            // Ensure the skill exists in SKILLS
            if (typeof SKILLS !== 'undefined' && SKILLS[threshold.skill]) {
                player.skills[threshold.skill] = true;
                Engine.logEvent(`${player.fullName} learned ${threshold.name} from work experience!`);
                if (typeof UI !== 'undefined' && UI.toast) {
                    UI.toast(`📚 Learned ${threshold.name} from work experience!`, 'success');
                }
            }
        }
    }

    function getJobSkillProgress(jobType) {
        const threshold = JOB_SKILL_THRESHOLDS[jobType];
        if (!threshold) return null;
        if (hasSkill(threshold.skill)) return null; // already learned
        const current = player.jobExperience[jobType] || 0;
        return { current, needed: threshold.days, skillName: threshold.name };
    }
