    function doWork(jobIndex) {
        const jobs = getAvailableJobs();
        if (jobIndex < 0 || jobIndex >= jobs.length) return { success: false, message: 'Invalid job.' };
        if (player.traveling) return { success: false, message: 'Cannot work while traveling.' };
        if (player.jailedUntilDay > 0 && Engine.getDay() < player.jailedUntilDay) {
            return { success: false, message: 'Cannot work while in jail.' };
        }
        if (player.workingUntilTick > 0 && player.workingUntilTick > Engine.getDay()) {
            return { success: false, message: 'Already working on a job.' };
        }
        if (player.autoTravelJob) {
            return { success: false, message: 'Cannot take jobs while on an auto-travel mission.' };
        }

        const job = jobs[jobIndex];
        const rng = Engine.getRng();
        const ticksRequired = job.ticks || 20;

        // Tournament: special multi-round handler
        if (job.isTournament) {
            return enterTournament(job);
        }

        // Auto-travel jobs: start a multi-leg mission instead of instant completion
        if (job.autoTravel) {
            if (player.autoTravelJob) return { success: false, message: 'Already on an auto-travel mission.' };
            return startAutoTravelJob(job);
        }

        // Energy check — do we have enough energy for this job?
        var jobEnergyCostPerTick = getJobEnergyCostPerTick(job);
        var jobEnergyCost = jobEnergyCostPerTick * ticksRequired;
        var energyCheck = checkEnergyForAction(jobEnergyCost);
        if (energyCheck.blocked) return { success: false, message: energyCheck.message };

        // Consume energy for the job
        consumeEnergy(jobEnergyCost);

        // Apply low-energy debuff to pay if applicable
        var energyPayMod = 1.0 + getLowEnergyModifier('workPay');

        // Death risk check
        if (job.deathRisk && rng && rng.random() < job.deathRisk && !window._godInvincible) {
            Engine.logEvent(`${player.fullName} was killed while working as ${job.name}.`);
            if (typeof UI !== 'undefined' && UI.toast) UI.toast(`☠️ Killed during ${job.name}!`, 'danger', 'critical');
            player.alive = false;
            return { success: true, message: `Fatal accident during ${job.name}.` };
        }

        // Injury risk check
        if (job.injuryRisk && rng && rng.random() < job.injuryRisk) {
            inflictRandomInjury(job.name);
        }

        // Illness risk check
        if (job.illnessRisk && rng && rng.random() < job.illnessRisk) {
            if (job.jobTypeKey === 'plague_nurse' || job.name.includes('Plague') || job.name.includes('Gravedigger')) {
                inflictSpecificIllness('plague', job.name);
            } else {
                inflictRandomIllness(job.name);
            }
        }

        // Apply work efficiency modifier from injuries/illnesses + energy
        const efficiency = getWorkEfficiencyModifier() * energyPayMod;
        let finalPay = Math.round(job.pay * efficiency);

        // Prosperity wage scaling
        try {
            var currentTown = Engine.findTown(player.townId);
            if (currentTown && typeof currentTown.prosperity === 'number') {
                var wageMultiplier = 1 + (currentTown.prosperity - 50) * 0.003;
                finalPay = Math.round(finalPay * wageMultiplier);
            }
        } catch(e) {}

        const workDays = Math.max(1, Math.ceil(ticksRequired / CONFIG.TICKS_PER_DAY));
        player.workDaysCompleted = (player.workDaysCompleted || 0) + workDays;

        // Track job experience for skill learning
        if (job.jobTypeKey) {
            trackJobExperience(job.jobTypeKey, workDays);
        }

        // XP reward
        if (job.xpReward) {
            grantXP(job.xpReward, job.name);
        }

        // Kingdom reputation gain
        if (job.repGain) {
            const town = Engine.findTown(player.townId);
            if (town) {
                var repGainAmount = job.repGain;
                // Town Benefactor: +5% reputation bonus in towns where player owns buildings
                if (hasSkill('town_benefactor')) {
                    var playerOwnsBuilding = (town.buildings || []).some(function(b) { return b.ownerId === 'player'; });
                    if (playerOwnsBuilding) {
                        repGainAmount *= 1.05;
                    }
                }
                player.reputation[town.kingdomId] = Math.min(100,
                    (player.reputation[town.kingdomId] || 50) + repGainAmount
                );
            }
        }

        // Relationship gain with NPC merchant employer
        if (job.npcId) {
            modifyRelationship(job.npcId, 3, 'employer');
        }

        // Advance ticks instantly — the world simulates forward (capped for safety)
        var ticksToAdvance = Math.min(ticksRequired, 60);
        if (typeof Game !== 'undefined' && Game.advanceTicks) {
            Game.advanceTicks(ticksToAdvance);
        }

        // Pay the player immediately after tick advancement
        if (player.conquestServitude && player.conquestServitude.active) {
            const servK = Engine.findKingdom(player.conquestServitude.kingdomId);
            if (servK) servK.gold += finalPay;
            Engine.logEvent(`Work complete: ${job.name} — ${finalPay}g paid to ${servK ? servK.name : 'the kingdom'} (servitude).`);
        } else {
            player.gold += finalPay;
            player.stats.totalGoldEarned += finalPay;
            Engine.logEvent(`Work complete: ${job.name} — earned ${finalPay}g.`);
        }

        // Privateer loot drops
        var lootMsg = '';
        if (job.jobTypeKey === 'privateer' && rng) {
            lootMsg = rollPrivateerLoot(rng);
        }

        // Spy special events
        var spyEventMsg = '';
        if (job.jobTypeKey === 'spy' && rng) {
            spyEventMsg = rollSpyEvent(rng);
        }

        // Entertainment instrument tracking
        var instrumentMsg = '';
        if (job.isEntertainment) {
            var bestInst = getBestInstrumentForTown(player.townId);
            if (bestInst) {
                recordPerformance(bestInst.id, player.townId);
                var newSkill = Math.round(player.instrumentSkill[bestInst.id] || 0);
                instrumentMsg = ' 🎵 ' + bestInst.inst.icon + ' skill: ' + newSkill + '/100';
            }
        }

        // Customs Inspector banned goods discovery
        var customsMsg = '';
        if (job.jobTypeKey === 'customs_inspector' && rng && job.bannedGoods && job.bannedGoods.length > 0) {
            var findChance = 0.07; // 7% base
            if (hasSkill('discrete')) findChance += 0.03;
            if (rng.random() < findChance) {
                var bannedItem = job.bannedGoods[rng.randInt(0, job.bannedGoods.length - 1)];
                var bannedRes = findResource(bannedItem);
                var bannedName = bannedRes ? bannedRes.name : bannedItem;
                // Check if player has room
                var carriedWeight = getCarriedWeight();
                var carryCapacity = getCarryCapacity();
                var itemWeight = bannedRes ? (bannedRes.weight || 1) : 1;
                if (carriedWeight + itemWeight <= carryCapacity) {
                    // Player has room — offer choice
                    player._pendingCustomsFind = { resourceId: bannedItem, name: bannedName, kingdomId: job.kingdomId };
                    customsMsg = ' 🔍 Found contraband: ' + bannedName + '!';
                    if (typeof UI !== 'undefined' && UI.showCustomsChoiceDialog) {
                        setTimeout(function() { UI.showCustomsChoiceDialog(bannedName, bannedItem, job.kingdomId); }, 300);
                    }
                } else {
                    // No room — must turn in
                    player.gold += 10;
                    player.stats.totalGoldEarned += 10;
                    var _cKingdom = Engine.findKingdom(job.kingdomId);
                    player.reputation[job.kingdomId] = Math.min(100, (player.reputation[job.kingdomId] || 50) + 2);
                    Engine.logEvent('🔍 Found contraband ' + bannedName + ' but no room to carry — turned in for 10g bounty.');
                    customsMsg = ' 🔍 Found ' + bannedName + ' — turned in for 10g (no room)';
                }
            }
        }

        // Clear any leftover working state
        player.workingUntilTick = 0;
        player.pendingWorkPay = 0;
        player.pendingWorkName = '';

        var payPerTick = (finalPay / ticksRequired).toFixed(2);
        return { success: true, message: `Completed ${job.name} (${job.hours}hrs, ${ticksRequired} ticks) — earned ${finalPay}g (${payPerTick}g/tick).${lootMsg}${spyEventMsg}${instrumentMsg}${customsMsg}` };
    }

    // ========================================================
    // §12F  STREET TRADING
    // ========================================================
    function getStreetTrades() {
        if (player.traveling) return [];
        const town = Engine.findTown(player.townId);
        if (!town) return [];
        const rng = Engine.getRng();
        if (!rng) return [];

        // Refresh every few days
        const day = Engine.getDay();
        if (!player._streetTradesCache || !player._streetTradesDay || day - player._streetTradesDay >= CONFIG.STREET_TRADE_REFRESH_DAYS) {
            const trades = [];
            const people = Engine.getPeople(town.id);
            if (people && people.length > 0) {
                const candidates = rng.shuffle(people.filter(p => p.alive && p.occupation !== 'soldier' && p.occupation !== 'guard')).slice(0, 5);
                for (const npc of candidates) {
                    // Pick a random good
                    const goodKeys = Object.keys(RESOURCE_TYPES);
                    const goodKey = rng.pick(goodKeys);
                    const res = RESOURCE_TYPES[goodKey];
                    if (!res) continue;
                    const qty = rng.randInt(1, CONFIG.STREET_TRADE_MAX_QTY);
                    const premium = rng.randFloat(CONFIG.STREET_TRADE_PREMIUM_MIN, CONFIG.STREET_TRADE_PREMIUM_MAX);
                    const pricePerUnit = Math.ceil(res.basePrice * premium);
                    trades.push({
                        npcName: npc.firstName + ' ' + npc.lastName,
                        npcId: npc.id,
                        resourceId: res.id,
                        resourceName: res.name,
                        resourceIcon: res.icon,
                        qty: qty,
                        pricePerUnit: pricePerUnit,
                        marketPrice: town.market.prices[res.id] || res.basePrice,
                    });
                }
            }
            player._streetTradesCache = trades;
            player._streetTradesDay = day;
        }
        return player._streetTradesCache || [];
    }

    function getStreetBuyOffers(townId) {
        if (player.traveling) return [];
        var tid = townId || player.townId;
        var town = Engine.findTown(tid);
        if (!town) return [];
        var rng = Engine.getRng();
        if (!rng) return [];

        var day = Engine.getDay();
        if (player._streetBuyCache && player._streetBuyDay && day - player._streetBuyDay < (CONFIG.STREET_TRADE_REFRESH_DAYS || 3)) {
            return player._streetBuyCache || [];
        }

        var offers = [];
        var kingdom = Engine.findKingdom(town.kingdomId);
        var bannedGoods = (kingdom && kingdom.laws && kingdom.laws.bannedGoods) || [];

        // Only generate buy offers for banned goods (otherwise buy from market normally)
        if (bannedGoods.length > 0) {
            var people = Engine.getPeople(town.id);
            var candidates = [];
            if (people && people.length > 0) {
                for (var ci = 0; ci < people.length; ci++) {
                    var cp = people[ci];
                    if (cp && cp.alive && cp.occupation !== 'soldier' && cp.occupation !== 'guard' && cp.occupation !== 'noble') {
                        candidates.push(cp);
                    }
                }
            }
            // Shuffle and pick up to 3 sellers
            var shuffled = [];
            for (var si = candidates.length - 1; si > 0; si--) {
                var j = rng.randInt(0, si);
                var tmp = candidates[si];
                candidates[si] = candidates[j];
                candidates[j] = tmp;
            }
            shuffled = candidates.slice(0, 3);

            for (var oi = 0; oi < shuffled.length; oi++) {
                var npc = shuffled[oi];
                // Pick a random banned good to sell
                var bannedGood = bannedGoods[rng.randInt(0, bannedGoods.length - 1)];
                var res = findResource(bannedGood);
                if (!res) continue;
                var qty = rng.randInt(1, 5);
                var premium = rng.randFloat(2.0, 3.5);
                var pricePerUnit = Math.ceil(res.basePrice * premium);

                // Also always include blasting_powder if banned
                offers.push({
                    npcName: npc.firstName + ' ' + npc.lastName,
                    npcId: npc.id,
                    resourceId: res.id,
                    resourceName: res.name,
                    resourceIcon: res.icon || '\uD83D\uDCE6',
                    qty: qty,
                    pricePerUnit: pricePerUnit,
                    detectionChance: 0.15,
                    isBanned: true,
                });
            }

            // Always include a blasting_powder offer if it's banned
            var bpBanned = bannedGoods.indexOf('blasting_powder') !== -1;
            if (bpBanned && offers.filter(function(o) { return o.resourceId === 'blasting_powder'; }).length === 0 && shuffled.length > 0) {
                var bpNpc = shuffled[0];
                var bpRes = findResource('blasting_powder');
                if (bpRes) {
                    offers.push({
                        npcName: bpNpc.firstName + ' ' + bpNpc.lastName,
                        npcId: bpNpc.id,
                        resourceId: 'blasting_powder',
                        resourceName: bpRes.name,
                        resourceIcon: bpRes.icon || '\uD83D\uDCA5',
                        qty: rng.randInt(1, 3),
                        pricePerUnit: Math.ceil(bpRes.basePrice * rng.randFloat(2.0, 3.5)),
                        detectionChance: 0.15,
                        isBanned: true,
                    });
                }
            }
        }

        player._streetBuyCache = offers;
        player._streetBuyDay = day;
        return offers;
    }

    function executeStreetBuy(buyIndex) {
        var offers = getStreetBuyOffers();
        if (buyIndex < 0 || buyIndex >= offers.length) return { success: false, message: 'Invalid offer.' };

        var offer = offers[buyIndex];
        var totalPrice = offer.pricePerUnit * offer.qty;
        if (player.gold < totalPrice) return { success: false, message: 'Not enough gold. Need ' + totalPrice + 'g.' };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.street_trade || 3);

        var town = Engine.findTown(player.townId);
        var kingdom = town ? Engine.findKingdom(town.kingdomId) : null;
        var rng = Engine.getRng();

        // Detection check
        if (rng && offer.isBanned) {
            var detectionChance = offer.detectionChance || 0.15;
            var rankIdx = player.socialRank ? (player.socialRank[(kingdom || {}).id] || 0) : 0;
            detectionChance -= rankIdx * (CONFIG.SMUGGLING_RANK_REDUCTION || 0.05);
            detectionChance -= Math.min(CONFIG.SMUGGLING_SKILL_MAX_REDUCTION || 0.20, (player.smugglingSkill || 0) * (CONFIG.SMUGGLING_SKILL_REDUCTION || 0.01));
            if (hasSkill('master_smuggler')) detectionChance -= 0.20;
            else if (hasSkill('discrete')) detectionChance -= 0.10;
            detectionChance = Math.max(0.03, detectionChance);

            if (rng.chance(detectionChance)) {
                var fineAmount = Math.floor(totalPrice * (CONFIG.SMUGGLING_FINE_MULTIPLIER || 2));
                var actualFine = Math.min(fineAmount, player.gold);
                player.gold -= actualFine;
                if (kingdom) {
                    player.reputation[kingdom.id] = Math.max(0, (player.reputation[kingdom.id] || 50) - (CONFIG.SMUGGLING_REP_PENALTY || 15));
                }
                offers.splice(buyIndex, 1);
                Engine.logEvent(player.fullName + ' was caught buying banned ' + offer.resourceName + ' on the street! Fined ' + actualFine + 'g.');
                return { success: false, message: 'Caught buying banned goods! Fined ' + actualFine + 'g. Goods confiscated.', caught: true };
            }
        }

        // Successful purchase
        player.gold -= totalPrice;
        player.stats.totalGoldSpent += totalPrice;
        player.inventory[offer.resourceId] = (player.inventory[offer.resourceId] || 0) + offer.qty;

        // Improve smuggling skill
        player.smugglingSkill = Math.min(20, (player.smugglingSkill || 0) + 1);

        offers.splice(buyIndex, 1);
        return { success: true, message: 'Bought ' + offer.qty + ' ' + offer.resourceName + ' for ' + totalPrice + 'g from the black market.' };
    }

    function executeStreetTrade(tradeIndex) {
        const trades = getStreetTrades();
        if (tradeIndex < 0 || tradeIndex >= trades.length) return { success: false, message: 'Invalid trade.' };

        const trade = trades[tradeIndex];
        const held = player.inventory[trade.resourceId] || 0;
        if (held < trade.qty) return { success: false, message: `Not enough ${trade.resourceName}. Need ${trade.qty}, have ${held}.` };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.street_trade || 3);

        const town = Engine.findTown(player.townId);
        const kingdom = town ? Engine.findKingdom(town.kingdomId) : null;

        // Banned goods check — street trades are harder to police (lower detection than market)
        if (kingdom && kingdom.laws && kingdom.laws.bannedGoods && kingdom.laws.bannedGoods.includes(trade.resourceId)) {
            const rng = Engine.getRng();
            if (rng) {
                let detectionChance = (CONFIG.SMUGGLING_BASE_DETECTION || 0.30) * 0.7; // 70% of market detection rate
                const rankIdx = player.socialRank[kingdom.id] || 0;
                detectionChance -= rankIdx * (CONFIG.SMUGGLING_RANK_REDUCTION || 0.05);
                detectionChance -= Math.min(CONFIG.SMUGGLING_SKILL_MAX_REDUCTION || 0.20, (player.smugglingSkill || 0) * (CONFIG.SMUGGLING_SKILL_REDUCTION || 0.01));
                if (hasSkill('master_smuggler')) detectionChance -= 0.20;
                else if (hasSkill('discrete')) detectionChance -= 0.10;
                detectionChance = Math.max(0.05, detectionChance);

                if (rng.chance(detectionChance)) {
                    const fineAmount = Math.floor(trade.pricePerUnit * trade.qty * (CONFIG.SMUGGLING_FINE_MULTIPLIER || 2));
                    const actualFine = Math.min(fineAmount, player.gold);
                    player.gold -= actualFine;
                    player.inventory[trade.resourceId] -= trade.qty;
                    player.reputation[kingdom.id] = Math.max(0, (player.reputation[kingdom.id] || 50) - (CONFIG.SMUGGLING_REP_PENALTY || 15));
                    trades.splice(tradeIndex, 1);
                    Engine.logEvent(`${player.fullName} was caught selling banned ${trade.resourceName} on the street! Fined ${actualFine}g.`);
                    return { success: false, message: `Caught selling banned goods on the street! Fined ${actualFine}g.`, caught: true };
                }
            }
        }

        // Apply at least base tax rate to street trades
        const taxRate = (kingdom && kingdom.taxRate) || CONFIG.TAX_RATE_DEFAULT || 0.10;
        const taxAmount = Math.floor(trade.pricePerUnit * trade.qty * taxRate);
        const totalRevenue = trade.pricePerUnit * trade.qty - taxAmount;

        player.gold += totalRevenue;
        player.stats.totalGoldEarned += totalRevenue;
        player.inventory[trade.resourceId] -= trade.qty;
        player.stats.tradesCompleted++;
        grantXP(XP_REWARDS.SELL_TRADE, 'street_trade');

        // Build relationship with NPC
        if (trade.npcId) {
            const rel = player.relationships[trade.npcId] || { level: 0 };
            rel.level = Math.min(100, (rel.level || 0) + 3);
            player.relationships[trade.npcId] = rel;
        }

        // Remove trade from cache
        trades.splice(tradeIndex, 1);

        // Track tax revenue for kingdom from street trades
        if (kingdom && taxAmount > 0) {
            kingdom.taxRevenue = (kingdom.taxRevenue || 0) + taxAmount;
            kingdom.gold = (kingdom.gold || 0) + taxAmount;
        }

        Engine.logEvent(`${player.fullName} sold ${trade.qty} ${trade.resourceName} to ${trade.npcName} for ${totalRevenue}g (${taxAmount}g tax).`);
        return { success: true, message: `Sold ${trade.qty} ${trade.resourceName} to ${trade.npcName} for ${totalRevenue}g (${taxAmount}g tax).` };
    }

    // ========================================================
    // §12F2  FORAGING SYSTEM
    // ========================================================

    function forage() {
        if (player.traveling) return { success: false, message: 'Cannot forage while traveling.' };
        if (player.workingUntilTick) return { success: false, message: 'Already working.' };

        const town = Engine.findTown(player.townId);
        if (!town) return { success: false, message: 'Town not found.' };

        const terrainData = Engine.getTerrainGrid();
        if (!terrainData) return { success: false, message: 'Terrain not available.' };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.forage || 30);

        const { grid, cols, rows } = terrainData;
        const cx = Math.floor(town.x / CONFIG.TILE_SIZE);
        const cy = Math.floor(town.y / CONFIG.TILE_SIZE);
        const radius = 10;

        let terrainCounts = { grass: 0, forest: 0, mountain: 0, hills: 0, water: 0, sand: 0 };
        for (let dy = -radius; dy <= radius; dy++) {
            for (let dx = -radius; dx <= radius; dx++) {
                const tx = cx + dx, ty = cy + dy;
                if (tx < 0 || ty < 0 || tx >= cols || ty >= rows) continue;
                const t = grid[ty * cols + tx];
                if (t === TERRAIN.WATER.id) terrainCounts.water++;
                else if (t === TERRAIN.FOREST.id) terrainCounts.forest++;
                else if (t === TERRAIN.MOUNTAIN.id) terrainCounts.mountain++;
                else if (t === TERRAIN.HILLS.id) terrainCounts.hills++;
                else if (t === TERRAIN.SAND.id) terrainCounts.sand++;
                else terrainCounts.grass++;
            }
        }

        const found = [];
        const roll = Math.random.bind(Math);

        // Forest: herbs, timber, berries
        if (terrainCounts.forest > 20) {
            if (roll() < 0.4) { var qty = Math.ceil(roll() * 2); if (hasSkill('herbalist')) qty *= 2; player.inventory.herbs = (player.inventory.herbs || 0) + qty; found.push(`${qty} herbs`); }
            if (roll() < 0.3) { const qty = Math.ceil(roll() * 2); player.inventory.timber = (player.inventory.timber || 0) + qty; found.push(`${qty} timber`); }
            if (roll() < 0.3) { var hungerRestore = 15; if (hasSkill('wilderness_survival')) hungerRestore = 23; player.hunger = Math.min(100, (player.hunger || 0) + hungerRestore); found.push('wild berries (restored hunger)'); }
        }

        // Mountain: iron ore, gold (rare), stone
        if (terrainCounts.mountain > 10) {
            if (roll() < 0.25) { const qty = Math.ceil(roll() * 2); player.inventory.iron_ore = (player.inventory.iron_ore || 0) + qty; found.push(`${qty} iron ore`); }
            if (roll() < 0.05) { player.inventory.gold_ingot = (player.inventory.gold_ingot || 0) + 1; found.push('1 gold nugget!'); }
            if (roll() < 0.3) { const qty = Math.ceil(roll() * 3); player.inventory.stone = (player.inventory.stone || 0) + qty; found.push(`${qty} stone`); }
        }

        // Water: fish
        if (terrainCounts.water > 15) {
            if (roll() < 0.5) { const qty = Math.ceil(roll() * 3); player.inventory.fish = (player.inventory.fish || 0) + qty; found.push(`${qty} fish`); }
        }

        // Hills: herbs, small game
        if (terrainCounts.hills > 15) {
            if (roll() < 0.35) { var hqty = Math.ceil(roll() * 2); if (hasSkill('herbalist')) hqty *= 2; player.inventory.herbs = (player.inventory.herbs || 0) + hqty; found.push(`${hqty} herbs`); }
            if (roll() < 0.2) { player.inventory.meat = (player.inventory.meat || 0) + 1; found.push('1 wild game meat'); }
        }

        // Desert/Sand: rare finds
        if (terrainCounts.sand > 20) {
            if (roll() < 0.1) { player.gold += 50; found.push('buried treasure (50g)'); }
            if (roll() < 0.2) { player.hunger = Math.min(100, (player.hunger || 0) + 10); found.push('desert oasis (restored some hunger)'); }
        }

        // Injury risk from foraging
        if (roll() < 0.05) {
            found.push('\u26A0\uFE0F Minor injury while foraging');
            if (typeof inflictRandomInjury === 'function') inflictRandomInjury('foraging accident');
        }

        grantXP(3, 'foraging');

        // Takes half a day
        player.workingUntilTick = Engine.getDay() + 0.5;

        if (found.length === 0) {
            Engine.logEvent('You spent time foraging but found nothing useful.');
            return { success: true, message: 'Found nothing useful.', found: [] };
        }

        Engine.logEvent(`\uD83C\uDF3F Foraging: Found ${found.join(', ')}.`);
        return { success: true, message: `Found: ${found.join(', ')}`, found };
    }

    // ========================================================
    // §12F3  BRIDGE & ROAD CONSTRUCTION (PLAYER)
    // ========================================================

    function playerDestroyBridge(roadIndex, method) {
        if (player.traveling) return { success: false, message: 'Cannot do this while traveling.' };
        if (player.bridgeDestruction) return { success: false, message: 'Already destroying a bridge. Cancel or wait for it to finish.' };
        var roads = Engine.getRoads();
        var road = roads[roadIndex];
        if (!road || !(road.hasBridge || false)) return { success: false, message: 'No bridge on this road.' };
        if (road.bridgeDestroyed) return { success: false, message: 'Bridge already destroyed.' };
        if (player.townId !== road.fromTownId && player.townId !== road.toTownId) {
            return { success: false, message: 'You must be in a town connected to this bridge.' };
        }

        // Validate method
        var methods = CONFIG.BRIDGE_DESTROY_METHODS;
        if (!methods || !methods[method]) return { success: false, message: 'Invalid destruction method.' };
        var m = methods[method];

        // Check materials
        var reqs = m.requires || {};
        for (var resId in reqs) {
            if ((player.inventory[resId] || 0) < reqs[resId]) {
                var res = CONFIG.RESOURCE_TYPES ? Object.values(CONFIG.RESOURCE_TYPES).find(function(r) { return r.id === resId; }) : null;
                var rname = res ? res.name : resId;
                return { success: false, message: 'Need ' + reqs[resId] + ' ' + rname + ' (have ' + (player.inventory[resId] || 0) + ').' };
            }
        }

        // Check gold cost
        var cost = CONFIG.BRIDGE_DESTROY_COST || 500;
        if (player.gold < cost) return { success: false, message: 'Need ' + cost + 'g to begin sabotage.' };

        // Deduct materials and gold
        for (var resId2 in reqs) {
            player.inventory[resId2] = (player.inventory[resId2] || 0) - reqs[resId2];
        }
        player.gold -= cost;
        player.stats.totalGoldSpent += cost;

        // Determine duration based on skills
        var hasSkill = _hasBridgeDestructionSkill();
        var totalDays = hasSkill ? m.skilledDays : m.baseDays;
        var detectionRate = hasSkill ? m.skilledDetectionPerDay : m.detectionPerDay;

        // Further skill modifiers
        if (hasSkill && _hasSkill('arsonist_skill')) {
            detectionRate *= 0.5;
        }
        if (_hasSkill('shadow_dealings')) {
            detectionRate *= 0.7;
        }
        if (_hasSkill('discrete')) {
            detectionRate *= 0.8;
        }

        // Start the task
        player.bridgeDestruction = {
            roadIndex: roadIndex,
            method: method,
            startDay: Engine.getDay(),
            totalDays: totalDays,
            daysElapsed: 0,
            detectionRate: detectionRate,
            methodName: m.name,
            caught: false,
        };

        var fromTown = Engine.findTown(road.fromTownId);
        var toTown = Engine.findTown(road.toTownId);
        var bridgeName = (fromTown ? fromTown.name : '?') + ' – ' + (toTown ? toTown.name : '?');
        return { success: true, message: '💣 Bridge sabotage begun on ' + bridgeName + '! Estimated ' + totalDays + ' days. Stay near the bridge and avoid detection.' };
    }

    function _hasBridgeDestructionSkill() {
        var skills = CONFIG.BRIDGE_DESTROY_SKILLS || ['arsonist_skill', 'shadow_dealings', 'discrete'];
        for (var i = 0; i < skills.length; i++) {
            if (_hasSkill(skills[i])) return true;
        }
        return false;
    }

    function _hasSkill(skillId) {
        if (typeof Player !== 'undefined' && Player.hasSkill) return Player.hasSkill(skillId);
        if (player.skills) {
            for (var i = 0; i < player.skills.length; i++) {
                if (player.skills[i] === skillId || (player.skills[i] && player.skills[i].id === skillId)) return true;
            }
        }
        return false;
    }

    function tickBridgeDestruction() {
        if (!player.bridgeDestruction) return;
        var bd = player.bridgeDestruction;
        bd.daysElapsed++;

        // Check if player left the area (must stay in connected town)
        var roads = Engine.getRoads();
        var road = roads[bd.roadIndex];
        if (!road) { player.bridgeDestruction = null; return; }
        if (player.traveling || (player.townId !== road.fromTownId && player.townId !== road.toTownId)) {
            player.bridgeDestruction = null;
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('💣 Bridge sabotage cancelled — you left the area.', 'warning');
            return;
        }

        // Detection roll
        var detectionChance = bd.detectionRate;
        // Increase detection if kingdom has many guards
        var kingdom = null;
        try {
            var town = Engine.findTown(player.townId);
            if (town) kingdom = Engine.findKingdom(town.kingdomId);
        } catch (e) { /* no-op */ }
        if (kingdom) {
            var guardBonus = ((kingdom.guards || 0) + (kingdom.soldiers || 0)) * 0.001;
            detectionChance += Math.min(0.05, guardBonus);
        }

        var rng = Engine.getWorld ? (Engine.getWorld().rng || Math) : Math;
        var roll = typeof rng.random === 'function' ? rng.random() : Math.random();

        if (roll < detectionChance) {
            // CAUGHT!
            bd.caught = true;
            player.bridgeDestruction = null;

            var fine = CONFIG.BRIDGE_DESTROY_CAUGHT_FINE || 2000;
            var jailDays = CONFIG.BRIDGE_DESTROY_CAUGHT_JAIL_DAYS || 30;
            var repPenalty = CONFIG.BRIDGE_DESTROY_CAUGHT_REP_PENALTY || -30;

            // Deduct fine (goes to kingdom coffers)
            var actualFine = Math.min(player.gold, fine);
            player.gold -= actualFine;
            if (kingdom) kingdom.gold = (kingdom.gold || 0) + actualFine;

            // Jail time
            player.jailed = true;
            player.jailDays = jailDays;
            player.jailedDay = Engine.getDay();
            player.jailKingdomId = kingdom ? kingdom.id : null;

            // Reputation penalty in ALL kingdoms
            var allKingdoms = Engine.getKingdoms ? Engine.getKingdoms() : [];
            for (var ki = 0; ki < allKingdoms.length; ki++) {
                modifyKingdomReputation(allKingdoms[ki].id, repPenalty);
            }

            // Criminal record
            if (!player.criminalRecord) player.criminalRecord = {};
            if (!player.criminalRecord.sabotage) player.criminalRecord.sabotage = 0;
            player.criminalRecord.sabotage++;

            if (typeof Engine !== 'undefined' && Engine.logEvent) {
                Engine.logEvent('🚨 ' + (player.firstName || 'Player') + ' was caught destroying a bridge! Fined ' + actualFine + 'g and sentenced to ' + jailDays + ' days in jail.');
            }
            if (typeof UI !== 'undefined' && UI.toast) {
                UI.toast('🚨 CAUGHT! You were caught destroying the bridge! Fined ' + actualFine + 'g, jailed for ' + jailDays + ' days, reputation damaged in all kingdoms.', 'danger');
            }
            return;
        }

        // Progress check — did we finish?
        if (bd.daysElapsed >= bd.totalDays) {
            // Bridge destroyed!
            var result = Engine.destroyBridge(bd.roadIndex);
            player.bridgeDestruction = null;

            if (result && result.success) {
                grantXP(15, 'sabotage');
                var town2 = Engine.findTown(player.townId);
                if (town2) modifyTownReputation(town2.id, -10);
                player.bridgesDestroyed = (player.bridgesDestroyed || 0) + 1;

                if (typeof UI !== 'undefined' && UI.toast) {
                    UI.toast('💣 Bridge successfully destroyed! The road is now impassable.', 'success');
                }
            }
        }
    }

    function cancelBridgeDestruction() {
        if (!player.bridgeDestruction) return { success: false, message: 'No active bridge destruction.' };
        player.bridgeDestruction = null;
        return { success: true, message: 'Bridge sabotage cancelled. Materials already consumed.' };
    }

    function getBridgeDestructionStatus() {
        if (!player.bridgeDestruction) return null;
        var bd = player.bridgeDestruction;
        var roads = Engine.getRoads();
        var road = roads[bd.roadIndex];
        var fromTown = road ? Engine.findTown(road.fromTownId) : null;
        var toTown = road ? Engine.findTown(road.toTownId) : null;
        return {
            roadIndex: bd.roadIndex,
            method: bd.method,
            methodName: bd.methodName,
            daysElapsed: bd.daysElapsed,
            totalDays: bd.totalDays,
            daysRemaining: bd.totalDays - bd.daysElapsed,
            detectionRate: bd.detectionRate,
            fromTown: fromTown ? fromTown.name : '?',
            toTown: toTown ? toTown.name : '?',
        };
    }

    function playerRebuildBridge(roadIndex) {
        if (player.traveling) return { success: false, message: 'Cannot do this while traveling.' };
        const roads = Engine.getRoads();
        const road = roads[roadIndex];
        if (!road || !(road.hasBridge || false)) return { success: false, message: 'No bridge on this road.' };
        if (!road.bridgeDestroyed) return { success: false, message: 'Bridge is not destroyed.' };
        const cost = CONFIG.BRIDGE_REBUILD_COST || 1000;
        if (player.gold < cost) return { success: false, message: `Need ${cost}g to rebuild.` };
        if (player.townId !== road.fromTownId && player.townId !== road.toTownId) {
            return { success: false, message: 'You must be in a town connected to this bridge.' };
        }
        const timberNeeded = 5;
        if ((player.inventory.timber || 0) < timberNeeded) return { success: false, message: `Need ${timberNeeded} timber to rebuild.` };
        player.gold -= cost;
        player.inventory.timber -= timberNeeded;
        player.stats.totalGoldSpent += cost;
        const result = Engine.rebuildBridge(roadIndex);
        if (result.success) {
            grantXP(15, 'construction');
            const town = Engine.findTown(player.townId);
            if (town) modifyTownReputation(town.id, 15);
            player.bridgesBuilt = (player.bridgesBuilt || 0) + 1;
        }
        return result;
    }

    function playerBuildRoad(targetTownId) {
        if (player.traveling) return { success: false, message: 'Cannot build while traveling.' };
        const currentTown = Engine.findTown(player.townId);
        const targetTown = Engine.findTown(targetTownId);
        if (!currentTown || !targetTown) return { success: false, message: 'Town not found.' };
        if (player.townId === targetTownId) return { success: false, message: 'Already in this town.' };

        // Check if road already exists
        const roads = Engine.getRoads();
        const exists = roads.some(r =>
            (r.fromTownId === player.townId && r.toTownId === targetTownId) ||
            (r.fromTownId === targetTownId && r.toTownId === player.townId)
        );
        if (exists) return { success: false, message: 'A road already exists between these towns.' };

        // Check distance
        const d = Math.hypot(currentTown.x - targetTown.x, currentTown.y - targetTown.y);
        if (d > 3000) return { success: false, message: 'Too far! Maximum road building distance is 3000 units.' };

        // Check water
        const waterFrac = Engine.checkWaterFraction(currentTown.x, currentTown.y, targetTown.x, targetTown.y);
        if (waterFrac > 0.15) return { success: false, message: 'Too much water in the way. Cannot build a road here.' };

        // Cost calculation
        const baseCost = 1000;
        const distCost = Math.floor(d * 2);
        let bridgeCost = 0;
        if (waterFrac > 0) bridgeCost = 500;
        var totalCost = baseCost + distCost + bridgeCost;
        if (hasSkill('cartographer')) totalCost = Math.floor(totalCost * 0.75); // 25% discount

        // Material requirements
        const timberNeeded = 10 + Math.floor(d / 200);
        const stoneNeeded = 5 + Math.floor(d / 300);

        if (player.gold < totalCost) return { success: false, message: `Need ${totalCost}g (base ${baseCost} + distance ${distCost} + bridges ${bridgeCost}).` };
        if ((player.inventory.timber || 0) < timberNeeded) return { success: false, message: `Need ${timberNeeded} timber.` };
        if ((player.inventory.stone || 0) < stoneNeeded) return { success: false, message: `Need ${stoneNeeded} stone.` };

        // Require at least Merchant rank (index 3)
        if (getPlayerRankIndex() < 3) return { success: false, message: 'Must be at least Merchant rank to build roads.' };

        player.gold -= totalCost;
        player.inventory.timber -= timberNeeded;
        player.inventory.stone -= stoneNeeded;
        player.stats.totalGoldSpent += totalCost;

        const result = Engine.buildNewRoad(player.townId, targetTownId, 'player');
        if (result.success) {
            grantXP(50, 'road construction');
            modifyTownReputation(player.townId, 20);
            modifyTownReputation(targetTownId, 20);
            player.roadsBuilt = (player.roadsBuilt || 0) + 1;
        }
        return result;
    }

    // ── Toll Road & Sea Route Functions ──

    function playerBuildTollRoad(targetTownId) {
        if (player.traveling) return { success: false, message: 'Cannot build while traveling.' };
        const currentTown = Engine.findTown(player.townId);
        const targetTown = Engine.findTown(targetTownId);
        if (!currentTown || !targetTown) return { success: false, message: 'Town not found.' };
        if (player.townId === targetTownId) return { success: false, message: 'Already in this town.' };

        const roads = Engine.getRoads();
        const exists = roads.some(r =>
            (r.fromTownId === player.townId && r.toTownId === targetTownId) ||
            (r.fromTownId === targetTownId && r.toTownId === player.townId)
        );
        if (exists) return { success: false, message: 'A road already exists between these towns.' };

        const d = Math.hypot(currentTown.x - targetTown.x, currentTown.y - targetTown.y);
        if (d > 3000) return { success: false, message: 'Too far! Maximum road building distance is 3000 units.' };

        const waterFrac = Engine.checkWaterFraction(currentTown.x, currentTown.y, targetTown.x, targetTown.y);
        if (waterFrac > CONFIG.TOLL_ROAD_MAX_WATER_FRACTION) return { success: false, message: 'Too much water in the way. Cannot build a road here.' };

        const baseCost = CONFIG.TOLL_ROAD_BASE_COST;
        const distCost = Math.floor(d * CONFIG.TOLL_ROAD_DIST_COST);
        const waterCost = waterFrac > 0 ? Math.floor(baseCost * waterFrac * CONFIG.TOLL_ROAD_WATER_MULTIPLIER) : 0;
        var totalCost = baseCost + distCost + waterCost;
        if (hasSkill('cartographer')) totalCost = Math.floor(totalCost * 0.75); // 25% discount

        const timberNeeded = Math.ceil(d / 100) * CONFIG.TOLL_ROAD_TIMBER_PER_100;
        const stoneNeeded = Math.ceil(d / 100) * CONFIG.TOLL_ROAD_STONE_PER_100;
        const ironNeeded = Math.ceil(d / 100) * CONFIG.TOLL_ROAD_IRON_PER_100;

        if (getPlayerRankIndex() < 3) return { success: false, message: 'Must be at least Guildmaster rank to build toll roads.' };

        if (player.gold < totalCost) return { success: false, message: `Need ${totalCost.toLocaleString()}g (Base: ${baseCost}, Distance: ${distCost}, Water: ${waterCost}).` };
        if ((player.inventory.timber || 0) < timberNeeded) return { success: false, message: `Need ${timberNeeded} timber (have ${player.inventory.timber || 0}).` };
        if ((player.inventory.stone || 0) < stoneNeeded) return { success: false, message: `Need ${stoneNeeded} stone (have ${player.inventory.stone || 0}).` };
        if ((player.inventory.iron_ore || 0) < ironNeeded) return { success: false, message: `Need ${ironNeeded} iron ore (have ${player.inventory.iron_ore || 0}).` };

        player.gold -= totalCost;
        player.inventory.timber = (player.inventory.timber || 0) - timberNeeded;
        player.inventory.stone = (player.inventory.stone || 0) - stoneNeeded;
        player.inventory.iron_ore = (player.inventory.iron_ore || 0) - ironNeeded;
        player.stats.totalGoldSpent = (player.stats.totalGoldSpent || 0) + totalCost;

        const result = Engine.buildNewRoad(player.townId, targetTownId, 'player', {
            ownerId: 'player',
            tollRate: CONFIG.TOLL_DEFAULT_RATE,
            isTollRoad: true,
            quality: 2,
        });

        if (result.success) {
            grantXP(100, 'toll road construction');
            modifyTownReputation(player.townId, 25);
            modifyTownReputation(targetTownId, 25);
            if (!player.ownedRoutes) player.ownedRoutes = [];
            player.ownedRoutes.push({ type: 'road', fromTownId: player.townId, toTownId: targetTownId, builtDay: Engine.getDay() });
            player.roadsBuilt = (player.roadsBuilt || 0) + 1;
        }
        return result;
    }

    function playerBuildSeaRoute(targetTownId) {
        if (player.traveling) return { success: false, message: 'Cannot build while traveling.' };
        const currentTown = Engine.findTown(player.townId);
        const targetTown = Engine.findTown(targetTownId);
        if (!currentTown || !targetTown) return { success: false, message: 'Town not found.' };
        if (!currentTown.isPort) return { success: false, message: `${currentTown.name} is not a port town!` };
        if (!targetTown.isPort) return { success: false, message: `${targetTown.name} is not a port town!` };

        const seaRoutes = Engine.getSeaRoutes ? Engine.getSeaRoutes() : [];
        const exists = seaRoutes.some(r =>
            (r.fromTownId === player.townId && r.toTownId === targetTownId) ||
            (r.fromTownId === targetTownId && r.toTownId === player.townId)
        );
        if (exists) return { success: false, message: 'A sea route already exists between these ports.' };

        if (!player.ships || player.ships.length === 0) return { success: false, message: 'You must own at least one ship to establish a sea route.' };
        if (getPlayerRankIndex() < 3) return { success: false, message: 'Must be at least Guildmaster rank to build sea routes.' };

        const d = Math.hypot(currentTown.x - targetTown.x, currentTown.y - targetTown.y);

        const baseCost = CONFIG.TOLL_SEA_BASE_COST;
        const dockCost = CONFIG.TOLL_SEA_DOCK_COST * 2;
        const distCost = Math.floor(d * 5);
        const totalCost = baseCost + dockCost + distCost;

        const timberNeeded = CONFIG.TOLL_SEA_TIMBER_NEEDED;
        const stoneNeeded = CONFIG.TOLL_SEA_STONE_NEEDED;
        const ironNeeded = CONFIG.TOLL_SEA_IRON_NEEDED;

        if (player.gold < totalCost) return { success: false, message: `Need ${totalCost.toLocaleString()}g (Base: ${baseCost}, Docks: ${dockCost}, Distance: ${distCost}).` };
        if ((player.inventory.timber || 0) < timberNeeded) return { success: false, message: `Need ${timberNeeded} timber (have ${player.inventory.timber || 0}).` };
        if ((player.inventory.stone || 0) < stoneNeeded) return { success: false, message: `Need ${stoneNeeded} stone (have ${player.inventory.stone || 0}).` };
        if ((player.inventory.iron_ore || 0) < ironNeeded) return { success: false, message: `Need ${ironNeeded} iron ore (have ${player.inventory.iron_ore || 0}).` };

        player.gold -= totalCost;
        player.inventory.timber = (player.inventory.timber || 0) - timberNeeded;
        player.inventory.stone = (player.inventory.stone || 0) - stoneNeeded;
        player.inventory.iron_ore = (player.inventory.iron_ore || 0) - ironNeeded;
        player.stats.totalGoldSpent = (player.stats.totalGoldSpent || 0) + totalCost;

        const result = Engine.buildNewSeaRoute(player.townId, targetTownId, 'player', {
            ownerId: 'player',
            tollRate: CONFIG.TOLL_DEFAULT_RATE,
            isTollRoute: true,
        });

        if (result.success) {
            grantXP(200, 'sea route establishment');
            modifyTownReputation(player.townId, 30);
            modifyTownReputation(targetTownId, 30);
            if (!player.ownedRoutes) player.ownedRoutes = [];
            player.ownedRoutes.push({ type: 'sea', fromTownId: player.townId, toTownId: targetTownId, builtDay: Engine.getDay() });
            player.seaRoutesBuilt = (player.seaRoutesBuilt || 0) + 1;
        }
        return result;
    }

    function collectTollRevenue() {
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.collect_tolls || 2);
        let totalCollected = 0;
        const roads = Engine.getRoads();
        const seaRoutes = Engine.getSeaRoutes ? Engine.getSeaRoutes() : [];

        for (const road of roads) {
            if (road.ownerId === 'player' && road.tollRevenue > 0) {
                totalCollected += road.tollRevenue;
                road.tollRevenue = 0;
            }
        }
        for (const route of seaRoutes) {
            if (route.ownerId === 'player' && route.tollRevenue > 0) {
                totalCollected += route.tollRevenue;
                route.tollRevenue = 0;
            }
        }

        if (totalCollected > 0) {
            player.gold += totalCollected;
            player.stats.totalGoldEarned = (player.stats.totalGoldEarned || 0) + totalCollected;
            logEvent(`\uD83D\uDCB0 Collected ${Math.floor(totalCollected)}g in toll revenue.`);
        }
        return totalCollected;
    }

    function setTollRate(routeType, fromTownId, toTownId, newRate) {
        newRate = Math.max(CONFIG.TOLL_MIN_RATE, Math.min(CONFIG.TOLL_MAX_RATE, newRate));
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.set_toll || 1);
        const routes = routeType === 'sea' ? (Engine.getSeaRoutes ? Engine.getSeaRoutes() : []) : Engine.getRoads();
        for (const r of routes) {
            if (r.ownerId === 'player' &&
                ((r.fromTownId === fromTownId && r.toTownId === toTownId) ||
                 (r.fromTownId === toTownId && r.toTownId === fromTownId))) {
                r.tollRate = newRate;
                return { success: true, message: `Toll rate set to ${newRate}g.` };
            }
        }
        return { success: false, message: 'Route not found or not owned by you.' };
    }

    function getPlayerOwnedRoutes() {
        const owned = [];
        const roads = Engine.getRoads();
        const seaRoutes = Engine.getSeaRoutes ? Engine.getSeaRoutes() : [];

        for (const r of roads) {
            if (r.ownerId === 'player') {
                const fromT = Engine.findTown(r.fromTownId);
                const toT = Engine.findTown(r.toTownId);
                owned.push({
                    type: 'road',
                    fromTownId: r.fromTownId,
                    toTownId: r.toTownId,
                    fromName: fromT ? fromT.name : '?',
                    toName: toT ? toT.name : '?',
                    tollRate: r.tollRate,
                    tollRevenue: r.tollRevenue,
                    condition: r.condition,
                    builtDay: r.builtDay,
                });
            }
        }
        for (const r of seaRoutes) {
            if (r.ownerId === 'player') {
                const fromT = Engine.findTown(r.fromTownId);
                const toT = Engine.findTown(r.toTownId);
                owned.push({
                    type: 'sea',
                    fromTownId: r.fromTownId,
                    toTownId: r.toTownId,
                    fromName: fromT ? fromT.name : '?',
                    toName: toT ? toT.name : '?',
                    tollRate: r.tollRate,
                    tollRevenue: r.tollRevenue,
                    builtDay: r.builtDay,
                });
            }
        }
        return owned;
    }

    function influenceKingToBuildRoad(targetTownId) {
        if (player.traveling) return { success: false, message: 'Cannot do this while traveling.' };
        const currentTown = Engine.findTown(player.townId);
        const targetTown = Engine.findTown(targetTownId);
        if (!currentTown || !targetTown) return { success: false, message: 'Town not found.' };

        if (currentTown.kingdomId !== targetTown.kingdomId) return { success: false, message: 'Both towns must be in the same kingdom.' };

        const kingdom = Engine.findKingdom(currentTown.kingdomId);
        if (!kingdom) return { success: false, message: 'Kingdom not found.' };

        if (getPlayerRankIndex(kingdom.id) < CONFIG.KING_INFLUENCE_MIN_RANK) {
            return { success: false, message: `Must be at least Minor Noble rank to influence the king. (Current: ${CONFIG.SOCIAL_RANKS[getPlayerRankIndex(kingdom.id)]?.name || 'Unknown'})` };
        }

        const rep = player.reputation ? (player.reputation[kingdom.id] || 0) : 0;
        if (rep < CONFIG.KING_INFLUENCE_MIN_REP) {
            return { success: false, message: `Need at least ${CONFIG.KING_INFLUENCE_MIN_REP} reputation with ${kingdom.name}. (Current: ${Math.floor(rep)})` };
        }

        const roads = Engine.getRoads();
        const exists = roads.some(r =>
            (r.fromTownId === player.townId && r.toTownId === targetTownId) ||
            (r.fromTownId === targetTownId && r.toTownId === player.townId)
        );
        if (exists) return { success: false, message: 'A road already exists between these towns.' };

        const d = Math.hypot(currentTown.x - targetTown.x, currentTown.y - targetTown.y);
        const waterFrac = Engine.checkWaterFraction(currentTown.x, currentTown.y, targetTown.x, targetTown.y);
        if (waterFrac > CONFIG.TOLL_ROAD_MAX_WATER_FRACTION) return { success: false, message: 'Too much water in the way for a road.' };

        const fullCost = CONFIG.TOLL_ROAD_BASE_COST + Math.floor(d * CONFIG.TOLL_ROAD_DIST_COST) + (waterFrac > 0 ? Math.floor(CONFIG.TOLL_ROAD_BASE_COST * waterFrac * CONFIG.TOLL_ROAD_WATER_MULTIPLIER) : 0);
        const playerCost = Math.floor(fullCost * CONFIG.KING_INFLUENCE_COST_FRACTION);
        const kingdomCost = fullCost - playerCost;

        if (player.gold < playerCost) return { success: false, message: `You need ${playerCost.toLocaleString()}g as your contribution (10% of ${fullCost.toLocaleString()}g total cost).` };
        if (kingdom.gold < kingdomCost) return { success: false, message: `${kingdom.name} cannot afford their share (${kingdomCost.toLocaleString()}g). Kingdom treasury: ${Math.floor(kingdom.gold).toLocaleString()}g.` };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.influence_king || 10);

        let chance = CONFIG.KING_INFLUENCE_BASE_CHANCE;

        const kp = kingdom.kingPersonality;
        if (kp) {
            if (kp.intelligence === 'brilliant') chance += 0.15;
            else if (kp.intelligence === 'dim') chance -= 0.10;
            if (kp.ambition === 'ambitious') chance += 0.10;
            else if (kp.ambition === 'content') chance -= 0.05;
            if (kp.greed === 'generous') chance += 0.10;
            else if (kp.greed === 'greedy') chance -= 0.15;
            if (kp.temperament === 'kind') chance += 0.05;
            else if (kp.temperament === 'cruel') chance -= 0.10;
        }

        chance += Math.max(0, (rep - CONFIG.KING_INFLUENCE_MIN_REP) / 200);
        const rankBonus = (getPlayerRankIndex(kingdom.id) - CONFIG.KING_INFLUENCE_MIN_RANK) * 0.05;
        chance += rankBonus;

        const worldData = Engine.getWorld ? Engine.getWorld() : {};
        const atWar = worldData.activeWars && Object.values(worldData.activeWars).some(w =>
            w.active && (w.attackerId === kingdom.id || w.defenderId === kingdom.id)
        );
        if (atWar) chance -= 0.20;

        if (kingdom.gold < kingdomCost * 2) chance -= 0.15;
        if (kingdom.gold > kingdomCost * 5) chance += 0.10;

        const popFactor = ((currentTown.population || 0) + (targetTown.population || 0)) / 500;
        chance += Math.min(0.10, popFactor * 0.05);

        if (d > 2000) chance -= 0.10;
        if (d < 500) chance += 0.05;

        chance = Math.max(0.05, Math.min(0.85, chance));

        player.gold -= playerCost;
        player.stats.totalGoldSpent = (player.stats.totalGoldSpent || 0) + playerCost;

        if (Math.random() < chance) {
            kingdom.gold -= kingdomCost;
            const result = Engine.buildNewRoad(player.townId, targetTownId, kingdom.id);
            if (result.success) {
                grantXP(50, 'royal influence');
                modifyTownReputation(player.townId, 10);
                logEvent(`\uD83D\uDC51 King ${kingdom.kingName || 'the King'} of ${kingdom.name} has agreed to build a road between ${currentTown.name} and ${targetTown.name}!`);
                return { success: true, message: `The king agreed! Road construction begins. Cost to you: ${playerCost.toLocaleString()}g. (You do NOT own this road \u2014 no tolls.)`, chance: Math.floor(chance * 100) };
            }
            return result;
        } else {
            logEvent(`\uD83D\uDC51 King ${kingdom.kingName || 'the King'} of ${kingdom.name} declined your petition to build a road between ${currentTown.name} and ${targetTown.name}.`);
            return { success: false, message: `The king considered your petition but declined. Your ${playerCost.toLocaleString()}g petition fee is non-refundable. (Approval chance was ~${Math.floor(chance * 100)}%)` };
        }
    }

    // ========================================================
    // §12H  PETITION SYSTEM
    // ========================================================

    let _nextPetitionId = 1;

    function createPetition(typeId, targetData) {
        if (!player.citizenshipKingdomId && !Object.keys(player.socialRank).some(function(k) { return (player.socialRank[k] || 0) >= 1; })) {
            return { success: false, message: 'You must be a citizen of a kingdom to create petitions.' };
        }
        if (!player.petitions) player.petitions = [];
        const pType = PETITION_TYPES.find(t => t.id === typeId);
        if (!pType) return { success: false, message: 'Invalid petition type.' };
        const active = player.petitions.filter(p => p.status === 'active');
        if (active.length >= CONFIG.PETITION_MAX_ACTIVE) return { success: false, message: 'You already have ' + CONFIG.PETITION_MAX_ACTIVE + ' active petitions. Submit or cancel one first.' };
        const currentDay = Engine.getDay();
        const cooldownEnd = player.petitions
            .filter(p => p.typeId === typeId && (p.status === 'approved' || p.status === 'rejected'))
            .reduce((latest, p) => Math.max(latest, (p.submittedDay || p.createdDay) + CONFIG.PETITION_COOLDOWN_DAYS), 0);
        if (currentDay < cooldownEnd) return { success: false, message: 'Cooldown: you must wait ' + (cooldownEnd - currentDay) + ' more days before creating another ' + pType.name + ' petition.' };
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.create_petition || 3);
        const petition = {
            id: 'pet_' + (_nextPetitionId++),
            typeId: typeId,
            kingdomId: player.citizenshipKingdomId,
            createdDay: currentDay,
            signatures: [],
            targetData: targetData || null,
            status: 'active',
            petitioners: [],
            submitted: false,
        };
        player.petitions.push(petition);
        Engine.logEvent('📜 You created a petition: ' + pType.icon + ' ' + pType.name + '.');
        return { success: true, message: 'Petition created: ' + pType.name, petitionId: petition.id };
    }

    function getKingdomPopulation(kingdomId) {
        const world = Engine.getWorld();
        if (!world || !world.people) return 0;
        return world.people.filter(function(p) { return p.alive && p.kingdomId === kingdomId; }).length;
    }

    function _calcNpcQuirkModifier(npc, typeId) {
        let mod = 0;
        const pers = npc.personality || {};
        const quirks = npc.quirks || [];
        // Personality trait modifiers
        if ((pers.loyalty || 0) > 60) mod += 0.10;
        if ((pers.ambition || 0) > 60) {
            if (typeId === 'declare_war' || typeId === 'establish_trade_agreement' || typeId === 'build_road' || typeId === 'build_market') mod += 0.05;
            if (typeId === 'seek_peace') mod -= 0.05;
        }
        if ((pers.frugality || 0) > 60) {
            if (typeId === 'lower_taxes') mod += 0.10;
            if (typeId === 'raise_taxes') mod -= 0.10;
            if (typeId === 'build_market' || typeId === 'build_road' || typeId === 'build_bridge' || typeId === 'fund_festival') mod -= 0.05;
        }
        if ((pers.warmth || 0) > 60) {
            if (typeId === 'fund_festival' || typeId === 'seek_peace') mod += 0.05;
            if (typeId === 'declare_war') mod -= 0.05;
        }
        // Quirk modifiers
        if (quirks.includes('stubborn')) mod -= 0.15;
        if (quirks.includes('diplomatic')) mod += 0.10;
        if (quirks.includes('loyal_heart')) {
            // checked per-caller with relationship
        }
        return mod;
    }

    function requestSignature(petitionId, npcId) {
        if (!player.petitions) return { signed: false, chance: 0, message: 'No petitions.' };
        const petition = player.petitions.find(function(p) { return p.id === petitionId; });
        if (!petition || petition.status !== 'active') return { signed: false, chance: 0, message: 'Petition not found or not active.' };
        const world = Engine.getWorld();
        if (!world) return { signed: false, chance: 0, message: 'World not available.' };
        const npc = world.people.find(function(p) { return p.id === npcId; });
        if (!npc || !npc.alive) return { signed: false, chance: 0, message: 'Person not found or not alive.' };
        if (npc.townId !== player.townId) return { signed: false, chance: 0, message: 'That person is not in your current town.' };
        if (npc.kingdomId !== petition.kingdomId) return { signed: false, chance: 0, message: 'That person is not a citizen of the petition\'s kingdom.' };
        if (petition.signatures.includes(npcId)) return { signed: false, chance: 0, message: npc.firstName + ' has already signed this petition.' };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.request_signature || 3);

        var rel = getRelationship(npcId);
        var relLevel = rel ? (rel.level || 0) : 0;
        var townRep = (player.townReputation && player.townReputation[player.townId]) || 50;
        var kingdomRep = (player.reputation && player.reputation[petition.kingdomId]) || 50;

        var chance = CONFIG.PETITION_PLAYER_SIGN_CHANCE_BASE;
        chance += relLevel * CONFIG.PETITION_PLAYER_REL_BONUS;
        chance += townRep * CONFIG.PETITION_PLAYER_TOWN_REP_BONUS;
        chance += kingdomRep * CONFIG.PETITION_PLAYER_KINGDOM_REP_BONUS;
        chance += _calcNpcQuirkModifier(npc, petition.typeId);
        // loyal_heart quirk bonus
        if ((npc.quirks || []).includes('loyal_heart') && relLevel > 50) chance += 0.10;

        if (chance < 0.05) {
            return { signed: false, chance: Math.max(0, chance), message: npc.firstName + ' refuses outright to sign your petition. They seem strongly opposed to the idea.' };
        }
        chance = Math.max(0.02, Math.min(0.95, chance));

        var roll = Math.random();
        if (roll < chance) {
            petition.signatures.push(npcId);
            modifyRelationship(npcId, 2);
            return { signed: true, chance: chance, message: npc.firstName + ' ' + npc.lastName + ' signed your petition! ✍️' };
        } else {
            modifyRelationship(npcId, -1);
            return { signed: false, chance: chance, message: npc.firstName + ' declined to sign your petition.' };
        }
    }

    function hirePetitioner(petitionId, mounted) {
        if (!player.petitions) return { success: false, message: 'No petitions.' };
        var petition = player.petitions.find(function(p) { return p.id === petitionId; });
        if (!petition || petition.status !== 'active') return { success: false, message: 'Petition not found or not active.' };
        var cost = mounted ? CONFIG.PETITIONER_MOUNTED_COST : CONFIG.PETITIONER_BASIC_COST;
        // Economic Advisor: -25% petition cost
        if (hasSkill('economic_advisor')) {
            cost = Math.floor(cost * 0.75);
        }
        if (player.gold < cost) return { success: false, message: 'Not enough gold. Need ' + cost + 'g for the first day.' };
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.hire_petitioner || 2);
        player.gold -= cost;
        player.stats.totalGoldSpent = (player.stats.totalGoldSpent || 0) + cost;
        var petitioner = {
            id: 'ptr_' + Date.now() + '_' + Math.floor(Math.random() * 1000),
            mounted: !!mounted,
            hiredDay: Engine.getDay(),
            currentTownId: player.townId,
            dailyCost: cost,
            active: true,
            signaturesCollected: 0,
            moveCooldown: 3 + Math.floor(Math.random() * 3),
        };
        petition.petitioners.push(petitioner);
        Engine.logEvent('📜 Hired a ' + (mounted ? 'mounted' : 'basic') + ' petitioner for ' + cost + 'g/day.');
        return { success: true, message: 'Hired ' + (mounted ? 'mounted' : 'basic') + ' petitioner (' + cost + 'g/day).' };
    }

    function firePetitioner(petitionId, petitionerId) {
        if (!player.petitions) return { success: false, message: 'No petitions.' };
        var petition = player.petitions.find(function(p) { return p.id === petitionId; });
        if (!petition) return { success: false, message: 'Petition not found.' };
        var ptr = petition.petitioners.find(function(p) { return p.id === petitionerId; });
        if (!ptr) return { success: false, message: 'Petitioner not found.' };
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.fire_petitioner || 1);
        ptr.active = false;
        Engine.logEvent('📜 Fired a petitioner.');
        return { success: true, message: 'Petitioner fired.' };
    }

    function tickPetitions(currentDay) {
        if (!player.petitions) return;
        var world = Engine.getWorld();
        if (!world) return;

        for (var pi = 0; pi < player.petitions.length; pi++) {
            var petition = player.petitions[pi];
            if (petition.status !== 'active') continue;

            // Check expiration
            if (currentDay - petition.createdDay >= CONFIG.PETITION_MAX_DURATION_DAYS) {
                submitPetition(petition.id);
                continue;
            }

            // Tick petitioners
            for (var ti = 0; ti < petition.petitioners.length; ti++) {
                var ptr = petition.petitioners[ti];
                if (!ptr.active) continue;

                // Check if player can afford daily cost
                if (player.gold < ptr.dailyCost) {
                    ptr.active = false;
                    Engine.logEvent('📜 Petitioner fired — you cannot afford the ' + ptr.dailyCost + 'g daily cost.');
                    continue;
                }
                player.gold -= ptr.dailyCost;
                player.stats.totalGoldSpent = (player.stats.totalGoldSpent || 0) + ptr.dailyCost;

                // Petitioner attempts 2-4 signatures per day
                var attempts = 2 + Math.floor(Math.random() * 3);
                for (var a = 0; a < attempts; a++) {
                    // Find eligible NPCs in petitioner's current town
                    var eligible = world.people.filter(function(p) {
                        return p.alive && p.townId === ptr.currentTownId &&
                               p.kingdomId === petition.kingdomId &&
                               !petition.signatures.includes(p.id);
                    });
                    if (eligible.length === 0) break;
                    var npc = eligible[Math.floor(Math.random() * eligible.length)];

                    var rel = getRelationship(npc.id);
                    var relLevel = rel ? (rel.level || 0) : 0;
                    var townRep = (player.townReputation && player.townReputation[ptr.currentTownId]) || 50;
                    var kingdomRep = (player.reputation && player.reputation[petition.kingdomId]) || 50;

                    var chance = CONFIG.PETITIONER_BASE_SIGN_CHANCE;
                    chance += relLevel * CONFIG.PETITIONER_RELATIONSHIP_BONUS;
                    chance += townRep * CONFIG.PETITIONER_TOWN_REP_BONUS;
                    chance += kingdomRep * CONFIG.PETITIONER_KINGDOM_REP_BONUS;
                    chance += _calcNpcQuirkModifier(npc, petition.typeId) * 0.7;
                    chance = Math.max(0.02, Math.min(0.85, chance));

                    if (Math.random() < chance) {
                        petition.signatures.push(npc.id);
                        ptr.signaturesCollected++;
                    }
                }

                // Move petitioner to different town every 3-5 days
                ptr.moveCooldown--;
                if (ptr.moveCooldown <= 0) {
                    var towns = Engine.getTowns ? Engine.getTowns() : (world.towns || []);
                    var kingdomTowns = towns.filter(function(t) { return t.kingdomId === petition.kingdomId && t.id !== ptr.currentTownId; });
                    if (kingdomTowns.length > 0) {
                        ptr.currentTownId = kingdomTowns[Math.floor(Math.random() * kingdomTowns.length)].id;
                    }
                    ptr.moveCooldown = 3 + Math.floor(Math.random() * 3);
                }
            }
        }
    }

    function _getWeightedSignatures(petition) {
        var world = Engine.getWorld();
        if (!world) return petition.signatures.length;
        var total = 0;
        for (var i = 0; i < petition.signatures.length; i++) {
            var npc = world.people.find(function(p) { return p.id === petition.signatures[i]; });
            if (!npc) { total += 1; continue; }
            var rankIdx = 0;
            if (npc.socialRank != null) rankIdx = npc.socialRank;
            if (rankIdx >= 5 || (npc.occupation === 'noble' || npc.wealthClass === 'upper')) {
                total += CONFIG.PETITION_NOBLE_SIGNATURE_WEIGHT;
            } else if (npc.isEliteMerchant) {
                total += CONFIG.PETITION_ELITE_SIGNATURE_WEIGHT;
            } else {
                total += 1;
            }
        }
        return total;
    }

    function getPetitionChanceEstimate(petitionId) {
        if (!player.petitions) return null;
        var petition = player.petitions.find(function(p) { return p.id === petitionId; });
        if (!petition) return null;

        var kingdomPop = getKingdomPopulation(petition.kingdomId);
        var weighted = _getWeightedSignatures(petition);
        var signaturePct = kingdomPop > 0 ? (weighted / kingdomPop) * 100 : 0;

        if (signaturePct < CONFIG.PETITION_MIN_SIGNATURES_PCT) {
            var needed = Math.ceil(kingdomPop * CONFIG.PETITION_MIN_SIGNATURES_PCT / 100) - weighted;
            return {
                chance: 0,
                signaturePct: signaturePct,
                totalWeightedSignatures: weighted,
                kingdomPop: kingdomPop,
                signaturesNeeded5pct: Math.max(0, needed),
                signaturesNeeded15pct: Math.max(0, Math.ceil(kingdomPop * CONFIG.PETITION_GOOD_CHANCE_PCT / 100) - weighted),
                signaturesNeeded25pct: Math.max(0, Math.ceil(kingdomPop * CONFIG.PETITION_GREAT_CHANCE_PCT / 100) - weighted),
                message: 'Not enough support yet. Need at least ' + CONFIG.PETITION_MIN_SIGNATURES_PCT + '% of the population.',
            };
        }

        var chance = CONFIG.PETITION_BASE_CHANCE;
        chance += signaturePct * CONFIG.PETITION_PER_PCT_BONUS;

        // King personality
        var kingdom = Engine.findKingdom(petition.kingdomId);
        if (kingdom && kingdom.kingPersonality) {
            var kp = kingdom.kingPersonality;
            if (kp.intelligence === 'brilliant') chance += 0.10;
            if (kp.intelligence === 'dim') chance -= 0.05;
            if (kp.ambition === 'ambitious' && (petition.typeId === 'declare_war' || petition.typeId === 'establish_trade_agreement' || petition.typeId === 'build_road' || petition.typeId === 'build_market')) chance += 0.05;
            if (kp.ambition === 'content') chance -= 0.05;
            var pType = PETITION_TYPES.find(function(t) { return t.id === petition.typeId; });
            var isCostly = pType && pType.costFactor > 0;
            if (kp.greed === 'generous' && isCostly) chance += 0.10;
            if (kp.greed === 'greedy') chance -= 0.15;
            if (kp.temperament === 'kind' && (petition.typeId === 'seek_peace' || petition.typeId === 'fund_festival')) chance += 0.05;
            if (kp.temperament === 'cruel') chance -= 0.05;
        }

        // Player bonuses
        var rep = (player.reputation && player.reputation[petition.kingdomId]) || 50;
        chance += (rep - 30) / 200;
        var rankIdx = getPlayerRankIndex(petition.kingdomId);
        chance += rankIdx * 0.03;

        // War modifiers
        if (kingdom && kingdom.atWar && kingdom.atWar.size > 0) {
            if (petition.typeId === 'declare_war') chance += 0.15;
            else if (petition.typeId !== 'seek_peace') chance -= 0.15;
        }

        // Treasury
        if (kingdom) {
            if (kingdom.gold < 1000) chance -= 0.10;
            else if (kingdom.gold > 10000) chance += 0.05;
        }

        // Court Etiquette skill: +10% petition success
        if (hasSkill('court_etiquette')) chance += 0.10;

        chance = Math.max(0.02, Math.min(0.90, chance));

        return {
            chance: chance,
            signaturePct: signaturePct,
            totalWeightedSignatures: weighted,
            kingdomPop: kingdomPop,
            signaturesNeeded5pct: Math.max(0, Math.ceil(kingdomPop * CONFIG.PETITION_MIN_SIGNATURES_PCT / 100) - weighted),
            signaturesNeeded15pct: Math.max(0, Math.ceil(kingdomPop * CONFIG.PETITION_GOOD_CHANCE_PCT / 100) - weighted),
            signaturesNeeded25pct: Math.max(0, Math.ceil(kingdomPop * CONFIG.PETITION_GREAT_CHANCE_PCT / 100) - weighted),
        };
    }

    function submitPetition(petitionId) {
        if (!player.petitions) return { success: false, message: 'No petitions.' };
        var petition = player.petitions.find(function(p) { return p.id === petitionId; });
        if (!petition || petition.status !== 'active') return { success: false, message: 'Petition not found or not active.' };

        // Energy check
        var ePet = checkEnergyForAction(ENERGY_CONFIG.PETITION_COST || 5);
        if (ePet.blocked) return { success: false, message: ePet.message };

        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.submit_petition || 5);
        consumeEnergy(ENERGY_CONFIG.PETITION_COST || 5);

        petition.submitted = true;
        petition.submittedDay = Engine.getDay();

        // Fire all petitioners
        for (var i = 0; i < petition.petitioners.length; i++) {
            petition.petitioners[i].active = false;
        }

        var estimate = getPetitionChanceEstimate(petitionId);
        if (!estimate || estimate.chance === 0) {
            petition.status = 'rejected';
            var pType = PETITION_TYPES.find(function(t) { return t.id === petition.typeId; });
            Engine.logEvent('📜 Your petition for ' + (pType ? pType.name : petition.typeId) + ' was rejected — not enough signatures.');
            return { success: false, approved: false, message: 'Petition rejected: not enough signatures. Need at least ' + CONFIG.PETITION_MIN_SIGNATURES_PCT + '% of the kingdom population.' };
        }

        var roll = Math.random();
        var pType = PETITION_TYPES.find(function(t) { return t.id === petition.typeId; });

        if (roll < estimate.chance) {
            petition.status = 'approved';
            executePetitionAction(petition);
            var xpReward = 30 + Math.floor(Math.min(70, estimate.signaturePct * 2));
            grantXP(xpReward, 'petition');
            Engine.logEvent('📜 Your petition for ' + (pType ? pType.name : petition.typeId) + ' was APPROVED by the king! 🎉');
            return { success: true, approved: true, chance: estimate.chance, message: 'The king approved your petition! ' + (pType ? pType.name : '') + ' will be carried out.' };
        } else {
            petition.status = 'rejected';
            Engine.logEvent('📜 Your petition for ' + (pType ? pType.name : petition.typeId) + ' was rejected by the king.');
            return { success: true, approved: false, chance: estimate.chance, message: 'The king considered your petition but declined. (Approval chance was ~' + Math.floor(estimate.chance * 100) + '%)' };
        }
    }

    function executePetitionAction(petition) {
        var world = Engine.getWorld();
        var kingdom = Engine.findKingdom(petition.kingdomId);
        var td = petition.targetData || {};

        switch (petition.typeId) {
            case 'build_road': {
                if (td.fromTownId && td.toTownId) {
                    var result = Engine.buildNewRoad(td.fromTownId, td.toTownId, petition.kingdomId, {});
                    if (result && result.success) {
                        Engine.logEvent('🛤️ The kingdom built a new road between ' + (td.fromName || td.fromTownId) + ' and ' + (td.toName || td.toTownId) + '!');
                    }
                }
                break;
            }
            case 'increase_security': {
                if (td.townId) {
                    var town = Engine.findTown(td.townId);
                    if (town) {
                        var addGuards = 3 + Math.floor(Math.random() * 3);
                        town.garrison = (town.garrison || 0) + addGuards;
                        Engine.logEvent('🛡️ ' + addGuards + ' guards deployed to ' + town.name + '!');
                    }
                }
                break;
            }
            case 'clear_bandits': {
                if (td.roadIndex != null) {
                    var roads = Engine.getRoads();
                    if (roads && roads[td.roadIndex]) {
                        var road = roads[td.roadIndex];
                        road.banditThreat = Math.max(0, (road.banditThreat || 0) - 50);
                        road.safe = true;
                        var fromT = Engine.findTown(road.fromTownId);
                        var toT = Engine.findTown(road.toTownId);
                        Engine.logEvent('⚔️ Soldiers cleared bandits from the road between ' + (fromT ? fromT.name : '?') + ' and ' + (toT ? toT.name : '?') + '!');
                    }
                }
                break;
            }
            case 'lower_taxes': {
                if (kingdom) {
                    kingdom.taxRate = Math.max(0.05, (kingdom.taxRate || 0.10) - 0.05);
                    Engine.logEvent('💰 ' + kingdom.name + ' lowered its tax rate to ' + Math.round(kingdom.taxRate * 100) + '%!');
                }
                break;
            }
            case 'raise_taxes': {
                if (kingdom) {
                    kingdom.taxRate = Math.min(0.40, (kingdom.taxRate || 0.10) + 0.05);
                    Engine.logEvent('📈 ' + kingdom.name + ' raised its tax rate to ' + Math.round(kingdom.taxRate * 100) + '%!');
                }
                break;
            }
            case 'build_market': {
                if (td.townId) {
                    var town = Engine.findTown(td.townId);
                    if (town) {
                        if (!town.buildings) town.buildings = [];
                        town.buildings.push({ type: 'marketplace', level: 1, ownerId: petition.kingdomId, active: true, workers: [] });
                        town.prosperity = Math.min(100, (town.prosperity || 50) + 5);
                        Engine.logEvent('🏪 A new market was built in ' + town.name + '!');
                    }
                }
                break;
            }
            case 'repair_infrastructure': {
                if (td.townId) {
                    var town = Engine.findTown(td.townId);
                    if (town) {
                        var roads = Engine.getRoads();
                        for (var ri = 0; ri < roads.length; ri++) {
                            if (roads[ri].fromTownId === td.townId || roads[ri].toTownId === td.townId) {
                                roads[ri].condition = 'new';
                                roads[ri].quality = Math.min(3, (roads[ri].quality || 1) + 1);
                            }
                        }
                        town.prosperity = Math.min(100, (town.prosperity || 50) + 3);
                        Engine.logEvent('🔧 Infrastructure repaired in ' + town.name + '!');
                    }
                }
                break;
            }
            case 'establish_trade_agreement': {
                if (td.targetKingdomId && kingdom) {
                    var targetK = Engine.findKingdom(td.targetKingdomId);
                    if (targetK) {
                        if (!kingdom.relations) kingdom.relations = {};
                        if (!targetK.relations) targetK.relations = {};
                        kingdom.relations[td.targetKingdomId] = Math.min(100, (kingdom.relations[td.targetKingdomId] || 0) + 30);
                        targetK.relations[petition.kingdomId] = Math.min(100, (targetK.relations[petition.kingdomId] || 0) + 30);
                        Engine.logEvent('🤝 Trade agreement established between ' + kingdom.name + ' and ' + targetK.name + '!');
                    }
                }
                break;
            }
            case 'ban_goods': {
                if (td.resourceId && kingdom) {
                    if (!kingdom.laws) kingdom.laws = {};
                    if (!kingdom.laws.bannedGoods) kingdom.laws.bannedGoods = [];
                    if (!kingdom.laws.bannedGoods.includes(td.resourceId)) {
                        kingdom.laws.bannedGoods.push(td.resourceId);
                    }
                    Engine.logEvent('🚫 ' + kingdom.name + ' banned the trade of ' + (td.resourceName || td.resourceId) + '!');
                }
                break;
            }
            case 'unban_goods': {
                if (td.resourceId && kingdom) {
                    if (kingdom.laws && kingdom.laws.bannedGoods) {
                        kingdom.laws.bannedGoods = kingdom.laws.bannedGoods.filter(function(g) { return g !== td.resourceId; });
                    }
                    Engine.logEvent('✅ ' + kingdom.name + ' unbanned the trade of ' + (td.resourceName || td.resourceId) + '!');
                }
                break;
            }
            case 'build_bridge': {
                if (td.roadIndex != null) {
                    var roads = Engine.getRoads();
                    if (roads && roads[td.roadIndex]) {
                        roads[td.roadIndex].hasBridge = true;
                        roads[td.roadIndex].bridgeDestroyed = false;
                        var fromT = Engine.findTown(roads[td.roadIndex].fromTownId);
                        var toT = Engine.findTown(roads[td.roadIndex].toTownId);
                        Engine.logEvent('🌉 A bridge was built on the road between ' + (fromT ? fromT.name : '?') + ' and ' + (toT ? toT.name : '?') + '!');
                    }
                }
                break;
            }
            case 'declare_war': {
                if (td.targetKingdomId && kingdom) {
                    var targetK = Engine.findKingdom(td.targetKingdomId);
                    if (targetK && Engine.declareWar) {
                        if (!kingdom.atWar || !kingdom.atWar.has(td.targetKingdomId)) {
                            Engine.declareWar(kingdom, targetK);
                            Engine.logEvent('⚔️ ' + kingdom.name + ' declared war on ' + targetK.name + '!');
                        }
                    }
                }
                break;
            }
            case 'seek_peace': {
                if (td.targetKingdomId && kingdom) {
                    var targetK = Engine.findKingdom(td.targetKingdomId);
                    if (targetK && Engine.makePeace) {
                        if (kingdom.atWar && kingdom.atWar.has(td.targetKingdomId)) {
                            Engine.makePeace(kingdom, targetK, false, null);
                            Engine.logEvent('🕊️ ' + kingdom.name + ' made peace with ' + targetK.name + '!');
                        }
                    }
                }
                break;
            }
            case 'fund_festival': {
                if (td.townId) {
                    var town = Engine.findTown(td.townId);
                    if (town) {
                        town.happiness = Math.min(100, (town.happiness || 50) + 15);
                        town.prosperity = Math.min(100, (town.prosperity || 50) + 5);
                        Engine.logEvent('🎉 A grand festival was held in ' + town.name + '! Happiness soars!');
                    }
                }
                break;
            }
        }
    }

    function cancelPetition(petitionId) {
        if (!player.petitions) return { success: false, message: 'No petitions.' };
        var petition = player.petitions.find(function(p) { return p.id === petitionId; });
        if (!petition || petition.status !== 'active') return { success: false, message: 'Petition not found or not active.' };
        petition.status = 'cancelled';
        for (var i = 0; i < petition.petitioners.length; i++) {
            petition.petitioners[i].active = false;
        }
        Engine.logEvent('📜 You cancelled your petition.');
        return { success: true, message: 'Petition cancelled.' };
    }

    function getActivePetitions() {
        if (!player.petitions) return [];
        return player.petitions.filter(function(p) { return p.status === 'active'; });
    }

    function getPetitionHistory() {
        return player.petitions || [];
    }

    // ========================================================
    // §12G  DARK DEEDS — CORRUPT ACTIONS SYSTEM
    // ========================================================

    function calculateCorruptDetection(baseDetection, town) {
        let detection = baseDetection;
        detection += ((town && town.security) || 50) * 0.005;
        const w = Engine.getWorld ? Engine.getWorld() : null;
        const hour = w ? (w.hour || 0) : 12;
        if (hour >= 20 || hour <= 5) detection *= 0.7;
        if (hasSkill('shadow_dealings')) detection *= 0.85;
        if (hasSkill('ghost')) detection *= 0.5;
        detection += (player.notoriety || 0) * 0.003;
        // Bribed guards reduction
        if (town && player.bribedGuards[town.id]) {
            const bg = player.bribedGuards[town.id];
            const day = Engine.getDay();
            if (bg.expiresDay > day) {
                detection *= (1 - (bg.reductionPct || 40) / 100);
            }
        }
        // Alibi reduces detection
        if (player.alibi && Engine.getDay() <= player.alibi.expiresDay) {
            detection *= 0.8;
        }
        return Math.max(0.02, Math.min(0.95, detection));
    }

    function isInTown(townId) {
        return !player.traveling && player.townId === townId;
    }

    function isJailed() {
        return player.jailedUntilDay > 0 && Engine.getDay() < player.jailedUntilDay;
    }

    function recordCorruptAction(actionId, caught) {
        player.corruptActions = (player.corruptActions || 0) + 1;
        player.crimesCommitted[actionId] = (player.crimesCommitted[actionId] || 0) + 1;
        if (!caught) {
            player.corruptionStreak = (player.corruptionStreak || 0) + 1;
        } else {
            player.corruptionStreak = 0;
        }
        // Achievement checks
        if (player.corruptActions === 1) unlockAchievement('first_crime');
        if (player.corruptActions >= 50) unlockAchievement('crime_lord');
        if (player.corruptionStreak >= 20) unlockAchievement('untouchable_crimes');
    }

    function applyCorruptPenalty(town, kingdom, fine, repLoss, jailDays, exile, crimeId) {
        const kId = kingdom ? kingdom.id : (town ? town.kingdomId : null);

        // If a crimeId is specified, look up the kingdom's punishment
        if (crimeId && kId) {
            var punishment = getCrimePunishment(kId, crimeId);
            if (punishment) {
                if (fine === 0 && punishment.fine > 0) fine = punishment.fine;
                if (jailDays === 0 && punishment.jailDays > 0) jailDays = punishment.jailDays;
            }
            // Track criminal record
            if (!player.criminalRecord) player.criminalRecord = {};
            if (!player.criminalRecord[kId]) player.criminalRecord[kId] = {};
            player.criminalRecord[kId][crimeId] = (player.criminalRecord[kId][crimeId] || 0) + 1;
        }

        // Foreign Noble crime handling
        if (kId && getForeignNobleStatus(kId) && (jailDays > 0 || exile)) {
            var isExecution = exile || jailDays >= 180;
            var fnResult = handleForeignNobleCrime(kId, jailDays, isExecution);
            if (fnResult && fnResult.paid) {
                // Foreign noble fine paid - skip jail/execution
                if (kId && repLoss > 0) {
                    player.reputation[kId] = Math.max(0, (player.reputation[kId] || 50) - repLoss);
                }
                return fnResult.fine;
            }
        }

        const actualFine = Math.min(fine, player.gold);
        player.gold -= actualFine;
        if (kId && repLoss > 0) {
            player.reputation[kId] = Math.max(0, (player.reputation[kId] || 50) - repLoss);
        }
        if (jailDays > 0) {
            let days = jailDays;
            if (hasSkill('jail_break')) days = Math.max(1, Math.floor(days * 0.5));
            player.jailedUntilDay = Engine.getDay() + days;
        }
        if (exile && kId) {
            // Exile: reputation to 0, lose all buildings in kingdom
            player.reputation[kId] = 0;
            Engine.logEvent(`${player.fullName} has been exiled from ${kingdom ? kingdom.name : 'the kingdom'}!`);
        }
        return actualFine;
    }

    // ── (a) Sabotage Building ──
    function sabotageBuilding(buildingIndex, townId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        const bld = town.buildings[buildingIndex];
        if (!bld) return { success: false, message: 'Building not found.' };
        const toolQty = player.inventory.tools || 0;
        if (toolQty < 2) return { success: false, message: 'Need 2 tools in inventory.' };

        player.inventory.tools -= 2;
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(0.25, town);
        const caught = rng && rng.chance(detection);

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, 200, 15, 5, false);
            recordCorruptAction('sabotage_building', true);
            player.notoriety += 8;
            Engine.logEvent(`${player.fullName} was caught sabotaging a building in ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, jailed 5 days, reputation -15.` };
        }

        const disabledDays = rng ? rng.randInt(15, 30) : 20;
        player.sabotagedBuildings.push({ townId, buildingIdx: buildingIndex, expiresDay: Engine.getDay() + disabledDays });
        bld._disabledUntil = Engine.getDay() + disabledDays;
        player.notoriety += 8;
        recordCorruptAction('sabotage_building', false);
        grantXP(10, 'Sabotaged building');
        Engine.logEvent(`A building in ${town.name} has been sabotaged! Production halted for ${disabledDays} days.`);
        return { success: true, message: `✅ Building sabotaged! Disabled for ${disabledDays} days.` };
    }

    // ── (b) Sabotage Road ──
    function sabotageRoad(roadIdx) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        const toolQty = player.inventory.tools || 0;
        if (toolQty < 5) return { success: false, message: 'Need 5 tools in inventory.' };
        const roads = Engine.getRoads ? Engine.getRoads() : [];
        const road = roads[roadIdx];
        if (!road) return { success: false, message: 'Road not found.' };
        // Must be at one end
        if (player.townId !== road.fromTownId && player.townId !== road.toTownId) {
            return { success: false, message: 'Must be at one end of the road.' };
        }

        player.inventory.tools -= 5;
        const town = Engine.findTown(player.townId);
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(0.15, town);
        const caught = rng && rng.chance(detection);

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town ? town.kingdomId : null) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, 300, 20, 0, false);
            recordCorruptAction('sabotage_road', true);
            player.notoriety += 10;
            Engine.logEvent(`${player.fullName} was caught sabotaging a road!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, reputation -20.` };
        }

        const origQuality = road.quality || 1;
        road.quality = Math.max(0, origQuality - 1);
        player.sabotagedRoads.push({ roadIdx, expiresDay: Engine.getDay() + 60, origQuality });
        player.notoriety += 10;
        recordCorruptAction('sabotage_road', false);
        grantXP(15, 'Sabotaged road');
        Engine.logEvent('A road has been sabotaged! Travel slowed.');
        return { success: true, message: '✅ Road sabotaged! Quality reduced for 60 days.' };
    }

    // ── (c) Arson ──
    function commitArson(buildingIndex, townId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        const bld = town.buildings[buildingIndex];
        if (!bld) return { success: false, message: 'Building not found.' };
        const woodQty = player.inventory.wood || 0;
        if (woodQty < 1) return { success: false, message: 'Need wood for fire materials.' };
        if (player.gold < 10) return { success: false, message: 'Need 10g for oil.' };

        player.inventory.wood = (player.inventory.wood || 0) - 1;
        player.gold -= 10;

        let baseDetect = 0.40;
        if (hasSkill('arsonist_skill')) baseDetect *= 0.5;
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(baseDetect, town);
        const caught = rng && rng.chance(detection);

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const doExile = rng && rng.chance(0.3);
            const actualFine = applyCorruptPenalty(town, kingdom, 1000, 30, 15, doExile);
            recordCorruptAction('arson', true);
            player.notoriety += 25;
            Engine.logEvent(`${player.fullName} was caught committing arson in ${town.name}!`);
            let msg = `🚨 CAUGHT! Fined ${actualFine}g, jailed 15 days, reputation -30.`;
            if (doExile) msg += ' EXILED from kingdom!';
            return { success: false, caught: true, message: msg };
        }

        // Destroy building permanently
        town.buildings.splice(buildingIndex, 1);
        player.arsonCount = (player.arsonCount || 0) + 1;
        player.notoriety += 25;
        recordCorruptAction('arson', false);
        grantXP(25, 'Arson');
        if (player.arsonCount >= 5) unlockAchievement('arsonist_ach');
        Engine.logEvent(`A building in ${town.name} has been destroyed by fire!`);
        return { success: true, message: '✅ Building destroyed by fire!' };
    }

    // ── (d) Steal Goods ──
    function stealGoods(resourceId, qty, townId) {
        qty = Number(qty);
        if (!qty || !isFinite(qty) || qty <= 0) return { success: false, message: 'Invalid quantity.' };
        qty = Math.floor(qty);
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        qty = Math.min(qty, 20);
        const available = (town.market && town.market.supply[resourceId]) || 0;
        if (available < qty) return { success: false, message: `Only ${available} available in market.` };

        const w = Engine.getWorld ? Engine.getWorld() : null;
        const hour = w ? (w.hour || 0) : 12;
        const baseDetect = (hour >= 20 || hour <= 5) ? 0.20 : 0.35;
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(baseDetect, town);
        const caught = rng && rng.chance(detection);
        const res = findResource(resourceId);
        const value = res ? res.basePrice * qty : 10 * qty;

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, value * 2, 10, 0, false);
            recordCorruptAction('steal_goods', true);
            player.notoriety += 5;
            Engine.logEvent(`${player.fullName} was caught stealing in ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, reputation -10. Goods confiscated.` };
        }

        town.market.supply[resourceId] -= qty;
        player.inventory[resourceId] = (player.inventory[resourceId] || 0) + qty;
        player.notoriety += 5;
        recordCorruptAction('steal_goods', false);
        const xpBonus = Math.min(10, Math.floor(value / 50));
        grantXP(5 + xpBonus, 'Stole goods');
        Engine.logEvent(`Goods went missing from ${town.name}'s market.`);
        return { success: true, message: `✅ Stole ${qty} ${res ? res.name : resourceId}! (worth ~${value}g)` };
    }

    // ── (d2) Pickpocket ──
    function pickpocket(townId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };

        const w = Engine.getWorld ? Engine.getWorld() : null;
        const hour = w ? (w.hour || 0) : 12;
        const isNight = (hour >= 20 || hour <= 5);
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(isNight ? 0.15 : 0.30, town);
        const caught = rng && rng.chance(detection);
        const yield_ = 5 + Math.floor(Math.random() * 26); // 5-30g

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, yield_ * 3, 5, 3, false);
            recordCorruptAction('pickpocket', true);
            player.notoriety += 3;
            Engine.logEvent(`${player.fullName} was caught pickpocketing in ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, jailed 3 days.` };
        }

        player.gold += yield_;
        player.stats.totalGoldEarned += yield_;
        player.notoriety += 2;
        recordCorruptAction('pickpocket', false);
        grantXP(3, 'Pickpocketed');
        Engine.logEvent('A townsfolk reported missing coins.');
        return { success: true, message: `✅ Lifted ${yield_}g from an unsuspecting local!` };
    }

    // ── (d3) Warehouse Heist ──
    function warehouseHeist(townId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        if (!hasSkill('shadow_dealings') && !hasSkill('discrete')) return { success: false, message: 'Requires Shadow Dealings or Discrete skill.' };
        if ((player.inventory.tools || 0) < 1) return { success: false, message: 'Need 1 tools to break in.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };

        player.inventory.tools -= 1;
        const w = Engine.getWorld ? Engine.getWorld() : null;
        const hour = w ? (w.hour || 0) : 12;
        const isNight = (hour >= 20 || hour <= 5);
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(isNight ? 0.25 : 0.45, town);
        const caught = rng && rng.chance(detection);

        // Pick random goods from town market
        const marketKeys = Object.keys(town.market.supply || {}).filter(k => (town.market.supply[k] || 0) > 5);
        if (marketKeys.length === 0) return { success: false, message: 'Nothing worth stealing here.' };

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, 500, 20, 10, false);
            recordCorruptAction('warehouse_heist', true);
            player.notoriety += 10;
            Engine.logEvent(`${player.fullName} was caught breaking into a warehouse in ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, jailed 10 days, reputation -20.` };
        }

        // Steal 10-50 units of 1-3 random goods
        let stolenMsg = [];
        let totalValue = 0;
        const numGoods = 1 + Math.floor(Math.random() * 3);
        for (let g = 0; g < numGoods && g < marketKeys.length; g++) {
            const resId = marketKeys[Math.floor(Math.random() * marketKeys.length)];
            const avail = town.market.supply[resId] || 0;
            const qty = Math.min(avail, 10 + Math.floor(Math.random() * 41));
            if (qty <= 0) continue;
            town.market.supply[resId] -= qty;
            player.inventory[resId] = (player.inventory[resId] || 0) + qty;
            const res = findResource(resId);
            totalValue += (res ? res.basePrice : 10) * qty;
            stolenMsg.push(`${qty} ${res ? res.name : resId}`);
        }

        player.notoriety += 8;
        recordCorruptAction('warehouse_heist', false);
        grantXP(15, 'Warehouse heist');
        Engine.logEvent('A warehouse in ' + town.name + ' was broken into overnight.');
        return { success: true, message: `✅ Heist successful! Stole: ${stolenMsg.join(', ')} (worth ~${totalValue}g)` };
    }

    // ── (d4) Rob Traveler ──
    function robTraveler(townId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        if (!hasSkill('shadow_dealings')) return { success: false, message: 'Requires Shadow Dealings skill.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };

        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(0.20, town);
        const caught = rng && rng.chance(detection);

        // Combat check — having weapon/armor helps
        const hasWeapon = !!player.weapon;
        const hasArmor = !!player.armor;
        const combatPower = (hasWeapon ? 30 : 5) + (hasArmor ? 20 : 0) + (player.militaryRank ? 15 : 0);
        const travelerFight = 10 + Math.floor(Math.random() * 40); // 10-50
        const playerWins = combatPower > travelerFight;

        if (!playerWins) {
            // Traveler fights back — player takes minor damage
            player.notoriety += 5;
            recordCorruptAction('rob_traveler', true);
            Engine.logEvent(`${player.fullName} tried to rob a traveler but was fought off!`);
            return { success: false, message: '⚔️ The traveler fought back! You fled empty-handed. (-5 notoriety gained)' };
        }

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, 300, 15, 7, false);
            recordCorruptAction('rob_traveler', true);
            player.notoriety += 8;
            Engine.logEvent(`${player.fullName} was caught robbing travelers near ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, jailed 7 days.` };
        }

        // Success — gain gold and maybe goods
        const goldStolen = 20 + Math.floor(Math.random() * 81); // 20-100g
        player.gold += goldStolen;
        player.stats.totalGoldEarned += goldStolen;

        // 50% chance to also get some random goods
        let goodsMsg = '';
        if (Math.random() < 0.5) {
            const possibleGoods = ['bread', 'cloth', 'wine', 'jewelry', 'herbs', 'salt'];
            const resId = possibleGoods[Math.floor(Math.random() * possibleGoods.length)];
            const qty = 1 + Math.floor(Math.random() * 5);
            player.inventory[resId] = (player.inventory[resId] || 0) + qty;
            const res = findResource(resId);
            goodsMsg = ` + ${qty} ${res ? res.name : resId}`;
        }

        player.notoriety += 6;
        recordCorruptAction('rob_traveler', false);
        grantXP(10, 'Robbed traveler');
        Engine.logEvent('A traveler was robbed on the road near ' + town.name + '.');
        return { success: true, message: `✅ Robbed a traveler for ${goldStolen}g${goodsMsg}!` };
    }

    // ── (d5) Raid Caravan ──
    function raidCaravan(townId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        if (player.gold < 200) return { success: false, message: 'Need 200g to hire bandits.' };
        if (!hasSkill('dark_connections') && player.notoriety < 40) return { success: false, message: 'Requires Dark Connections skill or 40+ notoriety.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };

        player.gold -= 200;
        player.stats.totalGoldSpent += 200;

        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(0.35, town);
        const caught = rng && rng.chance(detection);

        // 20% chance bandits just take the money and run
        if (Math.random() < 0.2) {
            recordCorruptAction('raid_caravan', true);
            player.notoriety += 3;
            Engine.logEvent('The bandits you hired took your gold and disappeared.');
            return { success: false, message: '💀 The bandits took your 200g and vanished! Never trust criminals.' };
        }

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, 1000, 30, 15, true);
            recordCorruptAction('raid_caravan', true);
            player.notoriety += 15;
            Engine.logEvent(`${player.fullName} was linked to a caravan raid near ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, jailed 15 days, reputation -30. This is a serious crime!` };
        }

        // Success — big haul of random goods
        let stolenMsg = [];
        let totalValue = 0;
        const possibleGoods = ['wheat', 'iron', 'cloth', 'wine', 'tools', 'weapons', 'armor', 'silk', 'spices', 'jewelry'];
        const numGoods = 2 + Math.floor(Math.random() * 3); // 2-4 types
        for (let g = 0; g < numGoods; g++) {
            const resId = possibleGoods[Math.floor(Math.random() * possibleGoods.length)];
            const qty = 10 + Math.floor(Math.random() * 41); // 10-50
            player.inventory[resId] = (player.inventory[resId] || 0) + qty;
            const res = findResource(resId);
            totalValue += (res ? res.basePrice : 15) * qty;
            stolenMsg.push(`${qty} ${res ? res.name : resId}`);
        }

        player.notoriety += 12;
        recordCorruptAction('raid_caravan', false);
        grantXP(25, 'Raided caravan');
        Engine.logEvent('A trade caravan was ambushed on the roads near ' + town.name + '.');
        return { success: true, message: `✅ Caravan raid successful! Loot: ${stolenMsg.join(', ')} (worth ~${totalValue}g)` };
    }

    // ── (e) Sell Counterfeit Goods ──
    function sellCounterfeit(resourceId, qty, townId) {
        qty = Number(qty);
        if (!qty || !isFinite(qty) || qty <= 0) return { success: false, message: 'Invalid quantity.' };
        qty = Math.floor(qty);
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!hasSkill('master_forger')) return { success: false, message: 'Requires Master Forger skill.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        const allowedGoods = ['jewelry', 'wine', 'cloth'];
        if (!allowedGoods.includes(resourceId)) return { success: false, message: 'Can only counterfeit jewelry, wine, or cloth.' };
        const res = findResource(resourceId);
        if (!res) return { success: false, message: 'Resource not found.' };

        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(0.30, town);
        const caught = rng && rng.chance(detection);
        const revenue = Math.floor(res.basePrice * qty * ((town.market && town.market.prices[resourceId]) ? town.market.prices[resourceId] / res.basePrice : 1));

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, revenue * 3, 25, 10, false);
            // Revoke all licenses
            const kId = town.kingdomId;
            if (kId && player.licenses[kId]) player.licenses[kId] = [];
            recordCorruptAction('counterfeit', true);
            player.notoriety += 15;
            Engine.logEvent(`${player.fullName} was caught selling counterfeit goods in ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, jailed 10 days, all licenses revoked.` };
        }

        player.gold += revenue;
        player.stats.totalGoldEarned += revenue;
        player.notoriety += 15;
        recordCorruptAction('counterfeit', false);
        grantXP(15, 'Sold counterfeit goods');
        return { success: true, message: `✅ Sold ${qty} counterfeit ${res.name} for ${revenue}g!` };
    }

    // ── (f) Bribe Guards ──
    function bribeGuards(townId, amount) {
        amount = Number(amount);
        if (!amount || !isFinite(amount) || amount <= 0) return { success: false, message: 'Invalid bribe amount.' };
        amount = Math.floor(amount);
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (!isInTown(townId)) return { success: false, message: 'You must be in the town.' };
        const town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        const security = (town.security || 50);
        const minCost = Math.floor(50 + security * 4.5);
        if (!amount || amount < minCost) return { success: false, message: `Minimum bribe: ${minCost}g for this town's security level.` };
        if (amount > 500) amount = 500;
        if (player.gold < amount) return { success: false, message: 'Not enough gold.' };

        player.gold -= amount;
        const rng = Engine.getRng();
        let detection = calculateCorruptDetection(0.10, town);
        if (hasSkill('silver_tongue_dark')) detection *= 0.75;
        const caught = rng && rng.chance(detection);

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town.kingdomId) : null;
            const actualFine = applyCorruptPenalty(town, kingdom, amount * 2, 15, 0, false);
            recordCorruptAction('bribe_guards', true);
            player.notoriety += 3;
            Engine.logEvent(`${player.fullName} was caught trying to bribe guards in ${town.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, reputation -15.` };
        }

        player.bribedGuards[townId] = { expiresDay: Engine.getDay() + 30, reductionPct: 40 };
        player.notoriety += 3;
        recordCorruptAction('bribe_guards', false);
        grantXP(5, 'Bribed guards');
        Engine.logEvent(`Guards in ${town.name} have been bribed.`);
        return { success: true, message: `✅ Guards bribed! Detection -40% in ${town.name} for 30 days.` };
    }

    // ── (g) Bribe Royal Advisor ──
    function bribeAdvisor(kingdomId, voteDirection) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        const kingdom = Engine.findKingdom ? Engine.findKingdom(kingdomId) : null;
        if (!kingdom) return { success: false, message: 'Kingdom not found.' };
        if (!hasSkill('silver_tongue_dark')) {
            // Check relationship with advisor NPCs
            const towns = Engine.getTowns ? Engine.getTowns() : [];
            let hasAdvisorRel = false;
            for (const t of towns) {
                if (t.kingdomId !== kingdomId) continue;
                const people = Engine.getPeople ? Engine.getPeople(t.id) : [];
                for (const p of people) {
                    if (p.occupation === 'noble' || p.occupation === 'advisor') {
                        const rel = player.relationships[p.id];
                        if (rel && rel.level >= 30) { hasAdvisorRel = true; break; }
                    }
                }
                if (hasAdvisorRel) break;
            }
            if (!hasAdvisorRel) return { success: false, message: 'Need relationship >= 30 with an advisor, or Silver Tongue skill.' };
        }

        const prosperity = kingdom.prosperity || 50;
        const cost = Math.floor(500 + prosperity * 15);
        if (player.gold < cost) return { success: false, message: `Need ${cost}g to bribe advisor.` };

        player.gold -= cost;
        const town = Engine.findTown(player.townId);
        const rng = Engine.getRng();
        let detection = calculateCorruptDetection(0.20, town);
        if (hasSkill('silver_tongue_dark')) detection *= 0.75;
        if (hasSkill('kingmaker_skill')) detection *= 0.8;
        const caught = rng && rng.chance(detection);

        if (caught) {
            const actualFine = applyCorruptPenalty(town, kingdom, 2000, 30, 0, true);
            recordCorruptAction('bribe_advisor', true);
            player.notoriety += 12;
            Engine.logEvent(`${player.fullName} was caught bribing a royal advisor in ${kingdom.name}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Fined ${actualFine}g, exiled from ${kingdom.name}!` };
        }

        player.notoriety += 12;
        recordCorruptAction('bribe_advisor', false);
        grantXP(25, 'Bribed royal advisor');
        // Count kingdom bribes for Shadow Emperor achievement
        const kBribes = (player.crimesCommitted['bribe_advisor_' + kingdomId] || 0) + 1;
        player.crimesCommitted['bribe_advisor_' + kingdomId] = kBribes;
        if (kBribes >= 5) unlockAchievement('shadow_emperor');
        Engine.logEvent(`A royal advisor in ${kingdom.name} has been influenced.`);
        return { success: true, message: `✅ Advisor bribed! The next ${voteDirection || 'vote'} will go your way.` };
    }

    // ── (h) Cultivate the Heir ──
    function cultivateHeir(kingdomId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        const kingdom = Engine.findKingdom ? Engine.findKingdom(kingdomId) : null;
        if (!kingdom) return { success: false, message: 'Kingdom not found.' };
        // Check for luxury goods to gift
        const luxuryGoods = ['jewelry', 'wine', 'silk', 'pearls', 'gold_ore'];
        let giftValue = 0;
        let giftsUsed = {};
        for (const g of luxuryGoods) {
            const qty = player.inventory[g] || 0;
            if (qty > 0) {
                const res = findResource(g);
                const useQty = Math.min(qty, 5);
                giftValue += (res ? res.basePrice : 20) * useQty;
                giftsUsed[g] = useQty;
            }
        }
        if (giftValue < 100) return { success: false, message: 'Need at least 100g worth of luxury goods (jewelry, wine, silk, pearls, gold ore).' };

        // Consume gifts
        for (const [resId, qty] of Object.entries(giftsUsed)) {
            player.inventory[resId] = (player.inventory[resId] || 0) - qty;
        }

        // Increase favor
        const favorGain = Math.min(15, Math.floor(giftValue / 50));
        player.heirFavor[kingdomId] = Math.min(100, (player.heirFavor[kingdomId] || 0) + favorGain);
        grantXP(5, 'Cultivated heir');
        if (player.heirFavor[kingdomId] >= 80) unlockAchievement('master_puppeteer');
        Engine.logEvent(`${player.fullName} gifted luxury goods to the heir of ${kingdom.name}.`);
        return { success: true, message: `✅ Heir favor in ${kingdom.name}: ${player.heirFavor[kingdomId]}/100 (+${favorGain}).` };
    }

    // ── (i) Blackmail NPC ──
    function blackmailNPC(personId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        const person = Engine.findPerson ? Engine.findPerson(personId) : null;
        if (!person || !person.alive) return { success: false, message: 'Person not found or dead.' };
        if (player.blackmailTargets[personId]) return { success: false, message: 'Already blackmailing this person.' };

        const town = Engine.findTown(person.townId || player.townId);
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(0.25, town);
        const caught = rng && rng.chance(detection);

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town ? town.kingdomId : null) : null;
            applyCorruptPenalty(town, kingdom, 0, 20, 0, false);
            if (player.relationships[personId]) player.relationships[personId].level = 0;
            recordCorruptAction('blackmail', true);
            player.notoriety += 10;
            Engine.logEvent(`${player.fullName} was exposed trying to blackmail ${person.firstName}!`);
            return { success: false, caught: true, message: `🚨 CAUGHT! Reputation -20, relationship with ${person.firstName} destroyed.` };
        }

        const payment = rng ? rng.randInt(50, 200) : 100;
        player.blackmailTargets[personId] = { paymentPerSeason: payment, nextPayDay: Engine.getDay() + 90 };
        player.notoriety += 10;
        recordCorruptAction('blackmail', false);
        grantXP(15, 'Blackmailed NPC');
        Engine.logEvent(`${person.firstName} is now being blackmailed.`);
        return { success: true, message: `✅ Blackmailing ${person.firstName} for ${payment}g per season!` };
    }

    // ── (j) Spread Rumors ──
    function spreadRumors(targetMerchantId) {
        if (isJailed()) return { success: false, message: 'You are in jail.' };
        if (player.gold < 50) return { success: false, message: 'Need 50g to pay gossips.' };

        player.gold -= 50;
        const town = Engine.findTown(player.townId);
        const rng = Engine.getRng();
        const detection = calculateCorruptDetection(0.15, town);
        const caught = rng && rng.chance(detection);

        if (caught) {
            const kingdom = Engine.findKingdom ? Engine.findKingdom(town ? town.kingdomId : null) : null;
            applyCorruptPenalty(town, kingdom, 0, 10, 0, false);
            if (player.relationships[targetMerchantId]) player.relationships[targetMerchantId].level = 0;
            recordCorruptAction('spread_rumors', true);
            player.notoriety += 5;
            return { success: false, caught: true, message: '🚨 CAUGHT! Reputation -10. Target knows you spread rumors.' };
        }

        player.rumorTargets[targetMerchantId] = { expiresDay: Engine.getDay() + 60 };
        player.notoriety += 5;
        recordCorruptAction('spread_rumors', false);
        grantXP(8, 'Spread rumors');
        Engine.logEvent('Rumors are spreading about a merchant...');
        return { success: true, message: '✅ Rumors spread! Target reputation damaged for 60 days.' };
    }

