    function generateMasterTask() {
        if (!player.indentured || !player.indentured.active) return;
        if (player.indentured.currentTask) return; // Already have a task

        var rng = Engine.getRng();
        var day = Engine.getDay();
        var master = Engine.findPerson(player.indentured.masterId);
        if (!master || !master.alive) return;

        // Pick a task template — weight toward local tasks for newer servants
        var totalCompleted = (player.indentured.totalTasksCompleted || 0) + (player.indentured.totalTasksFailed || 0);
        var localTemplates = MASTER_TASK_TEMPLATES.filter(function(t) { return !t.needsTravel; });
        var travelTemplates = MASTER_TASK_TEMPLATES.filter(function(t) { return t.needsTravel; });
        var template;
        if (totalCompleted < 3) {
            // First 3 tasks: 90% local (learn the ropes)
            template = rng.random() < 0.9 ? rng.pick(localTemplates) : rng.pick(travelTemplates);
        } else if (totalCompleted < 8) {
            // Tasks 4-8: 60% local
            template = rng.random() < 0.6 ? rng.pick(localTemplates) : rng.pick(travelTemplates);
        } else {
            // After 8 tasks: 40% local, 60% travel (normal mix)
            template = rng.random() < 0.4 ? rng.pick(localTemplates) : rng.pick(travelTemplates);
        }

        // Generate task-specific details
        var details = template.generate(master, rng);

        // Pick a target town for travel tasks — prefer nearby towns
        var targetTownId = null;
        var targetTownName = '';
        if (template.needsTravel) {
            var towns = Engine.getTowns();
            var masterTown = Engine.findTown(master.townId);
            var otherTowns = towns.filter(function(t) { return t.id !== master.townId; });
            // Sort by distance from master's town (prefer nearby)
            if (masterTown) {
                otherTowns.sort(function(a, b) {
                    var da = Math.hypot(a.x - masterTown.x, a.y - masterTown.y);
                    var db = Math.hypot(b.x - masterTown.x, b.y - masterTown.y);
                    return da - db;
                });
            }
            // Pick from nearest 4 towns (weighted toward closest)
            var nearbyPool = otherTowns.slice(0, Math.min(4, otherTowns.length));
            if (nearbyPool.length > 0) {
                var targetTown = rng.pick(nearbyPool);
                targetTownId = targetTown.id;
                targetTownName = targetTown.name;
            }
        }

        // Calculate deadline based on travel distance using actual travel speed
        var travelDays = 0;
        if (targetTownId) {
            var route = Engine.findPath(master.townId, targetTownId);
            if (route && route.length > 0) {
                var totalDist = 0;
                for (var ri = 0; ri < route.length; ri++) {
                    totalDist += route[ri].distance || 100;
                }
                // Use actual player travel speed (CARAVAN_BASE_SPEED * 1.5)
                var actualSpeed = CONFIG.CARAVAN_BASE_SPEED * 1.5;
                travelDays = Math.ceil(totalDist / actualSpeed) * 2; // Round trip
            } else {
                travelDays = 6; // Default if no path found
            }
        }
        // Cap deadline: tasks should be completable in a reasonable timeframe
        var deadlineDays = template.baseDays + travelDays + rng.randInt(2, 5);
        deadlineDays = Math.min(deadlineDays, 45); // Never more than 45 days

        // Master personality affects rewards
        var personality = master.personality || {};
        var rewardMult = 1.0;
        if ((personality.warmth || 50) > 65) rewardMult += 0.2;
        if ((personality.greed || 50) > 65) rewardMult -= 0.15;
        if ((personality.honesty || 50) > 60) rewardMult += 0.1;

        // Build description string
        var desc = template.description;
        desc = desc.replace('{town}', targetTownName || 'the market');
        desc = desc.replace('{good}', details.good || 'supplies');
        desc = desc.replace('{qty}', details.qty || '');
        desc = desc.replace('{amount}', details.amount || '');
        desc = desc.replace('{npcName}', details.npcName || 'a contact');
        desc = desc.replace('{minPrice}', details.minPrice || '');
        desc = desc.replace('{goldProvided}', details.goldProvided || '0');

        var task = {
            id: 'task_' + day + '_' + Math.floor(Math.random() * 1000),
            type: template.id,
            name: template.icon + ' ' + template.name,
            description: desc,
            assignedDay: day,
            deadlineDay: day + deadlineDays,
            targetTownId: targetTownId,
            targetTownName: targetTownName,
            needsTravel: template.needsTravel,
            details: details,
            reward: {
                gold: Math.floor(template.baseReward.gold * rewardMult),
                debtReduction: Math.floor(template.baseReward.debtReduction * rewardMult),
                xp: template.baseReward.xp
            },
            completed: false,
            failed: false
        };

        player.indentured.currentTask = task;
        player.indentured.lastTaskDay = day;

        // If master provides gold for buy_goods tasks, give it to the player
        if (details.goldProvided && details.goldProvided > 0 && template.id === 'buy_goods') {
            player.gold += details.goldProvided;
            Engine.logEvent('💰 Your master gave you ' + details.goldProvided + 'g to buy supplies.');
        }

        // Next task in 12-25 days (ambitious masters give tasks more frequently)
        var ambition = (personality.ambition || 50);
        var interval = Math.max(8, 25 - Math.floor(ambition / 5));
        player.indentured.nextTaskDay = day + deadlineDays + rng.randInt(interval - 3, interval + 3);

        var taskMsg = '📋 Your master ' + master.firstName + ' assigned you a task: ' + desc + ' (Due in ' + deadlineDays + ' days)';
        if (template.needsTravel && targetTownName) {
            taskMsg += ' 🗺️ You have temporary freedom to travel to ' + targetTownName + '!';
        }
        Engine.logEvent(taskMsg);
    }

    function completeCurrentTask() {
        if (!player.indentured || !player.indentured.active) {
            return { success: false, message: 'You are not indentured.' };
        }
        if (!player.indentured.currentTask) {
            return { success: false, message: 'You have no active task.' };
        }

        var task = player.indentured.currentTask;
        var day = Engine.getDay();
        var master = Engine.findPerson(player.indentured.masterId);

        var canComplete = false;
        var failReason = '';

        // Check completion requirements
        switch (task.type) {
            case 'deliver_goods':
            case 'escort_caravan':
                // Must be in target town with goods OR must have visited target town
                if (task.needsTravel && task.targetTownId && player.townId !== task.targetTownId) {
                    failReason = 'You need to be in ' + task.targetTownName + ' to complete this task.';
                } else {
                    canComplete = true;
                }
                break;

            case 'sell_goods':
                if (task.needsTravel && task.targetTownId && player.townId !== task.targetTownId) {
                    failReason = 'You need to be in ' + task.targetTownName + ' to complete this task.';
                } else {
                    canComplete = true;
                }
                break;

            case 'buy_goods':
            case 'fetch_supplies':
                // Must have the goods in inventory
                var needed = task.details.qty || 1;
                var goodId = task.details.good || '';
                var has = player.inventory[goodId] || 0;
                if (has < needed) {
                    failReason = 'You need ' + needed + ' ' + goodId + ' in your inventory. You have ' + has + '.';
                } else {
                    canComplete = true;
                }
                break;

            case 'collect_debt':
                // Must be in target town OR have enough gold to represent collected debt
                if (task.needsTravel && task.targetTownId && player.townId !== task.targetTownId) {
                    failReason = 'You need to travel to ' + task.targetTownName + ' to collect the debt.';
                } else {
                    canComplete = true;
                }
                break;

            case 'deliver_message':
            case 'scout_prices':
            case 'negotiate_deal':
                // Must have visited the target town
                if (task.needsTravel && task.targetTownId && player.townId !== task.targetTownId) {
                    failReason = 'You need to travel to ' + task.targetTownName + ' first.';
                } else {
                    canComplete = true;
                }
                break;

            case 'guard_warehouse':
            case 'inventory_count':
            case 'clean_shop':
            case 'repair_equipment':
            case 'load_shipment':
                // Local tasks — just need to be in master's town
                if (master && player.townId !== master.townId) {
                    failReason = 'You need to be in your master\'s town to complete this task.';
                } else {
                    canComplete = true;
                }
                break;

            default:
                canComplete = true;
        }

        if (!canComplete) {
            return { success: false, message: failReason };
        }

        // Complete the task!
        task.completed = true;
        task.completedDay = day;

        // Give rewards
        var reward = task.reward;
        player.gold += reward.gold;
        player.indentured.debtRemaining = Math.max(0, player.indentured.debtRemaining - reward.debtReduction);
        grantXP(reward.xp, 'master task');

        // For buy tasks, transfer goods to master (remove from player inventory)
        if ((task.type === 'buy_goods' || task.type === 'fetch_supplies') && task.details.good) {
            var transferQty = Math.min(player.inventory[task.details.good] || 0, task.details.qty || 0);
            if (transferQty > 0) {
                player.inventory[task.details.good] = (player.inventory[task.details.good] || 0) - transferQty;
                if (player.inventory[task.details.good] <= 0) delete player.inventory[task.details.good];
            }
        }

        // Improve master relationship
        player.indentured.masterRelationship = Math.min(100, (player.indentured.masterRelationship || 50) + 3);
        player.indentured.consecutiveFailures = 0;
        player.indentured.totalTasksCompleted = (player.indentured.totalTasksCompleted || 0) + 1;

        // Track in history
        player.indentured.taskHistory.push({
            type: task.type,
            name: task.name,
            completedDay: day,
            result: 'completed'
        });

        // Bonus: completing many tasks gives bonus debt reduction
        if (player.indentured.totalTasksCompleted % 5 === 0) {
            var bonus = 10;
            player.indentured.debtRemaining = Math.max(0, player.indentured.debtRemaining - bonus);
            Engine.logEvent('⭐ Your master is pleased with your consistent work. Bonus debt reduction: ' + bonus + 'g!');
        }

        player.indentured.currentTask = null;

        var msg = '✅ Task completed! Earned ' + reward.gold + 'g, reduced debt by ' + reward.debtReduction + 'g.';
        Engine.logEvent(msg);
        return { success: true, message: msg };
    }

    function checkTaskDeadline() {
        if (!player.indentured || !player.indentured.active) return;
        if (!player.indentured.currentTask) return;

        var task = player.indentured.currentTask;
        var day = Engine.getDay();

        if (day > task.deadlineDay && !task.completed) {
            failCurrentTask();
        }
    }

    function failCurrentTask() {
        if (!player.indentured || !player.indentured.active) return;
        if (!player.indentured.currentTask) return;

        var task = player.indentured.currentTask;
        var day = Engine.getDay();
        var master = Engine.findPerson(player.indentured.masterId);
        var personality = master ? (master.personality || {}) : {};

        task.failed = true;
        task.failedDay = day;

        player.indentured.consecutiveFailures = (player.indentured.consecutiveFailures || 0) + 1;
        player.indentured.totalTasksFailed = (player.indentured.totalTasksFailed || 0) + 1;
        player.indentured.masterRelationship = Math.max(0, (player.indentured.masterRelationship || 50) - 8);

        var failures = player.indentured.consecutiveFailures;
        var isHarsh = (personality.warmth || 50) < 35 || (personality.greed || 50) > 70;
        var isViolent = (personality.honesty || 50) < 30 && (personality.risk_tolerance || 50) > 60;
        var isCruel = (personality.warmth || 50) < 25;

        // Track in history
        player.indentured.taskHistory.push({
            type: task.type,
            name: task.name,
            failedDay: day,
            result: 'failed'
        });

        // Escalating consequences
        if (failures === 1) {
            // Warning only — first offense is lenient
            player.indentured.contractDays += 7;
            Engine.logEvent('⚠️ Your master scolds you for failing your task. 7 days added as warning. (' + failures + ' failure)');
        } else if (failures === 2) {
            // Mild penalty + hunger
            player.indentured.contractDays += 20;
            if (player.hunger !== undefined) player.hunger = Math.max(0, player.hunger - 10);
            Engine.logEvent('😠 Your master is displeased. 20 days added, rations reduced. (' + failures + ' consecutive failures)');
        } else if (failures === 3) {
            // Moderate penalty
            player.indentured.contractDays += 60;
            Engine.logEvent('😡 Your master is angry! 60 days added to contract. (' + failures + ' consecutive failures)');
        } else if (failures === 4) {
            // Serious penalty + gold confiscation
            player.indentured.contractDays += 120;
            var confiscated = Math.min(player.gold, 50);
            if (confiscated > 0) {
                player.gold -= confiscated;
                if (master) master.gold = (master.gold || 0) + confiscated;
            }
            Engine.logEvent('🔥 ' + (master ? master.firstName : 'Your master') + ' confiscates ' + confiscated + 'g and adds 120 days! (' + failures + ' consecutive failures)');
        } else if (failures === 5) {
            // Beating (depends on personality) or severe punishment
            player.indentured.contractDays += 180;
            if (isViolent || isCruel) {
                player.injured = true;
                player.injuryDaysLeft = (player.injuryDaysLeft || 0) + 15;
                player.fatigue = Math.min(100, (player.fatigue || 0) + 30);
                Engine.logEvent('💀 Your master sent thugs to teach you a lesson! You\'re injured. (' + failures + ' consecutive failures)');
            } else {
                player.jailed = true;
                player.jailedUntilDay = day + 15;
                Engine.logEvent('🔒 Your master had you thrown in jail for 15 days! (' + failures + ' consecutive failures)');
            }
        } else if (failures === 6) {
            // Sold to harsher master OR severe beating
            if (isHarsh) {
                var people = Engine.getPeople();
                var newMasters = people.filter(function(p) {
                    return p.isEliteMerchant && p.alive && p.id !== player.indentured.masterId;
                });
                if (newMasters.length > 0) {
                    var newMaster = newMasters[Math.floor(Math.random() * newMasters.length)];
                    player.indentured.masterId = newMaster.id;
                    player.indentured.contractDays += 365; // 1 extra year (was 2)
                    player.indentured.masterRelationship = 20;
                    Engine.logEvent('⛓️ Your master sold your contract to ' + newMaster.firstName + ' ' + newMaster.lastName + '! 1 year added! (' + failures + ' consecutive failures)');
                } else {
                    player.indentured.contractDays += 365;
                    Engine.logEvent('⛓️ Your master extended your contract by 1 year! (' + failures + ' consecutive failures)');
                }
            } else {
                player.indentured.contractDays += 270;
                player.injured = true;
                player.injuryDaysLeft = (player.injuryDaysLeft || 0) + 10;
                Engine.logEvent('💀 Your master had you beaten and added 9 months to your contract! (' + failures + ' consecutive failures)');
            }
        } else if (failures >= 7) {
            // Execution risk (depends on personality)
            if (isCruel && isViolent) {
                var combatSkill = player.skills && player.skills.combat_trained ? 1 : 0;
                var escapeChance = 0.3 + combatSkill * 0.25;
                if (Math.random() < escapeChance) {
                    player.indentured.active = false;
                    player.notoriety = (player.notoriety || 0) + 15;
                    player.injured = true;
                    player.injuryDaysLeft = (player.injuryDaysLeft || 0) + 10;
                    var towns = Engine.getTowns();
                    var farTowns = towns.filter(function(t) { return t.id !== player.townId; });
                    if (farTowns.length > 0) {
                        player.townId = farTowns[Math.floor(Math.random() * farTowns.length)].id;
                    }
                    Engine.logEvent('☠️ Your master ordered your execution, but you escaped! You are injured and on the run — but free! (' + failures + ' consecutive failures)');
                    grantXP(40, 'survived execution');
                } else if (!window._godInvincible) {
                    player.alive = false;
                    Engine.logEvent('☠️ Your master had you executed for persistent defiance. Game Over. (' + failures + ' consecutive failures)');
                }
            } else if (isHarsh) {
                player.jailed = true;
                player.jailedUntilDay = day + 60;
                player.indentured.contractDays += 540; // 1.5 years (was 3)
                Engine.logEvent('🔒 Your master turned you over to the authorities! 60 days jail + 1.5 years added! (' + failures + ' consecutive failures)');
            } else {
                player.indentured.contractDays += 365;
                player.indentured.masterRelationship = 0;
                var confiscated2 = Math.floor(player.gold * 0.5);
                if (confiscated2 > 0) player.gold -= confiscated2;
                Engine.logEvent('😤 Your master has lost all patience. 1 year added, half your gold confiscated. (' + failures + ' consecutive failures)');
            }
            // Reset consecutive count to avoid infinite escalation beyond 7
            // but keep it high so next failure is still severe
            player.indentured.consecutiveFailures = 5;
        }

        player.indentured.currentTask = null;
    }

    function dismissCurrentTask() {
        // Explicitly dismiss/ignore a task (same as failing)
        if (!player.indentured || !player.indentured.currentTask) {
            return { success: false, message: 'No active task to dismiss.' };
        }
        failCurrentTask();
        return { success: true, message: 'Task dismissed. Your master will not be pleased.' };
    }

    function makeDebtPayment(amount) {
        amount = Number(amount);
        if (!amount || !isFinite(amount) || amount <= 0) {
            return { success: false, message: 'Enter an amount to pay.' };
        }
        amount = Math.floor(amount);
        if (!player.indentured || !player.indentured.active) {
            return { success: false, message: 'You are not indentured.' };
        }
        if (player.gold < amount) {
            return { success: false, message: 'You only have ' + Math.floor(player.gold) + 'g.' };
        }
        var debt = player.indentured.debtRemaining;
        if (debt <= 0) {
            return { success: false, message: 'Your debt is already paid off!' };
        }
        // Cap payment at remaining debt
        var payment = Math.min(amount, debt);
        player.gold -= payment;
        player.indentured.debtRemaining -= payment;
        var master = Engine.findPerson(player.indentured.masterId);
        if (master) master.gold = (master.gold || 0) + payment;
        // Improve relationship slightly for voluntary payments
        player.indentured.masterRelationship = Math.min(100, (player.indentured.masterRelationship || 50) + 1);

        if (player.indentured.debtRemaining <= 0) {
            Engine.logEvent('💰 You paid the last ' + payment + 'g of your debt! Speak to your master about freedom.');
        } else {
            Engine.logEvent('💰 You paid ' + payment + 'g toward your debt. Remaining: ' + player.indentured.debtRemaining + 'g');
        }
        return { success: true, message: 'Paid ' + payment + 'g. Debt remaining: ' + player.indentured.debtRemaining + 'g' };
    }

    function freeFromIndenture(message) {
        player.indentured.active = false;
        Engine.logEvent(message || (player.fullName + ' has been freed from indenture!'));
        grantXP(50, 'freedom');
    }

    // ========================================================
    // §13B  CONQUEST SERVITUDE (player)
    // ========================================================

    function tickConquestServitude() {
        if (!player.conquestServitude || !player.conquestServitude.active) return;

        var day = Engine.getDay();

        // Auto-free after servitude period ends
        if (day >= player.conquestServitude.servitudeEndDay) {
            freeFromConquestServitude('Your period of servitude has ended. You are a free citizen!');
            return;
        }
    }

    function freeFromConquestServitude(message) {
        player.conquestServitude.active = false;
        Engine.logEvent(message || (player.fullName + ' has been freed from conquest servitude!'));
        grantXP(50, 'freedom');
    }

    function buyFreedom() {
        if (!player.conquestServitude || !player.conquestServitude.active) {
            return { success: false, message: 'You are not indentured.' };
        }
        var cost = player.conquestServitude.freedomCost || CONFIG.SERVITUDE_FREEDOM_COST;
        if (player.gold < cost) {
            return { success: false, message: 'You need ' + cost + 'g to buy your freedom. You have ' + Math.floor(player.gold) + 'g.' };
        }

        player.gold -= cost;
        // Pay the kingdom
        var kingdom = Engine.findKingdom(player.conquestServitude.kingdomId);
        if (kingdom) kingdom.gold += cost;

        freeFromConquestServitude(player.fullName + ' has purchased their freedom for ' + cost + ' gold!');
        return { success: true, message: 'You have bought your freedom for ' + cost + 'g!' };
    }

    function tickPilgrim() {
        var day = Engine.getDay();
        // Followers give tithe monthly
        if (day % 30 === 0 && player.pilgrim.followers > 0) {
            var tithe = player.pilgrim.followers;
            player.gold += tithe;
            player.stats.totalGoldEarned += tithe;
        }

        // Rival faith grows
        if (!player.pilgrim.rivalDefeated && player.pilgrim.rivalFaith) {
            var rival = player.pilgrim.rivalFaith;
            if (day % 15 === 0) {
                // Rival gains followers
                rival.followers += Math.floor(Math.random() * 3) + 1;
                rival.strength = Math.min(100, rival.strength + 1);
                
                // Rival steals your followers if in the same town
                if (rival.townId === player.townId && player.pilgrim.followers > 0) {
                    var stolen = Math.min(player.pilgrim.followers, Math.floor(Math.random() * 2) + 1);
                    player.pilgrim.followers -= stolen;
                    rival.followers += stolen;
                    Engine.logEvent('⚡ ' + rival.preacherName + ' of ' + rival.name + ' has converted ' + stolen + ' of your followers!');
                }
                
                // Rival moves to a new town every 45 days
                if (day % 45 === 0) {
                    var towns = Engine.getTowns();
                    var moveTowns = towns.filter(function(t) { return t.id !== rival.townId; });
                    if (moveTowns.length > 0) {
                        rival.townId = moveTowns[Math.floor(Math.random() * moveTowns.length)].id;
                    }
                }
            }
            
            // If rival gets too strong, they take over holy sites you haven't visited
            if (rival.strength >= 60 && day % 60 === 0) {
                var unvisitedSites = player.pilgrim.holySites.filter(function(sId) {
                    return player.pilgrim.visitedSites.indexOf(sId) === -1;
                });
                if (unvisitedSites.length > 0) {
                    var contestedSite = unvisitedSites[Math.floor(Math.random() * unvisitedSites.length)];
                    var contestedTown = Engine.findTown(contestedSite);
                    if (contestedTown) {
                        Engine.logEvent('⚠️ ' + rival.name + ' is claiming the holy site in ' + contestedTown.name + '! Visit it before they desecrate it!');
                    }
                }
            }
        }

        // Check goal completion
        checkPilgrimGoals();
    }

    function checkPilgrimGoals(){
        var p = player.pilgrim;
        var completed = 0;
        for (var gi = 0; gi < p.goals.length; gi++) {
            var g = p.goals[gi];
            if (g === 'visit_all_sites' && p.visitedSites.length >= p.holySites.length) completed++;
            else if (g === 'convert_50_followers' && p.followers >= 50) completed++;
            else if (g === 'build_temple' && p.templeBuilt) completed++;
        }
        p.goalsCompleted = completed;

        if (completed >= 2 && p.active) {
            p.active = false;
            player.skills.divine_favor = true;
            player.skills.blessed_merchant = true;
            player.skills.prophets_tongue = true;
            Engine.logEvent(player.fullName + ' has completed their holy pilgrimage! Divine powers unlocked.');
            grantXP(100, 'pilgrimage complete');
        }
    }

    function tickShipwrecked() {
        var day = Engine.getDay();
        
        // Language growth from daily interactions
        if (day % 5 === 0 && player.shipwrecked.languageSkill < 100) {
            player.shipwrecked.languageSkill = Math.min(100, player.shipwrecked.languageSkill + 1);
        }
        
        // Artifact pulses when near a resonance site (same town)
        if (player.shipwrecked.artifactKept && player.shipwrecked.resonanceSites) {
            var pulsing = false;
            for (var si = 0; si < player.shipwrecked.resonanceSites.length; si++) {
                var site = player.shipwrecked.resonanceSites[si];
                if (!site.visited && site.townId === player.townId) {
                    pulsing = true;
                    break;
                }
            }
            player.shipwrecked.artifactPulsing = pulsing;
        }
        
        // Check final choice availability
        if (player.shipwrecked.active && !player.shipwrecked.finalChoiceAvailable) {
            if (player.shipwrecked.languageSkill >= 100 && player.shipwrecked.resonanceSitesVisited >= 5) {
                player.shipwrecked.finalChoiceAvailable = true;
                Engine.logEvent('🌟 The artifact thrums with power. All sea chart fragments assembled. ' + player.fullName + ' must now choose: OPEN the artifact or SEAL its power within.');
            }
        }
        
        // Embassy tick (if opened)
        if (player.shipwrecked.embassy && player.shipwrecked.finalChoice === 'open') {
            var emb = player.shipwrecked.embassy;
            // Generate 10 potions per day
            if (day % 1 === 0) {
                emb.potionStockRed = Math.min(50, (emb.potionStockRed || 0) + 3);
                emb.potionStockGreen = Math.min(50, (emb.potionStockGreen || 0) + 3);
                emb.potionStockBlue = Math.min(50, (emb.potionStockBlue || 0) + 4);
                player.shipwrecked.embassyPotionsGenerated += 10;
            }
            // Embassy sells potions daily (auto-sell from stock)
            if (day % 3 === 0) {
                var rng = Engine.getRng();
                var potionTypes = ['red', 'green', 'blue'];
                for (var pi = 0; pi < potionTypes.length; pi++) {
                    var stockKey = 'potionStock' + potionTypes[pi].charAt(0).toUpperCase() + potionTypes[pi].slice(1);
                    var stock = emb[stockKey] || 0;
                    if (stock > 0) {
                        var sold = Math.min(stock, rng.randInt(1, 3));
                        var basePrice = 500;
                        // Dynamic pricing: +/- 20%
                        var price = Math.floor(basePrice * (0.8 + rng.random() * 0.4));
                        var income = sold * price;
                        player.shipwrecked.embassyBankAccount += income;
                        emb[stockKey] -= sold;
                    }
                }
            }
            // Embassy buys from local market (items sent to homeland = deleted)
            if (day % 7 === 0 && player.shipwrecked.embassyBankAccount > 100) {
                var embTown = Engine.findTown(emb.townId);
                if (embTown && embTown.market) {
                    var marketKeys = Object.keys(embTown.market);
                    if (marketKeys.length > 0) {
                        var rng2 = Engine.getRng();
                        var buyRes = rng2.pick(marketKeys);
                        var mEntry = embTown.market[buyRes];
                        var mPrice = typeof mEntry === 'object' ? (mEntry.price || 10) : (mEntry || 10);
                        var buyQty = Math.min(5, Math.floor(player.shipwrecked.embassyBankAccount / mPrice));
                        if (buyQty > 0) {
                            var cost = buyQty * mPrice;
                            player.shipwrecked.embassyBankAccount -= cost;
                            // Items are "sent to homeland" — removed from market supply
                            if (typeof mEntry === 'object' && mEntry.supply !== undefined) {
                                mEntry.supply = Math.max(0, mEntry.supply - buyQty);
                            }
                        }
                    }
                }
            }
        }
        
        // Seal bonuses tick
        if (player.shipwrecked.sealBonuses && player.shipwrecked.finalChoice === 'seal') {
            // +25% relationship/reputation gains are applied in the gain functions
            // Disease/injury reduction applied in inflict functions
            // Speed bonus applied in travel functions
            // These are checked via player.shipwrecked.sealBonuses existing
        }
        
        // Integration completion (old behavior kept for backward compat, but now also triggers with resonance)
        if (player.shipwrecked.languageSkill >= 100 && player.shipwrecked.active && player.shipwrecked.finalChoice) {
            player.shipwrecked.active = false;
            player.skills.world_traveler = true;
            player.skills.diplomatic_immunity = true;
            player.skills.exotic_knowledge = true;
            Engine.logEvent(player.fullName + ' has fully integrated into society! Unique abilities unlocked.');
            grantXP(80, 'full integration');
        }
    }

    function tickMusician() {
        var day = Engine.getDay();
        // Passive fame spread from fans
        var kingdoms = Engine.getKingdoms();
        for (var ki = 0; ki < kingdoms.length; ki++) {
            var kId = kingdoms[ki].id;
            var fansInKingdom = 0;
            for (var fId in player.musician.fans) {
                if (player.musician.fans[fId]) {
                    var fanPerson = Engine.findPerson(fId);
                    if (fanPerson && fanPerson.alive) {
                        var fanTown = Engine.findTown(fanPerson.townId);
                        if (fanTown && fanTown.kingdomId === kId) fansInKingdom++;
                    }
                }
            }
            if (fansInKingdom > 0) {
                player.musician.fame[kId] = Math.min(100, (player.musician.fame[kId] || 0) + fansInKingdom * 0.1);
            }
        }

        // Fan gifts monthly
        if (day % 30 === 0) {
            var totalFans = Object.keys(player.musician.fans).length;
            if (totalFans > 0) {
                player.gold += totalFans;
                player.stats.totalGoldEarned += totalFans;
            }
        }

        // Rival musicians grow and move
        if (player.musician.rivals && day % 20 === 0) {
            for (var ri2 = 0; ri2 < player.musician.rivals.length; ri2++) {
                var rival = player.musician.rivals[ri2];
                if (rival.defeated) continue;
                rival.skill = Math.min(95, rival.skill + 1);
                rival.fans += Math.floor(Math.random() * 3) + 1;
                // Move to random town every 60 days
                if (day % 60 === 0) {
                    var allTowns = Engine.getTowns();
                    rival.townId = allTowns[Math.floor(Math.random() * allTowns.length)].id;
                }
                // Rival steals fans if in same town
                if (rival.townId === player.townId) {
                    var stolenFans = 0;
                    var tPeople = Engine.getPeople(player.townId);
                    for (var sf = 0; sf < tPeople.length && stolenFans < 2; sf++) {
                        if (player.musician.fans[tPeople[sf].id] && Math.random() < 0.1) {
                            delete player.musician.fans[tPeople[sf].id];
                            stolenFans++;
                        }
                    }
                    if (stolenFans > 0) {
                        rival.fans += stolenFans;
                        Engine.logEvent('🎵 ' + rival.name + ' performed in your town and stole ' + stolenFans + ' of your fans!');
                    }
                }
            }
        }

        // Music school passive income
        if (player.musician.legacyChoice === 'music_school' && player.musician.musicSchoolTownId && day % 7 === 0) {
            var schoolIncome = 30 + Object.keys(player.musician.fans).length;
            schoolIncome = Math.min(150, schoolIncome);
            player.gold += schoolIncome;
            player.stats.totalGoldEarned += schoolIncome;
            player.musician.musicSchoolIncome = (player.musician.musicSchoolIncome || 0) + schoolIncome;
        }

        // Legendary bard income boost (applied in performance functions via skill check)
        // Legendary bards: fame doesn't decay

        // Check fame milestone — offer legacy choice at 80+ fame
        if (player.musician.active && !player.musician.legacyChoice) {
            for (var mk = 0; mk < kingdoms.length; mk++) {
                if ((player.musician.fame[kingdoms[mk].id] || 0) >= 80) {
                    player.musician.legacyOffered = true;
                    Engine.logEvent('🌟 ' + player.fullName + ' has reached legendary fame in ' + kingdoms[mk].name + '! A choice awaits: retire and build a Music School, or continue as a Legendary Bard.');
                    break;
                }
            }
        }
    }

    function tickMilitaryLeader() {
        var ml = player.militaryLeader;
        var day = Engine.getDay();

        // Check for General retirement (held for 360 days)
        if (ml.rank === 'general' && ml.generalSinceDay > 0) {
            if (day - ml.generalSinceDay >= 360 && ml.active) {
                ml.active = false;
                player.skills.hero_of_ages = true;
                player.skills.legendary_commander = true;
                player.skills.battle_scarred = true;
                player.skills.war_council = true;
                // Permanent rep boost
                var kingdoms = Engine.getKingdoms();
                for (var ki = 0; ki < kingdoms.length; ki++) {
                    player.reputation[kingdoms[ki].id] = Math.min(100, (player.reputation[kingdoms[ki].id] || 50) + 50);
                }
                Engine.logEvent(player.fullName + ' retires as Hero of Ages! Legendary status achieved.');
                grantXP(200, 'hero of ages');
            }
        }

        // Update war council access based on rank
        var milRanks = CONFIG.MILITARY_LEADER_RANKS || [];
        var milRankIdx = milRanks.findIndex(function(r) { return r.id === player.militaryLeader.rank; });
        player.militaryLeader.warCouncilAccess = milRankIdx >= 4; // captain+
        
        // Check decisive battle availability
        if (milRankIdx >= 5 && (player.militaryLeader.victoriesAsLeader || 0) >= 10) {
            if (!player.militaryLeader.decisiveBattleAvailable) {
                player.militaryLeader.decisiveBattleAvailable = true;
                Engine.logEvent('⚔️ ' + player.fullName + ' is now eligible for the DECISIVE BATTLE — the path to becoming Hero of the Ages!');
            }
        }
    }

    function tickScholar() {
        var day = Engine.getDay();
        var s = player.scholar;

        // Knowledge fades if not written
        if (day % 30 === 0 && s.totalKnowledge > 0 && (day - (s.lastWriteDay || 0)) > 30) {
            s.totalKnowledge = Math.max(0, s.totalKnowledge - 1);
        }

        // Royalties from Great Book
        if (s.royaltiesActive && s.greatBookWritten && day % 7 === 0) {
            // Check if current player is the author (royalties end on death/inheritance)
            var currentId = player.firstName + '_' + player.lastName;
            if (currentId !== s.royaltiesPlayerId) {
                s.royaltiesActive = false;
                Engine.logEvent('📖 The royalties from the Great Book have ended with the passing of its author.');
            } else {
                // Weekly royalties: base 20g + 5g per specialization knowledge (capped at 100g/week)
                var baseRoyalty = 20;
                var specBonus = Math.floor((s.specializationKnowledge || 0) / 10);
                var royalty = Math.min(100, baseRoyalty + specBonus);
                player.gold += royalty;
                player.stats.totalGoldEarned += royalty;
                s.totalRoyaltiesEarned = (s.totalRoyaltiesEarned || 0) + royalty;

                // Monthly reputation boost across all kingdoms
                if (day % 30 === 0) {
                    var kingdoms = Engine.getKingdoms();
                    for (var ki = 0; ki < kingdoms.length; ki++) {
                        player.reputation[kingdoms[ki].id] = Math.min(100, (player.reputation[kingdoms[ki].id] || 50) + 3);
                    }
                }
            }
        }
    }

    // ── Special Start Actions ──

    // Pilgrim actions
    function giveSermon(townId) {
        if (!player.pilgrim || !player.pilgrim.active) return { success: false, message: 'You are not on a pilgrimage.' };
        var rng = Engine.getRng();
        // Sermon quality scales with experience
        var sermonSkill = Math.min(100, player.pilgrim.sermonsGiven * 2);  // 0-100 based on practice
        var minConverts = sermonSkill >= 80 ? 3 : (sermonSkill >= 40 ? 2 : 1);
        var maxConverts = sermonSkill >= 80 ? 8 : (sermonSkill >= 40 ? 5 : 3);
        var converts = rng.randInt(minConverts, maxConverts);
        var minDonations = sermonSkill >= 60 ? 8 : (sermonSkill >= 30 ? 4 : 2);
        var maxDonations = sermonSkill >= 60 ? 25 : (sermonSkill >= 30 ? 15 : 10);
        var donations = rng.randInt(minDonations, maxDonations);
        player.pilgrim.sermonsGiven++;
        player.pilgrim.followers += converts;
        player.gold += donations;
        player.stats.totalGoldEarned += donations;
        player.pilgrim.donations += donations;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.give_sermon || 5);
        var sermonQuality = sermonSkill >= 80 ? 'powerful' : (sermonSkill >= 40 ? 'compelling' : 'modest');
        Engine.logEvent(player.fullName + ' gave a ' + sermonQuality + ' sermon. ' + converts + ' new followers! ' + donations + 'g in donations.');
        grantXP(3, 'sermon');
        return { success: true, message: sermonQuality.charAt(0).toUpperCase() + sermonQuality.slice(1) + ' sermon! ' + converts + ' converts, ' + donations + 'g donations. (Skill: ' + sermonSkill + '%)' };
    }

    function visitHolySite(townId) {
        if (!player.pilgrim || !player.pilgrim.active) return { success: false, message: 'You are not on a pilgrimage.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        var town = Engine.findTown(townId);
        if (!town || !town.holySite) return { success: false, message: 'This town has no holy site.' };
        if (player.pilgrim.visitedSites.indexOf(townId) !== -1) return { success: false, message: 'Already visited this holy site.' };
        player.pilgrim.visitedSites.push(townId);
        var rng = Engine.getRng();
        if (town.kingdomId) {
            player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + 5);
        }
        // Holy site unique event
        var siteIndex = player.pilgrim.visitedSites.length; // Which site number is this
        var eventRoll = rng.random();
        var eventMsg = '';
        if (eventRoll < 0.25) {
            // Test of faith — donate gold for bonus followers
            var donationCost = 50 + siteIndex * 20;
            if (player.gold >= donationCost) {
                player.gold -= donationCost;
                player.stats.totalGoldSpent += donationCost;
                var bonusFollowers = rng.randInt(3, 8);
                player.pilgrim.followers += bonusFollowers;
                eventMsg = ' 🙏 Test of Faith: You donated ' + donationCost + 'g to the shrine and gained ' + bonusFollowers + ' devoted followers!';
            } else {
                eventMsg = ' 🙏 The shrine asked for a ' + donationCost + 'g donation, but you couldn\'t afford it.';
            }
        } else if (eventRoll < 0.5) {
            // Vision — bonus XP and knowledge (if scholar too)
            grantXP(15, 'holy vision');
            eventMsg = ' ✨ Vision: You experienced a divine vision! The path ahead is clearer. +15 XP.';
            if (town.kingdomId) {
                player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + 5);
                eventMsg += ' +5 rep.';
            }
        } else if (eventRoll < 0.7) {
            // Ancient relic — permanent bonus
            var relicGold = rng.randInt(20, 60);
            player.gold += relicGold;
            player.stats.totalGoldEarned += relicGold;
            eventMsg = ' 🏺 Ancient Relic: You discovered a sacred relic worth ' + relicGold + 'g!';
        } else if (eventRoll < 0.85) {
            // Challenge — bandits at the site
            var lostGold = Math.min(player.gold, rng.randInt(10, 30));
            player.gold -= lostGold;
            player.pilgrim.followers += 2; // Sympathy followers
            eventMsg = ' ⚔️ Bandits! Robbed of ' + lostGold + 'g at the site, but 2 locals join you in sympathy.';
        } else {
            // Miracle — big follower boost
            var miracleFollowers = rng.randInt(5, 12);
            player.pilgrim.followers += miracleFollowers;
            eventMsg = ' ⭐ Miracle! A sign appeared at the shrine — ' + miracleFollowers + ' people witnessed it and joined your faith!';
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.visit_holy_site || 10);
        Engine.logEvent(player.fullName + ' visited the holy site in ' + town.name + '.');
        grantXP(20, 'holy site');
        checkPilgrimGoals();
        return { success: true, message: 'Holy site visited! +20 XP, +5 rep. Sites: ' + player.pilgrim.visitedSites.length + '/' + player.pilgrim.holySites.length + eventMsg };
    }

    function convertNPC(npcId) {
        if (!player.pilgrim || !player.pilgrim.active) return { success: false, message: 'You are not on a pilgrimage.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Person not found.' };
        if (person.townId !== player.townId) return { success: false, message: 'Not in the same town.' };
        if (player.pilgrim.followerNpcs[npcId]) return { success: false, message: 'Already a follower.' };
        var rng = Engine.getRng();
        var rel = (player.relationships[npcId] && player.relationships[npcId].level) || 0;
        var warmth = (person.personality && person.personality.warmth) || 50;
        var chance = (rel + warmth) / 300;
        player.pilgrim.conversionAttempts++;
        if (rng.random() < chance) {
            player.pilgrim.followers++;
            player.pilgrim.followerNpcs[npcId] = true;
            if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.convert_npc || 3);
            grantXP(5, 'convert');
            checkPilgrimGoals();
            return { success: true, message: person.firstName + ' has been converted! Total followers: ' + player.pilgrim.followers };
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.convert_npc || 3);
        return { success: false, message: person.firstName + ' was not convinced.' };
    }

    function blessNPC(npcId) {
        if (!player.pilgrim || !player.pilgrim.active) return { success: false, message: 'You are not on a pilgrimage.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Person not found.' };
        player.relationships[npcId] = player.relationships[npcId] || { level: 0, type: 'acquaintance' };
        player.relationships[npcId].level = Math.min(100, player.relationships[npcId].level + 10);
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.bless_npc || 2);
        return { success: true, message: 'You blessed ' + person.firstName + '. +10 relationship.' };
    }

    function buildTemple(townId) {
        if (!player.pilgrim || !player.pilgrim.active) return { success: false, message: 'You are not on a pilgrimage.' };
        if (player.pilgrim.templeBuilt) return { success: false, message: 'You have already built a temple.' };
        var tid = townId || player.townId;
        var town = Engine.findTown(tid);
        if (!town) return { success: false, message: 'Town not found.' };
        if (player.townId !== tid) return { success: false, message: 'You must be in this town.' };
        var cost = 500;
        if (player.gold < cost) return { success: false, message: 'You need ' + cost + 'g to build a temple.' };
        if (player.pilgrim.followers < 20) return { success: false, message: 'You need at least 20 followers to build a temple.' };
        player.gold -= cost;
        player.stats.totalGoldSpent += cost;
        player.pilgrim.templeBuilt = true;
        player.pilgrim.templeTownId = tid;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.build_temple || 30);
        Engine.logEvent(player.fullName + ' built a temple in ' + town.name + '!');
        grantXP(50, 'build temple');
        checkPilgrimGoals();
        return { success: true, message: 'Temple built in ' + town.name + '! 🏛️' };
    }

    function challengeRivalFaith() {
        if (!player.pilgrim || !player.pilgrim.active) return { success: false, message: 'Not on a pilgrimage.' };
        if (player.pilgrim.rivalDefeated) return { success: false, message: 'The rival faith has already been defeated.' };
        var rival = player.pilgrim.rivalFaith;
        if (!rival || rival.townId !== player.townId) {
            var rivalTown = rival ? Engine.findTown(rival.townId) : null;
            return { success: false, message: 'The rival preacher is not in this town.' + (rivalTown ? ' They were last seen in ' + rivalTown.name + '.' : '') };
        }
        
        // Theological debate! Player strength based on followers, sermons given, and reputation
        var playerStr = player.pilgrim.followers * 2 + player.pilgrim.sermonsGiven * 3;
        var town = Engine.findTown(player.townId);
        if (town && town.kingdomId) playerStr += (player.reputation[town.kingdomId] || 0);
        var rivalStr = rival.followers * 2 + rival.strength;
        
        var rng = Engine.getRng();
        // Add some randomness
        playerStr += rng.randInt(0, 30);
        rivalStr += rng.randInt(0, 30);
        
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.challenge_rival || 10);
        
        if (playerStr > rivalStr) {
            // Victory — steal their followers, weaken them
            var stolenBack = Math.floor(rival.followers * 0.5);
            player.pilgrim.followers += stolenBack;
            rival.followers = Math.max(0, rival.followers - stolenBack);
            rival.strength = Math.max(0, rival.strength - 25);
            
            if (rival.strength <= 0) {
                player.pilgrim.rivalDefeated = true;
                Engine.logEvent('🏆 ' + player.fullName + ' has defeated ' + rival.preacherName + ' in a great theological debate! ' + rival.name + ' disbands!');
                grantXP(50, 'defeated rival faith');
                return { success: true, message: 'You defeated ' + rival.preacherName + '! Their followers (' + stolenBack + ') join your cause. ' + rival.name + ' is no more!' };
            }
            
            Engine.logEvent('⚡ ' + player.fullName + ' won a theological debate against ' + rival.preacherName + '! Gained ' + stolenBack + ' followers.');
            grantXP(20, 'won debate');
            return { success: true, message: 'You won the debate! Gained ' + stolenBack + ' followers. Rival weakened to ' + rival.strength + ' strength.' };
        } else {
            // Loss — lose some followers
            var lost = Math.min(player.pilgrim.followers, Math.floor(Math.random() * 5) + 2);
            player.pilgrim.followers = Math.max(0, player.pilgrim.followers - lost);
            rival.strength = Math.min(100, rival.strength + 10);
            Engine.logEvent('😔 ' + rival.preacherName + ' bested ' + player.fullName + ' in debate. Lost ' + lost + ' followers.');
            return { success: false, message: 'You lost the debate. -' + lost + ' followers. The rival grows stronger.' };
        }
    }

    // Shipwrecked actions
    function tellExoticStory(townId) {
        if (!player.shipwrecked) return { success: false, message: 'Not available.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        var rng = Engine.getRng();
        var gold = rng.randInt(5, 15);
        player.gold += gold;
        player.stats.totalGoldEarned += gold;
        player.shipwrecked.storiesTold++;
        player.shipwrecked.languageSkill = Math.min(100, player.shipwrecked.languageSkill + 2);
        var town = Engine.findTown(townId);
        if (town && town.kingdomId) {
            player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + 3);
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.tell_exotic_story || 3);
        grantXP(3, 'story');
        return { success: true, message: 'You told an exotic story! Earned ' + gold + 'g. Language +2.' };
    }

    function teachForeignCraft() {
        if (!player.shipwrecked) return { success: false, message: 'Not available.' };
        var recipes = ['exotic_spice_blend', 'foreign_medicine', 'ornate_jewelry'];
        var newRecipes = recipes.filter(function(r) { return player.shipwrecked.exoticRecipes.indexOf(r) === -1; });
        if (newRecipes.length === 0) return { success: false, message: 'No more recipes to teach.' };
        var recipe = newRecipes[0];
        player.shipwrecked.exoticRecipes.push(recipe);
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.teach_foreign_craft || 10);
        grantXP(10, 'foreign craft');
        return { success: true, message: 'You taught the technique for ' + recipe.replace(/_/g, ' ') + '!' };
    }

    function sellExoticArtifact() {
        if (!player.shipwrecked || !player.shipwrecked.artifactKept) return { success: false, message: 'No artifact to sell.' };
        if (!player.inventory.exotic_artifact || player.inventory.exotic_artifact < 1) return { success: false, message: 'No artifact.' };
        player.inventory.exotic_artifact = 0;
        player.gold += 800;
        player.stats.totalGoldEarned += 800;
        player.shipwrecked.artifactKept = false;
        return { success: true, message: 'Sold the exotic artifact for 800g. The luck bonus is gone forever.' };
    }

    function visitResonanceSite() {
        if (!player.shipwrecked || !player.shipwrecked.artifactKept) return { success: false, message: 'You need the artifact.' };
        if (!player.shipwrecked.resonanceSites) return { success: false, message: 'No resonance sites.' };
        var site = null;
        for (var i = 0; i < player.shipwrecked.resonanceSites.length; i++) {
            if (!player.shipwrecked.resonanceSites[i].visited && player.shipwrecked.resonanceSites[i].townId === player.townId) {
                site = player.shipwrecked.resonanceSites[i];
                break;
            }
        }
        if (!site) return { success: false, message: 'No resonance site here. The artifact is quiet.' };
        
        site.visited = true;
        player.shipwrecked.resonanceSitesVisited++;
        player.shipwrecked.seaChartFragments++;
        player.shipwrecked.languageSkill = Math.min(100, player.shipwrecked.languageSkill + 10);
        
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.visit_resonance || 20);
        grantXP(25, 'resonance site');
        Engine.logEvent('✨ ' + player.fullName + ' discovered ' + site.name + '! Vision: "' + site.vision + '"');
        
        var remaining = 5 - player.shipwrecked.resonanceSitesVisited;
        return { success: true, message: '✨ ' + site.name + '! Vision: "' + site.vision + '" Sea chart fragment ' + player.shipwrecked.seaChartFragments + '/5.' + (remaining > 0 ? ' ' + remaining + ' sites remain.' : ' All fragments collected!') };
    }
    
    function openArtifact(embassyTownId) {
        if (!player.shipwrecked) return { success: false, message: 'Not shipwrecked start.' };
        if (!player.shipwrecked.finalChoiceAvailable) return { success: false, message: 'Not ready. Need language 100 + all 5 resonance sites.' };
        if (player.shipwrecked.finalChoice) return { success: false, message: 'Choice already made: ' + player.shipwrecked.finalChoice };
        
        var town = Engine.findTown(embassyTownId || player.townId);
        if (!town) return { success: false, message: 'Town not found.' };
        if (!town.isPort) return { success: false, message: 'Embassy must be in a seaport town.' };
        
        player.shipwrecked.finalChoice = 'open';
        player.inventory.exotic_artifact = 0;
        
        // Create embassy
        var embassyData = {
            townId: town.id,
            townName: town.name,
            kingdomId: town.kingdomId,
            builtDay: Engine.getDay(),
            potionStockRed: 5,
            potionStockGreen: 5,
            potionStockBlue: 5
        };
        player.shipwrecked.embassy = embassyData;
        
        // Place building in town
        town.buildings = town.buildings || [];
        town.buildings.push({
            type: 'embassy',
            level: 1,
            ownerId: 'player',
            builtDay: Engine.getDay(),
            condition: 100,
            lastRepairDay: Engine.getDay()
        });
        
        // Town becomes indestructible
        town.indestructible = true;
        
        // +2 social ranks
        player.socialRank = player.socialRank || {};
        var currentRank = player.socialRank[town.kingdomId] || 0;
        player.socialRank[town.kingdomId] = Math.min(6, currentRank + 2);
        
        // Diplomatic immunity
        player.shipwrecked.diplomaticImmunityTownId = town.id;
        
        // Generate homeland NPCs
        var homelandNames = [
            { first: 'Kael', last: 'Stormborn', role: 'healer', dialog: [
                'I remember you from the Council chambers. We thought you were lost forever.',
                'This land is... different. The air tastes of salt and old stone.',
                'Back home, the healers work with crystals. Here they use herbs. Both work, I suppose.',
                'I will heal your wounds for free, always. You are family.'
            ]},
            { first: 'Liara', last: 'Tidecaller', role: 'merchant', dialog: [
                'The markets here are chaotic but fascinating. No fixed prices!',
                'In our homeland, the Merchant Guild sets all prices. Here, it is... wild.',
                'You were the youngest council member in a generation. Did you know that?',
                'These people brew a drink called ale. We have nothing like it back home.'
            ]},
            { first: 'Tormund', last: 'Ironveil', role: 'guard', dialog: [
                'I volunteered to come through. Someone has to keep you safe.',
                'Their weapons are crude but effective. I could learn a thing or two.',
                'The storms between our worlds are growing weaker. The artifact did that.',
                'Back home, we have no kings. Only the Council of Tides rules.'
            ]},
            { first: 'Yua', last: 'Dawnweaver', role: 'scholar', dialog: [
                'Remarkable! Their written language uses individual symbols for sounds. Ours uses whole concepts.',
                'I have been cataloging the local flora. Three species unknown to our world!',
                'You were carrying the Artifact of Bridges when you washed ashore. That was no accident.',
                'The people here fear the sea. For us, it was home. How strange.'
            ]},
            { first: 'Ren', last: 'Shellsong', role: 'worker', dialog: [
                'I can fix anything. Point me at a broken wall and I will have it right.',
                'The food here is heavy and rich. I miss the light seafood from home.',
                'We heard your signal across the storm-wall. It took us months to find a passage.',
                'Working for free? Of course. You opened the path. We owe you everything.'
            ]}
        ];
        player.shipwrecked.homelandNPCs = homelandNames;
        
        // Grant skills
        player.skills.embassy_founder = true;
        player.skills.bridge_between_worlds = true;
        
        grantXP(150, 'opened artifact');
        Engine.logEvent('🏛️ ' + player.fullName + ' OPENED the artifact and founded an Embassy in ' + town.name + '! A bridge between two worlds!');
        
        return { success: true, message: '🏛️ Embassy founded in ' + town.name + '! 10 potions/day, own bank, +2 social rank, town is indestructible, diplomatic immunity, homeland NPCs arrived. Warp available (30-day cooldown).' };
    }
    
    function sealArtifact() {
        if (!player.shipwrecked) return { success: false, message: 'Not shipwrecked start.' };
        if (!player.shipwrecked.finalChoiceAvailable) return { success: false, message: 'Not ready. Need language 100 + all 5 resonance sites.' };
        if (player.shipwrecked.finalChoice) return { success: false, message: 'Choice already made: ' + player.shipwrecked.finalChoice };
        
        player.shipwrecked.finalChoice = 'seal';
        player.inventory.exotic_artifact = 0;
        
        // Permanent bonuses
        player.shipwrecked.sealBonuses = {
            speedBonus: 0.25,       // +25% travel speed
            skillPoints: 20,        // one-time
            repBonus: 0.25,         // +25% relationship/rep gains
            diseaseReduction: 0.25, // -25% disease/injury/death
            lifespanBonus: 10,      // +10 years
            deathReversal: true     // one-time death reversal
        };
        player.shipwrecked.deathReversalAvailable = true;
        
        // Grant 20 skill points (as XP equivalent)
        grantXP(500, 'artifact absorption'); // Large XP dump
        
        // Increase max age
        player.maxAge = (player.maxAge || 70) + 10;
        
        // Grant skills
        player.skills.artifact_bearer = true;
        player.skills.seal_of_ages = true;
        player.skills.world_traveler = true;
        
        Engine.logEvent('⚡ ' + player.fullName + ' SEALED the artifact and absorbed its power! +25% speed, +25% rep gains, -25% disease/death risk, +10 year lifespan, one-time death reversal.');
        
        return { success: true, message: '⚡ POWER ABSORBED! +25% travel speed, +500 XP, +25% relationship gains, -25% disease/injury/death, +10 year lifespan. If you die, you may reverse death ONCE (bonuses removed except skills).' };
    }
    
    function warpToEmbassy() {
        if (!player.shipwrecked || !player.shipwrecked.embassy) return { success: false, message: 'No embassy.' };
        var day = Engine.getDay();
        var cooldown = 30;
        if (day - (player.shipwrecked.lastWarpDay || -9999) < cooldown) {
            var remaining = cooldown - (day - player.shipwrecked.lastWarpDay);
            return { success: false, message: 'Warp on cooldown. ' + remaining + ' days remaining.' };
        }
        
        player.shipwrecked.lastWarpDay = day;
        player.townId = player.shipwrecked.embassy.townId;
        player.traveling = false;
        
        // Update coordinates
        var embTown = Engine.findTown(player.shipwrecked.embassy.townId);
        if (embTown) {
            player.worldX = embTown.x;
            player.worldY = embTown.y;
        }
        
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(5);
        Engine.logEvent('🌀 ' + player.fullName + ' warped to the Embassy in ' + (player.shipwrecked.embassy.townName || 'embassy town') + '!');
        return { success: true, message: '🌀 Warped to Embassy in ' + (player.shipwrecked.embassy.townName || 'embassy town') + '! Next warp in 30 days.' };
    }
    
    function claimFreePotion(type) {
        if (!player.shipwrecked || !player.shipwrecked.embassy) return { success: false, message: 'No embassy.' };
        var validTypes = ['red', 'green', 'blue'];
        if (validTypes.indexOf(type) === -1) return { success: false, message: 'Choose red, green, or blue.' };
        
        var day = Engine.getDay();
        if (day - (player.shipwrecked.lastFreePotionDay || -9999) < 30) {
            var remaining = 30 - (day - player.shipwrecked.lastFreePotionDay);
            return { success: false, message: 'Free potion available in ' + remaining + ' days.' };
        }
        
        player.shipwrecked.lastFreePotionDay = day;
        player.shipwrecked.freePotion = { type: type, claimedDay: day, expiresDay: day + 30 };
        
        // Apply potion effect
        var effectMsg = '';
        if (type === 'red') {
            player.shipwrecked.freePotion.effect = 'strength';
            effectMsg = '💪 Crimson Vigor: +25% combat strength, +15% work output for 30 days.';
        } else if (type === 'green') {
            player.shipwrecked.freePotion.effect = 'productivity';
            effectMsg = '⚡ Emerald Swiftness: +25% travel speed, +15% skill gain rate for 30 days.';
        } else if (type === 'blue') {
            player.shipwrecked.freePotion.effect = 'immunity';
            effectMsg = '🛡️ Azure Ward: Immune to disease and injury for 30 days.';
        }
        
        grantXP(5, 'potion claimed');
        return { success: true, message: 'Free potion claimed! ' + effectMsg + ' You can sell it instead or use it.' };
    }
    
    function talkToHomelandNPC(npcIndex) {
        if (!player.shipwrecked || !player.shipwrecked.homelandNPCs) return { success: false, message: 'No homeland NPCs.' };
        if (!player.shipwrecked.embassy || player.townId !== player.shipwrecked.embassy.townId) {
            return { success: false, message: 'You must be at the Embassy to talk to homeland NPCs.' };
        }
        var npc = player.shipwrecked.homelandNPCs[npcIndex];
        if (!npc) return { success: false, message: 'NPC not found.' };
        
        var rng = Engine.getRng();
        var dialog = npc.dialog[rng.randInt(0, npc.dialog.length - 1)];
        
        // Healer heals for free
        if (npc.role === 'healer') {
            if (player.injuries && player.injuries.length > 0) {
                player.injuries = [];
                dialog += ' (All injuries healed!)';
            }
            if (player.illnesses && player.illnesses.length > 0) {
                player.illnesses = [];
                dialog += ' (All illnesses cured!)';
            }
        }
        
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(2);
        return { success: true, message: npc.first + ' ' + npc.last + ' (' + npc.role + '): "' + dialog + '"' };
    }
    
    function reverseShipwreckedDeath() {
        if (!player.shipwrecked || !player.shipwrecked.deathReversalAvailable) return { success: false, message: 'No death reversal available.' };
        if (player.shipwrecked.deathReversalUsed) return { success: false, message: 'Already used death reversal.' };
        
        player.shipwrecked.deathReversalUsed = true;
        player.shipwrecked.deathReversalAvailable = false;
        player.alive = true;
        player.energy = 50;
        
        // Remove seal bonuses except skill points already spent
        if (player.shipwrecked.sealBonuses) {
            player.shipwrecked.sealBonuses.speedBonus = 0;
            player.shipwrecked.sealBonuses.repBonus = 0;
            player.shipwrecked.sealBonuses.diseaseReduction = 0;
            player.shipwrecked.sealBonuses.lifespanBonus = 0;
            player.maxAge = (player.maxAge || 80) - 10;
        }
        
        Engine.logEvent('💫 ' + player.fullName + ' has been brought back from death by the artifact\'s residual power! But the power is spent — bonuses removed.');
        return { success: true, message: '💫 Death reversed! You live again, but artifact bonuses are gone. Only your earned skills remain.' };
    }

    // Musician actions
    function performAtTavern(townId) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        var rng = Engine.getRng();
        var gold = Math.floor(5 + (player.musician.musicSkill / 100) * 15);
        if (hasSkill('musician')) gold = Math.floor(gold * 1.5);
        player.gold += gold;
        player.stats.totalGoldEarned += gold;
        player.musician.totalPerformances++;
        player.musician.musicSkill = Math.min(100, player.musician.musicSkill + 1);
        // Gain fans
        var newFans = rng.randInt(1, 3);
        var townPeople = Engine.getPeople(townId);
        var potentialFans = townPeople.filter(function(p) { return !player.musician.fans[p.id]; });
        for (var fi = 0; fi < Math.min(newFans, potentialFans.length); fi++) {
            player.musician.fans[potentialFans[fi].id] = true;
        }
        // Fame boost
        var town = Engine.findTown(townId);
        if (town && town.kingdomId) {
            var fameGain = hasSkill('musician') ? 1.25 : 1;
            player.musician.fame[town.kingdomId] = Math.min(100, (player.musician.fame[town.kingdomId] || 0) + fameGain);
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.perform_tavern || 8);
        grantXP(3, 'performance');
        return { success: true, message: 'Tavern performance! Earned ' + gold + 'g. Music skill: ' + player.musician.musicSkill };
    }

    function streetPerformance(townId) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        var rng = Engine.getRng();
        var gold = rng.randInt(2, 8);
        if (hasSkill('musician')) gold = Math.floor(gold * 1.5);
        player.gold += gold;
        player.stats.totalGoldEarned += gold;
        player.musician.totalPerformances++;
        var newFans = rng.randInt(2, 5);
        var townPeople = Engine.getPeople(townId);
        var potentialFans = townPeople.filter(function(p) { return !player.musician.fans[p.id]; });
        for (var fi = 0; fi < Math.min(newFans, potentialFans.length); fi++) {
            player.musician.fans[potentialFans[fi].id] = true;
        }
        var town = Engine.findTown(townId);
        if (town && town.kingdomId) {
            var streetFameGain = hasSkill('musician') ? 0.625 : 0.5;
            player.musician.fame[town.kingdomId] = Math.min(100, (player.musician.fame[town.kingdomId] || 0) + streetFameGain);
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.street_performance || 5);
        grantXP(2, 'street performance');
        return { success: true, message: 'Street performance! Earned ' + gold + 'g.' };
    }

    function hostConcert(townId) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        if (player.musician.musicSkill < 40) return { success: false, message: 'Music skill must be 40+.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        // Count fans in town
        var fansInTown = 0;
        var townPeople = Engine.getPeople(townId);
        for (var ti = 0; ti < townPeople.length; ti++) {
            if (player.musician.fans[townPeople[ti].id]) fansInTown++;
        }
        if (fansInTown < 20) return { success: false, message: 'Need 20+ fans in this town. Current: ' + fansInTown };
        if (player.gold < 50) return { success: false, message: 'Need 50g for venue rental.' };
        player.gold -= 50;
        var earnings = fansInTown * 5;
        player.gold += earnings;
        player.stats.totalGoldEarned += earnings;
        var town = Engine.findTown(townId);
        if (town && town.kingdomId) {
            player.musician.fame[town.kingdomId] = Math.min(100, (player.musician.fame[town.kingdomId] || 0) + 5);
        }
        player.musician.totalPerformances++;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.host_concert || 30);
        grantXP(15, 'concert');
        return { success: true, message: 'Concert! Earned ' + earnings + 'g from ' + fansInTown + ' fans!' };
    }

    function composeSong(theme) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        var validThemes = ['love', 'war', 'comedy', 'tragedy', 'nature', 'epic'];
        if (validThemes.indexOf(theme) === -1) theme = 'love';
        var day = Engine.getDay();
        var rng = Engine.getRng();
        player.musician.songsComposed.push({ theme: theme, day: day, quality: player.musician.musicSkill });
        
        // Theme-specific fame bonuses
        var kingdoms = Engine.getKingdoms();
        var fameBonus = 3 + Math.floor(player.musician.musicSkill / 25);
        for (var ki = 0; ki < kingdoms.length; ki++) {
            var k = kingdoms[ki];
            var bonus = fameBonus;
            // War songs boost more in kingdoms at war
            if (theme === 'war' && k.atWar && (Array.isArray(k.atWar) ? k.atWar.length > 0 : k.atWar.size > 0)) {
                bonus = Math.floor(bonus * 2);
            }
            // Love songs popular in peaceful kingdoms
            if (theme === 'love' && (!k.atWar || (Array.isArray(k.atWar) ? k.atWar.length === 0 : true))) {
                bonus = Math.floor(bonus * 1.5);
            }
            // Comedy popular everywhere (slight universal bonus)
            if (theme === 'comedy') bonus = Math.floor(bonus * 1.3);
            // Epic songs boost in large kingdoms
            if (theme === 'epic') bonus = Math.floor(bonus * 1.4);
            player.musician.fame[k.id] = Math.min(100, (player.musician.fame[k.id] || 0) + bonus);
        }
        
        player.musician.musicSkill = Math.min(100, player.musician.musicSkill + 2);
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.compose_song || 10);
        grantXP(5, 'compose');
        var themeLabels = { love: '❤️ Love Ballad', war: '⚔️ War Anthem', comedy: '😂 Comedy', tragedy: '😢 Tragedy', nature: '🌿 Nature Hymn', epic: '⭐ Epic Tale' };
        return { success: true, message: 'Composed: ' + (themeLabels[theme] || theme) + '! Fame boosted across all kingdoms. Total songs: ' + player.musician.songsComposed.length };
    }

    function performAtCourt(kingdomId) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        if ((player.musician.fame[kingdomId] || 0) < 30) return { success: false, message: 'Need 30+ fame in this kingdom.' };
        var day = Engine.getDay();
        if (player.musician.lastCourtPerformance[kingdomId] && day - player.musician.lastCourtPerformance[kingdomId] < 30) {
            return { success: false, message: 'Must wait 30 days between court performances.' };
        }
        var rng = Engine.getRng();
        var gold = rng.randInt(50, 200);
        player.gold += gold;
        player.stats.totalGoldEarned += gold;
        player.reputation[kingdomId] = Math.min(100, (player.reputation[kingdomId] || 50) + 15);
        player.musician.lastCourtPerformance[kingdomId] = day;
        player.musician.totalPerformances++;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.perform_court || 15);
        grantXP(10, 'court performance');
        return { success: true, message: 'Performed at court! Earned ' + gold + 'g, +15 reputation.' };
    }

    function privatePerformance(npcId) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Person not found.' };
        var rng = Engine.getRng();
        var gold = rng.randInt(10, 50);
        player.gold += gold;
        player.stats.totalGoldEarned += gold;
        player.relationships[npcId] = player.relationships[npcId] || { level: 0, type: 'acquaintance' };
        player.relationships[npcId].level = Math.min(100, player.relationships[npcId].level + 15);
        player.musician.totalPerformances++;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.private_performance || 5);
        grantXP(3, 'private performance');
        return { success: true, message: 'Private performance for ' + person.firstName + '! ' + gold + 'g, +15 relationship.' };
    }

    function grandConcert(townId) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        if (player.musician.musicSkill < 70) return { success: false, message: 'Music skill must be 70+ for a Grand Concert.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        var town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        var avgFame = 0;
        var kingdoms = Engine.getKingdoms();
        for (var ki = 0; ki < kingdoms.length; ki++) {
            avgFame += (player.musician.fame[kingdoms[ki].id] || 0);
        }
        avgFame = kingdoms.length > 0 ? avgFame / kingdoms.length : 0;
        if (avgFame < 50) return { success: false, message: 'Need 50+ average fame across kingdoms. Current: ' + Math.floor(avgFame) };
        if (player.gold < 200) return { success: false, message: 'Need 200g for Grand Concert venue and marketing.' };
        
        player.gold -= 200;
        var rng = Engine.getRng();
        var skill = player.musician.musicSkill;
        var songCount = player.musician.songsComposed.length;
        
        // Success chance based on skill, songs composed, and luck
        var successChance = 0.3 + (skill / 200) + (songCount * 0.02);
        successChance = Math.min(0.85, successChance);
        var roll = rng.random();
        
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.grand_concert || 60);
        player.musician.totalPerformances++;
        
        if (roll < successChance * 0.4) {
            // LEGENDARY performance
            var earnings = rng.randInt(500, 1000);
            player.gold += earnings;
            player.stats.totalGoldEarned += earnings;
            // Massive fame boost
            for (var ki2 = 0; ki2 < kingdoms.length; ki2++) {
                player.musician.fame[kingdoms[ki2].id] = Math.min(100, (player.musician.fame[kingdoms[ki2].id] || 0) + 15);
            }
            // Tons of new fans
            var townPeople = Engine.getPeople(townId);
            var newFanCount = Math.min(townPeople.length, rng.randInt(20, 40));
            var potentialFans = townPeople.filter(function(p) { return !player.musician.fans[p.id]; });
            for (var fi = 0; fi < Math.min(newFanCount, potentialFans.length); fi++) {
                player.musician.fans[potentialFans[fi].id] = true;
            }
            if (town.kingdomId) {
                player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + 20);
            }
            grantXP(50, 'legendary concert');
            Engine.logEvent('🌟 ' + player.fullName + ' gave a LEGENDARY Grand Concert in ' + town.name + '! The crowd erupted in pure joy!');
            return { success: true, message: '🌟 LEGENDARY! Earned ' + earnings + 'g, +15 fame everywhere, ' + Math.min(newFanCount, potentialFans.length) + ' new fans!' };
        } else if (roll < successChance) {
            // Good performance
            var earnings2 = rng.randInt(200, 500);
            player.gold += earnings2;
            player.stats.totalGoldEarned += earnings2;
            for (var ki3 = 0; ki3 < kingdoms.length; ki3++) {
                player.musician.fame[kingdoms[ki3].id] = Math.min(100, (player.musician.fame[kingdoms[ki3].id] || 0) + 8);
            }
            var townPeople2 = Engine.getPeople(townId);
            var potentialFans2 = townPeople2.filter(function(p) { return !player.musician.fans[p.id]; });
            var fanGain = Math.min(potentialFans2.length, rng.randInt(10, 20));
            for (var fi2 = 0; fi2 < fanGain; fi2++) {
                player.musician.fans[potentialFans2[fi2].id] = true;
            }
            grantXP(25, 'grand concert');
            return { success: true, message: 'Grand Concert was a hit! Earned ' + earnings2 + 'g, +8 fame, ' + fanGain + ' new fans!' };
        } else {
            // FLOP
            var fameLoss = rng.randInt(3, 8);
            if (town.kingdomId) {
                player.musician.fame[town.kingdomId] = Math.max(0, (player.musician.fame[town.kingdomId] || 0) - fameLoss);
                player.reputation[town.kingdomId] = Math.max(0, (player.reputation[town.kingdomId] || 50) - 5);
            }
            Engine.logEvent('😬 ' + player.fullName + '\'s Grand Concert in ' + town.name + ' was a disaster. The crowd booed.');
            grantXP(5, 'flop concert');
            return { success: false, message: 'Concert flopped! Lost ' + fameLoss + ' fame in ' + (town.name || 'this kingdom') + ', -5 rep. 200g wasted.' };
        }
    }

    function musicDuel(rivalIndex) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        if (!player.musician.rivals || !player.musician.rivals[rivalIndex]) return { success: false, message: 'Rival not found.' };
        var rival = player.musician.rivals[rivalIndex];
        if (rival.defeated) return { success: false, message: rival.name + ' has already been defeated.' };
        if (rival.townId !== player.townId) {
            var rivalTown = Engine.findTown(rival.townId);
            return { success: false, message: rival.name + ' is not in this town.' + (rivalTown ? ' Last seen in ' + rivalTown.name + '.' : '') };
        }
        var day = Engine.getDay();
        if (day - (player.musician.lastDuelDay || 0) < 7) {
            return { success: false, message: 'Must wait 7 days between duels. (' + (7 - (day - player.musician.lastDuelDay)) + ' days left)' };
        }
        
        player.musician.lastDuelDay = day;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.music_duel || 10);
        
        // 3-round duel — each round, pick a different instrument
        var instruments = ['lute', 'flute', 'drum', 'harp', 'fiddle', 'pipes'];
        var rng = Engine.getRng();
        var playerWins = 0;
        var rivalWins = 0;
        var roundLog = [];
        var usedByPlayer = [];
        var usedByRival = [];
        
        for (var round = 0; round < 3; round++) {
            var playerPool = instruments.filter(function(i) { return usedByPlayer.indexOf(i) === -1; });
            var rivalPool = instruments.filter(function(i) { return usedByRival.indexOf(i) === -1; });
            var playerPick = rng.pick(playerPool);
            var rivalPick = rng.pick(rivalPool);
            usedByPlayer.push(playerPick);
            usedByRival.push(rivalPick);
            
            // Score: skill + instrument affinity + crowd taste + randomness
            var playerScore = player.musician.musicSkill + rng.randInt(0, 25);
            var rivalScore = rival.skill + rng.randInt(0, 25);
            
            // Bonus for matching the crowd's taste (random per round)
            var crowdPreference = rng.pick(instruments);
            if (playerPick === crowdPreference) playerScore += 15;
            if (rivalPick === crowdPreference) rivalScore += 15;
            
            // Bonus if player's main instrument matches
            if (playerPick === (player.musician.instrument || 'lute')) playerScore += 10;
            if (rivalPick === rival.instrument) rivalScore += 10;
            
            if (playerScore > rivalScore) {
                playerWins++;
                roundLog.push('Round ' + (round + 1) + ': You (' + playerPick + ') beat ' + rival.name + ' (' + rivalPick + ')!');
            } else {
                rivalWins++;
                roundLog.push('Round ' + (round + 1) + ': ' + rival.name + ' (' + rivalPick + ') won with the crowd!');
            }
        }
        
        var resultMsg = roundLog.join(' ');
        
        if (playerWins > rivalWins) {
            // WIN — steal their fans
            var stolenFans2 = Math.floor(rival.fans * 0.4);
            rival.fans = Math.max(0, rival.fans - stolenFans2);
            rival.skill = Math.max(5, rival.skill - 5);
            
            // Convert stolen fans to actual player fans
            var townPeople3 = Engine.getPeople(player.townId);
            var potFans = townPeople3.filter(function(p) { return !player.musician.fans[p.id]; });
            var actualGained = Math.min(stolenFans2, potFans.length);
            for (var fg = 0; fg < actualGained; fg++) {
                player.musician.fans[potFans[fg].id] = true;
            }
            
            player.musician.duelsWon = (player.musician.duelsWon || 0) + 1;
            player.musician.musicSkill = Math.min(100, player.musician.musicSkill + 3);
            
            // If rival has no fans left, they're defeated
            if (rival.fans <= 0) {
                rival.defeated = true;
                Engine.logEvent('🏆 ' + player.fullName + ' defeated ' + rival.name + ' in a legendary music duel! The rival has retired in shame.');
                grantXP(30, 'defeated rival musician');
                return { success: true, message: '🏆 VICTORY! ' + resultMsg + ' ' + rival.name + ' is defeated and retires! +' + actualGained + ' fans.' };
            }
            
            var town = Engine.findTown(player.townId);
            if (town && town.kingdomId) {
                player.musician.fame[town.kingdomId] = Math.min(100, (player.musician.fame[town.kingdomId] || 0) + 5);
            }
            grantXP(15, 'won duel');
            Engine.logEvent('🎵 ' + player.fullName + ' won a music duel against ' + rival.name + '!');
            return { success: true, message: 'You won! ' + resultMsg + ' Gained ' + actualGained + ' fans, +5 fame.' };
        } else {
            // LOSE — lose fame in this town's kingdom
            var town2 = Engine.findTown(player.townId);
            var fameLoss2 = rng.randInt(3, 8);
            if (town2 && town2.kingdomId) {
                player.musician.fame[town2.kingdomId] = Math.max(0, (player.musician.fame[town2.kingdomId] || 0) - fameLoss2);
            }
            player.musician.duelsLost = (player.musician.duelsLost || 0) + 1;
            rival.skill = Math.min(95, rival.skill + 3);
            rival.fans += 3;
            grantXP(5, 'lost duel');
            return { success: false, message: 'You lost! ' + resultMsg + ' -' + fameLoss2 + ' fame in ' + (town2 ? town2.name : 'this kingdom') + '.' };
        }
    }

    function chooseMusicianLegacy(choice) {
        if (!player.musician) return { success: false, message: 'Not a musician.' };
        if (!player.musician.legacyOffered) return { success: false, message: 'You haven\'t reached legendary fame yet.' };
        if (player.musician.legacyChoice) return { success: false, message: 'You already chose: ' + player.musician.legacyChoice };
        
        if (choice === 'music_school') {
            player.musician.legacyChoice = 'music_school';
            player.musician.active = false;
            player.musician.musicSchoolTownId = player.townId;
            player.musician.musicSchoolIncome = 0;
            // Grant business skills
            player.skills.bards_immunity = true;
            player.skills.crowd_control = true;
            player.skills.royal_performer = true;
            player.skills.song_of_prosperity = true;
            player.skills.music_school_owner = true;
            // Place unique building
            var town = Engine.findTown(player.townId);
            if (town) {
                town.buildings = town.buildings || [];
                town.buildings.push({
                    type: 'music_school',
                    level: 1,
                    ownerId: 'player',
                    builtDay: Engine.getDay(),
                    condition: 100,
                    lastRepairDay: Engine.getDay()
                });
            }
            Engine.logEvent('🎵 ' + player.fullName + ' founded a legendary Music School in ' + (town ? town.name : 'town') + '! Students flock from across the land.');
            grantXP(100, 'music school');
            return { success: true, message: '🏫 Music School founded in ' + (town ? town.name : 'town') + '! Earns passive income. You can send children here for instrument skills. Merchant career unlocked!' };
        } else if (choice === 'legendary_bard') {
            player.musician.legacyChoice = 'legendary_bard';
            // Stay active but with enhanced abilities
            player.skills.bards_immunity = true;
            player.skills.crowd_control = true;
            player.skills.royal_performer = true;
            player.skills.song_of_prosperity = true;
            player.skills.legendary_bard = true;
            // Legendary bards get: free inn stays, +50% all performance income, can perform at any court regardless of fame
            player.musician.musicSkill = 100;
            Engine.logEvent('🌟 ' + player.fullName + ' chose the life of a Legendary Bard! Their music echoes across all kingdoms.');
            grantXP(100, 'legendary bard');
            return { success: true, message: '🌟 You are now a Legendary Bard! 100 music skill, +50% income, court access everywhere, free inn stays. Continue your endless journey!' };
        }
        return { success: false, message: 'Choose music_school or legendary_bard.' };
    }

    // Military Leader actions
    function trainTroops(townId) {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        var tid = townId || player.townId;
        var town = Engine.findTown(tid);
        if (!town) return { success: false, message: 'Town not found.' };
        var kingdom = Engine.findKingdom(town.kingdomId);
        if (kingdom) {
            kingdom.militaryStrength = (kingdom.militaryStrength || 0) + 5;
        }
        player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + 2);
        player.militaryLeader.trainingsDone = (player.militaryLeader.trainingsDone || 0) + 1;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.train_troops || 10);
        grantXP(5, 'train troops');
        // Check for promotion based on training milestones
        checkMilitaryPromotion();
        return { success: true, message: 'Trained troops! +5 kingdom military strength, +2 reputation.' };
    }

    function planBattle() {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.plan_battle || 5);
        grantXP(3, 'plan battle');
        player.militaryLeader.battlePlanReady = true;
        return { success: true, message: 'Battle plan prepared! +20% success on next battle.' };
    }

    function inspireArmy() {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.inspire_army || 3);
        grantXP(2, 'inspire');
        player.militaryLeader.armyInspired = true;
        return { success: true, message: 'Army inspired! Soldiers -5% death chance in next battle.' };
    }

    function fortifyPosition(townId) {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        if (player.gold < 100) return { success: false, message: 'Need 100g for materials.' };
        var town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        player.gold -= 100;
        player.stats.totalGoldSpent += 100;
        town.garrison = (town.garrison || 0) + 10;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.fortify_position || 15);
        grantXP(5, 'fortify');
        return { success: true, message: 'Position fortified! +10 town defense.' };
    }

    function scoutEnemy() {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.scout_enemy || 8);
        grantXP(3, 'scout');
        var rng = Engine.getRng();
        var kingdoms = Engine.getKingdoms();
        var enemyKingdom = null;
        if (player.militaryKingdomId) {
            var playerK = Engine.findKingdom(player.militaryKingdomId);
            if (playerK && playerK.atWar) {
                var atWarArr = Array.isArray(playerK.atWar) ? playerK.atWar : [...playerK.atWar];
                if (atWarArr.length > 0) {
                    var eid = atWarArr[0];
                    enemyKingdom = Engine.findKingdom(eid);
                }
            }
        }
        if (enemyKingdom) {
            return { success: true, message: 'Scouted enemy: ' + enemyKingdom.name + ' has ~' + (enemyKingdom.militaryStrength || 0) + ' military strength.' };
        }
        return { success: true, message: 'No active enemies detected.' };
    }

    function engageBattle(tactic) {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        var validTactics = ['aggressive', 'defensive', 'flanking'];
        if (validTactics.indexOf(tactic) === -1) return { success: false, message: 'Choose a tactic: aggressive, defensive, or flanking.' };
        
        var playerK = null;
        if (player.militaryKingdomId) {
            playerK = Engine.findKingdom(player.militaryKingdomId);
        }
        if (!playerK || !playerK.atWar || (Array.isArray(playerK.atWar) ? playerK.atWar.length === 0 : true)) {
            return { success: false, message: 'Your kingdom is not at war. No battles available.' };
        }
        
        var day = Engine.getDay();
        if (day - (player.militaryLeader.lastBattleDay || 0) < 10) {
            return { success: false, message: 'Troops need rest. Wait ' + (10 - (day - player.militaryLeader.lastBattleDay)) + ' more days.' };
        }
        
        var rng = Engine.getRng();
        var atWarArr = Array.isArray(playerK.atWar) ? playerK.atWar : [playerK.atWar];
        var enemyId = atWarArr[rng.randInt(0, atWarArr.length - 1)];
        var enemyK = Engine.findKingdom(enemyId);
        if (!enemyK) return { success: false, message: 'Enemy kingdom not found.' };
        
        player.militaryLeader.lastBattleDay = day;
        player.militaryLeader.tacticsUsed = player.militaryLeader.tacticsUsed || {};
        player.militaryLeader.tacticsUsed[tactic] = (player.militaryLeader.tacticsUsed[tactic] || 0) + 1;
        
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.engage_battle || 30);
        
        // Calculate battle score
        var playerMil = playerK.militaryStrength || 50;
        var enemyMil = enemyK.militaryStrength || 50;
        var trainings = player.militaryLeader.trainingsDone || 0;
        var rankIdx = (CONFIG.MILITARY_LEADER_RANKS || []).findIndex(function(r) { return r.id === player.militaryLeader.rank; });
        
        var playerScore = playerMil + (trainings * 0.5) + (rankIdx * 10) + rng.randInt(0, 30);
        var enemyScore = enemyMil + rng.randInt(0, 30);
        
        // Tactic modifiers
        if (tactic === 'aggressive') {
            playerScore += 20; // Big attack bonus
            // But if enemy is strong, risky
            if (enemyMil > playerMil * 1.5) playerScore -= 15;
        } else if (tactic === 'defensive') {
            playerScore += 10;
            // Reduces enemy score — safe option
            enemyScore -= 10;
        } else if (tactic === 'flanking') {
            // High risk, high reward — requires higher skill
            if (trainings > 20) {
                playerScore += 30;
            } else {
                playerScore -= 10; // Badly executed flank
            }
        }
        
        // Plan battle bonus (if planBattle was recently used)
        if (player.militaryLeader.battlePlanReady) {
            playerScore += 15;
            player.militaryLeader.battlePlanReady = false;
        }
        
        // Inspire bonus
        if (player.militaryLeader.armyInspired) {
            playerScore += 10;
            player.militaryLeader.armyInspired = false;
        }
        
        player.militaryLeader.battlesAsLeader = (player.militaryLeader.battlesAsLeader || 0) + 1;
        
        var isSiege = rng.random() < 0.3; // 30% chance it's a siege
        var isNaval = rng.random() < 0.15; // 15% chance it's naval
        var battleType = isNaval ? 'naval battle' : (isSiege ? 'siege' : 'field battle');
        
        if (playerScore > enemyScore) {
            // VICTORY
            player.militaryLeader.victoriesAsLeader = (player.militaryLeader.victoriesAsLeader || 0) + 1;
            if (isSiege) player.militaryLeader.siegesWon = (player.militaryLeader.siegesWon || 0) + 1;
            if (isNaval) player.militaryLeader.navalBattlesWon = (player.militaryLeader.navalBattlesWon || 0) + 1;
            
            playerK.militaryStrength = (playerK.militaryStrength || 50) + 5;
            enemyK.militaryStrength = Math.max(10, (enemyK.militaryStrength || 50) - 5);
            
            var goldReward = rng.randInt(50, 150) + (rankIdx * 25);
            player.gold += goldReward;
            player.stats.totalGoldEarned += goldReward;
            
            player.reputation[player.militaryKingdomId] = Math.min(100, (player.reputation[player.militaryKingdomId] || 50) + 5);
            
            checkMilitaryPromotion();
            grantXP(20, 'battle victory');
            
            var victoryMsg = '⚔️ VICTORY in ' + battleType + ' against ' + enemyK.name + '! Tactic: ' + tactic + '. Earned ' + goldReward + 'g, +5 kingdom strength.';
            Engine.logEvent(player.fullName + ' won a ' + battleType + ' against ' + enemyK.name + ' using ' + tactic + ' tactics!');
            
            // Check decisive battle eligibility
            if (rankIdx >= 5 && (player.militaryLeader.victoriesAsLeader || 0) >= 10) {
                player.militaryLeader.decisiveBattleAvailable = true;
            }
            
            return { success: true, message: victoryMsg };
        } else {
            // DEFEAT
            playerK.militaryStrength = Math.max(10, (playerK.militaryStrength || 50) - 3);
            
            // Injury risk
            var injuryChance = tactic === 'aggressive' ? 0.3 : (tactic === 'flanking' ? 0.2 : 0.1);
            if (rng.random() < injuryChance && typeof inflictRandomInjury === 'function') {
                inflictRandomInjury('battle');
            }
            
            grantXP(8, 'battle defeat');
            Engine.logEvent(player.fullName + ' lost a ' + battleType + ' against ' + enemyK.name + '.');
            return { success: false, message: '💀 DEFEAT in ' + battleType + ' against ' + enemyK.name + '. Tactic: ' + tactic + '. Kingdom lost 3 military strength.' + (injuryChance > 0.15 ? ' You were injured!' : '') };
        }
    }

    function attendWarCouncil() {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        var ranks = CONFIG.MILITARY_LEADER_RANKS || [];
        var rankIdx = ranks.findIndex(function(r) { return r.id === player.militaryLeader.rank; });
        if (rankIdx < 4) return { success: false, message: 'Must be Captain or higher to attend War Council. Current rank: ' + (ranks[rankIdx] ? ranks[rankIdx].name : player.militaryLeader.rank) };
        
        var playerK = Engine.findKingdom(player.militaryKingdomId);
        if (!playerK || !playerK.atWar || (Array.isArray(playerK.atWar) ? playerK.atWar.length === 0 : true)) {
            return { success: false, message: 'No active wars. War council not in session.' };
        }
        
        var day = Engine.getDay();
        if (player.militaryLeader.lastCouncilDay && day - player.militaryLeader.lastCouncilDay < 30) {
            return { success: false, message: 'War council meets monthly. Next in ' + (30 - (day - player.militaryLeader.lastCouncilDay)) + ' days.' };
        }
        
        player.militaryLeader.lastCouncilDay = day;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.war_council || 15);
        
        var rng = Engine.getRng();
        var atWarArr = Array.isArray(playerK.atWar) ? playerK.atWar : [playerK.atWar];
        var enemyId = atWarArr[rng.randInt(0, atWarArr.length - 1)];
        var enemyK = Engine.findKingdom(enemyId);
        
        // Present 3 strategic options, each with different outcomes
        var strategies = [
            { name: 'Full Offensive', effect: 'boost_attack', desc: '+15 kingdom military, enemy -10, but costs 200g in war taxes' },
            { name: 'Fortify Borders', effect: 'fortify', desc: '+20 all town garrisons, +5 kingdom military, slower but safe' },
            { name: 'Economic Blockade', effect: 'blockade', desc: 'Enemy loses 10% treasury each month, your traders earn +20% in war zones' }
        ];
        
        var chosen = strategies[rng.randInt(0, strategies.length - 1)];
        
        // Apply the council strategy
        if (chosen.effect === 'boost_attack') {
            playerK.militaryStrength = (playerK.militaryStrength || 50) + 15;
            if (enemyK) enemyK.militaryStrength = Math.max(10, (enemyK.militaryStrength || 50) - 10);
        } else if (chosen.effect === 'fortify') {
            playerK.militaryStrength = (playerK.militaryStrength || 50) + 5;
            var kTowns = Engine.getTowns().filter(function(t) { return t.kingdomId === player.militaryKingdomId; });
            for (var kt = 0; kt < kTowns.length; kt++) {
                kTowns[kt].garrison = (kTowns[kt].garrison || 0) + 20;
            }
        } else if (chosen.effect === 'blockade') {
            if (enemyK) {
                enemyK.gold = Math.floor((enemyK.gold || 0) * 0.9);
            }
        }
        
        player.militaryLeader.warCouncilDecisions = (player.militaryLeader.warCouncilDecisions || 0) + 1;
        player.reputation[player.militaryKingdomId] = Math.min(100, (player.reputation[player.militaryKingdomId] || 50) + 8);
        grantXP(20, 'war council');
        
        Engine.logEvent(player.fullName + ' advised the War Council: ' + chosen.name + ' against ' + (enemyK ? enemyK.name : 'the enemy') + '!');
        return { success: true, message: '📋 War Council: Advised "' + chosen.name + '" — ' + chosen.desc + '. +8 reputation.' };
    }

    function fightDecisiveBattle() {
        if (!player.militaryLeader || !player.militaryLeader.active) return { success: false, message: 'Not a military leader.' };
        if (player.militaryLeader.heroOfAgesEarned) return { success: false, message: 'You have already earned the Hero of the Ages title!' };
        
        var ranks = CONFIG.MILITARY_LEADER_RANKS || [];
        var rankIdx = ranks.findIndex(function(r) { return r.id === player.militaryLeader.rank; });
        if (rankIdx < 5) return { success: false, message: 'Must be General to attempt the decisive battle. Current: ' + (ranks[rankIdx] ? ranks[rankIdx].name : player.militaryLeader.rank) };
        
        if ((player.militaryLeader.victoriesAsLeader || 0) < 10) {
            return { success: false, message: 'Need 10+ victories as leader. Current: ' + (player.militaryLeader.victoriesAsLeader || 0) };
        }
        
        var playerK = Engine.findKingdom(player.militaryKingdomId);
        if (!playerK || !playerK.atWar || (Array.isArray(playerK.atWar) ? playerK.atWar.length === 0 : true)) {
            return { success: false, message: 'Your kingdom must be at war for the decisive battle.' };
        }
        
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.decisive_battle || 60);
        
        var rng = Engine.getRng();
        var atWarArr = Array.isArray(playerK.atWar) ? playerK.atWar : [playerK.atWar];
        var enemyId = atWarArr[rng.randInt(0, atWarArr.length - 1)];
        var enemyK = Engine.findKingdom(enemyId);
        
        // Epic multi-phase battle
        var playerScore = 0;
        var enemyScore = 0;
        var phases = ['Opening Charge', 'Main Engagement', 'Flanking Maneuver', 'Final Stand'];
        var phaseLog = [];
        
        for (var phase = 0; phase < phases.length; phase++) {
            var pScore = (playerK.militaryStrength || 50) + (player.militaryLeader.trainingsDone || 0) * 0.3 + rng.randInt(0, 40);
            var eScore = (enemyK ? enemyK.militaryStrength || 50 : 50) + rng.randInt(0, 40);
            
            // Council decisions help
            pScore += (player.militaryLeader.warCouncilDecisions || 0) * 2;
            // Tactic versatility bonus
            var tacticsUsed = player.militaryLeader.tacticsUsed || {};
            if (Object.keys(tacticsUsed).length >= 3) pScore += 15;
            
            if (pScore > eScore) {
                playerScore++;
                phaseLog.push(phases[phase] + ': ✓');
            } else {
                enemyScore++;
                phaseLog.push(phases[phase] + ': ✗');
            }
        }
        
        player.militaryLeader.battlesAsLeader = (player.militaryLeader.battlesAsLeader || 0) + 1;
        
        if (playerScore >= 3) {
            // DECISIVE VICTORY — Hero of the Ages!
            player.militaryLeader.victoriesAsLeader = (player.militaryLeader.victoriesAsLeader || 0) + 1;
            player.militaryLeader.heroOfAgesEarned = true;
            player.militaryLeader.heroOfAgesDay = Engine.getDay();
            
            // Massive rewards
            var heroGold = rng.randInt(1000, 2000);
            player.gold += heroGold;
            player.stats.totalGoldEarned += heroGold;
            
            // Max reputation in your kingdom
            player.reputation[player.militaryKingdomId] = 100;
            
            // Social rank boost
            player.socialRank = player.socialRank || {};
            var currentRank = player.socialRank[player.militaryKingdomId] || 0;
            player.socialRank[player.militaryKingdomId] = Math.min(6, currentRank + 2);
            
            // Grant military skills
            player.skills.hero_of_ages = true;
            player.skills.master_tactician = true;
            player.skills.iron_will = true;
            player.skills.legendary_commander = true;
            
            // End the military quest
            player.militaryLeader.active = false;
            
            if (enemyK) {
                enemyK.militaryStrength = Math.max(5, (enemyK.militaryStrength || 50) - 30);
            }
            playerK.militaryStrength = (playerK.militaryStrength || 50) + 30;
            
            grantXP(200, 'Hero of the Ages');
            Engine.logEvent('⚔️👑 ' + player.fullName + ' won a DECISIVE BATTLE against ' + (enemyK ? enemyK.name : 'the enemy') + ' and earned the legendary title: HERO OF THE AGES!');
            
            return { success: true, message: '⚔️👑 HERO OF THE AGES! ' + phaseLog.join(', ') + '. Won ' + playerScore + '-' + enemyScore + '! Earned ' + heroGold + 'g, +2 social rank, 4 legendary skills, max reputation. Your name will echo through history!' };
        } else {
            // Failed — can try again
            grantXP(20, 'decisive battle attempt');
            
            // Injury risk on failure
            if (rng.random() < 0.4 && typeof inflictRandomInjury === 'function') {
                inflictRandomInjury('decisive battle');
            }
            
            Engine.logEvent(player.fullName + ' attempted a decisive battle against ' + (enemyK ? enemyK.name : 'the enemy') + ' but was repelled.');
            return { success: false, message: '💀 Decisive battle FAILED. ' + phaseLog.join(', ') + '. Lost ' + playerScore + '-' + enemyScore + '. Regroup and try again when ready.' };
        }
    }

    function checkMilitaryPromotion() {
        if (!player.militaryLeader || !player.militaryLeader.active) return;
        var ranks = CONFIG.MILITARY_LEADER_RANKS;
        var currentIdx = ranks.findIndex(function(r) { return r.id === player.militaryLeader.rank; });
        if (currentIdx >= ranks.length - 1) return; // already max rank
        var trainings = player.militaryLeader.trainingsDone || 0;
        var battles = player.militaryLeader.battlesAsLeader || 0;
        var victories = player.militaryLeader.victoriesAsLeader || 0;
        // Promotion thresholds per rank (trainings needed + battles/victories)
        var thresholds = [
            { trainings: 5, battles: 0 },   // recruit -> footman
            { trainings: 15, battles: 1 },   // footman -> sergeant
            { trainings: 30, battles: 3 },   // sergeant -> knight
            { trainings: 50, battles: 5 },   // knight -> captain
            { trainings: 80, battles: 10 },  // captain -> commander
            { trainings: 120, battles: 15, victories: 5 }, // commander -> general
        ];
        var req = thresholds[currentIdx] || { trainings: 999 };
        if (trainings >= req.trainings && battles >= (req.battles || 0) && victories >= (req.victories || 0)) {
            promoteMilitaryLeader();
        }
    }

    function promoteMilitaryLeader() {
        if (!player.militaryLeader || !player.militaryLeader.active) return;
        var ranks = CONFIG.MILITARY_LEADER_RANKS;
        var currentIdx = ranks.findIndex(function(r) { return r.id === player.militaryLeader.rank; });
        if (currentIdx < ranks.length - 1) {
            player.militaryLeader.rank = ranks[currentIdx + 1].id;
            if (player.militaryLeader.rank === 'general') {
                player.militaryLeader.generalSinceDay = Engine.getDay();
            }
            Engine.logEvent(player.fullName + ' has been promoted to ' + ranks[currentIdx + 1].name + '!');
        }
    }

    // Scholar actions
    function studyTown(townId) {
        if (!player.scholar || !player.scholar.active) return { success: false, message: 'Not a scholar.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        if (player.scholar.townsVisited[townId]) return { success: false, message: 'Already studied this town.' };
        var town = Engine.findTown(townId);
        if (!town) return { success: false, message: 'Town not found.' };
        var pop = town.population || 50;
        var knowledge = pop >= 200 ? 40 : (pop >= 100 ? 20 : (pop >= 50 ? 10 : 5));
        // Specialization bonus
        if (player.scholar.specialization === 'history') {
            // History scholars gain extra from old/large towns
            var historyBonus = pop >= 200 ? 15 : (pop >= 100 ? 8 : 3);
            knowledge += historyBonus;
            player.scholar.specializationKnowledge += historyBonus;
        }
        player.scholar.townsVisited[townId] = true;
        player.scholar.totalKnowledge += knowledge;
        if (town.kingdomId) {
            player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + 3);
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.study_town || 20);
        grantXP(10, 'study town');
        return { success: true, message: 'Studied ' + town.name + '! +' + knowledge + ' knowledge. Total: ' + player.scholar.totalKnowledge };
    }

    function learnFromNPC(npcId) {
        if (!player.scholar || !player.scholar.active) return { success: false, message: 'Not a scholar.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Person not found.' };
        if (player.scholar.npcsTaughtBy.indexOf(npcId) !== -1) return { success: false, message: 'Already learned from this person.' };
        var rng = Engine.getRng();
        var intelligence = (person.personality && person.personality.intelligence) || 50;
        var rel = (player.relationships[npcId] && player.relationships[npcId].level) || 0;
        var knowledge = Math.floor(2 + (intelligence + rel) / 30);
        // Specialization bonus
        if (player.scholar.specialization === 'natural_science') {
            var sciBonus = Math.floor(1 + intelligence / 25);
            knowledge += sciBonus;
            player.scholar.specializationKnowledge += sciBonus;
        }
        player.scholar.npcsTaughtBy.push(npcId);
        player.scholar.totalKnowledge += knowledge;
        player.relationships[npcId] = player.relationships[npcId] || { level: 0, type: 'acquaintance' };
        player.relationships[npcId].level = Math.min(100, player.relationships[npcId].level + 3);
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.learn_from_npc || 5);
        grantXP(3, 'learn from NPC');
        return { success: true, message: 'Learned from ' + person.firstName + '! +' + knowledge + ' knowledge.' };
    }

    function studyAtLibrary(townId) {
        if (!player.scholar || !player.scholar.active) return { success: false, message: 'Not a scholar.' };
        if (player.townId !== townId) return { success: false, message: 'You must be in this town.' };
        if (player.scholar.knowledgeGathered[townId]) return { success: false, message: 'Already studied the library here.' };
        var rng = Engine.getRng();
        var knowledge = rng.randInt(10, 20);
        // Specialization bonus
        if (player.scholar.specialization === 'economics') {
            var econBonus = rng.randInt(5, 12);
            knowledge += econBonus;
            player.scholar.specializationKnowledge += econBonus;
        }
        player.scholar.knowledgeGathered[townId] = true;
        player.scholar.totalKnowledge += knowledge;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.study_library || 15);
        grantXP(8, 'library study');
        return { success: true, message: 'Studied at the library! +' + knowledge + ' knowledge.' };
    }

    function writeNotes() {
        if (!player.scholar || !player.scholar.active) return { success: false, message: 'Not a scholar.' };
        var townCount = Object.keys(player.scholar.townsVisited).length;
        var prevProgress = player.scholar.bookProgress;
        player.scholar.bookProgress = Math.floor(player.scholar.totalKnowledge / 50);
        player.scholar.lastWriteDay = Engine.getDay();
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.write_notes || 5);
        return { success: true, message: 'Notes compiled. Book progress: ' + player.scholar.bookProgress + '. Knowledge preserved.' };
    }

    function writeGreatBook() {
        if (!player.scholar || !player.scholar.active) return { success: false, message: 'Not a scholar.' };
        var totalTowns = Engine.getTowns().length;
        var visitedCount = Object.keys(player.scholar.townsVisited).length;
        if (visitedCount < totalTowns) return { success: false, message: 'Must visit all towns first. ' + visitedCount + '/' + totalTowns };
        var required = totalTowns * 15;
        if (player.scholar.totalKnowledge < required) return { success: false, message: 'Need ' + required + ' knowledge. Have ' + player.scholar.totalKnowledge };
        if (player.gold < 200) return { success: false, message: 'Need 200g for materials.' };
        player.gold -= 200;
        player.stats.totalGoldSpent += 200;
        player.scholar.greatBookWritten = true;
        player.scholar.active = false;
        player.skills.master_scholar = true;
        player.skills.wisdom_of_ages = true;
        player.skills.polyglot = true;
        player.skills.sage_advisor = true;
        // Specialization-specific bonuses
        if (player.scholar.specialization === 'history') {
            player.skills.historian = true;
            // History book: +25 rep in all kingdoms
            var kingdoms = Engine.getKingdoms();
            for (var ki = 0; ki < kingdoms.length; ki++) {
                player.reputation[kingdoms[ki].id] = Math.min(100, (player.reputation[kingdoms[ki].id] || 50) + 25);
            }
        } else if (player.scholar.specialization === 'economics') {
            player.skills.economic_theorist = true;
            // Economics book: -10% buy prices permanently (applied via skill check elsewhere)
        } else if (player.scholar.specialization === 'natural_science') {
            player.skills.natural_philosopher = true;
            // Science book: +25% disease resistance, +10 max age
            player.maxAgeBonus = (player.maxAgeBonus || 0) + 10;
        }
        player.scholar.royaltiesActive = true;
        player.scholar.royaltiesStartDay = Engine.getDay();
        player.scholar.royaltiesPlayerId = player.firstName + '_' + player.lastName;
        player.scholar.totalRoyaltiesEarned = 0;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.write_great_book || 60);
        Engine.logEvent(player.fullName + ' has written the Great Book! Scholar\'s journey complete.');
        grantXP(200, 'great book');
        return { success: true, message: 'The Great Book is written! Master Scholar abilities unlocked!' };
    }

    function chooseScholarSpecialization(spec) {
        if (!player.scholar || !player.scholar.active) return { success: false, message: 'Not a scholar.' };
        if (player.scholar.specialization) return { success: false, message: 'Already chose specialization: ' + player.scholar.specialization };
        var valid = ['history', 'economics', 'natural_science'];
        if (valid.indexOf(spec) === -1) return { success: false, message: 'Invalid specialization. Choose: history, economics, or natural_science.' };
        player.scholar.specialization = spec;
        var labels = { history: 'History', economics: 'Economics', natural_science: 'Natural Science' };
        Engine.logEvent('📚 ' + player.fullName + ' has chosen to specialize in ' + labels[spec] + '!');
        grantXP(15, 'specialization');
        return { success: true, message: 'You now specialize in ' + labels[spec] + '! Related studies give bonus knowledge.' };
    }

    // ── Family Interaction Actions ──
    function askFamilyForMoney(npcId) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId; });
        if (!member) return { success: false, message: 'Not a family member.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Family member not found.' };
        var rel = (player.relationships[npcId] && player.relationships[npcId].level) || 0;
        if (rel < 50) return { success: false, message: member.name + ' refuses. "We\'re not that close..."' };
        var day = Engine.getDay();
        if (person._lastFamilyMoneyDay && day - person._lastFamilyMoneyDay < 30) {
            return { success: false, message: 'You already asked recently. Wait 30 days.' };
        }
        var pct = rel >= 75 ? 0.50 : (rel >= 60 ? 0.30 : 0.10);
        var amount = Math.floor((person.gold || 0) * pct);
        if (amount <= 0) return { success: false, message: member.name + ' says: "You know I\'d help you if I could..."' };
        person.gold -= amount;
        player.gold += amount;
        player.stats.totalGoldEarned += amount;
        person._lastFamilyMoneyDay = day;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.ask_family_money || 2);
        return { success: true, message: member.name + ' gave you ' + amount + 'g.' };
    }

    function askFamilyToWork(npcId) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId; });
        if (!member) return { success: false, message: 'Not a family member.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Family member not found.' };
        var rel = (player.relationships[npcId] && player.relationships[npcId].level) || 0;
        if (rel < 60) return { success: false, message: 'Relationship must be 60+ to ask for work.' };
        // Check if any family already working
        var alreadyWorking = player.familyMembers.some(function(m) {
            var p = Engine.findPerson(m.npcId);
            return p && p.employerId === 'player_family';
        });
        if (alreadyWorking) return { success: false, message: 'A family member is already working for you.' };
        person.employerId = 'player_family';
        person._familyWorkStartDay = Engine.getDay();
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.ask_family_work || 2);
        return { success: true, message: member.name + ' agrees to work for you for 30 days (50% efficiency, free).' };
    }

    function familyDinner() {
        if (!player.houses || player.houses.length === 0) return { success: false, message: 'You need a house to host dinner.' };
        var houseInTown = player.houses.find(function(h) { return h.townId === player.townId; });
        if (!houseInTown) return { success: false, message: 'No house in this town.' };
        var familyInTown = player.familyMembers.filter(function(m) {
            var p = Engine.findPerson(m.npcId);
            return p && p.alive && p.townId === player.townId;
        });
        if (familyInTown.length === 0) return { success: false, message: 'No family members in this town.' };
        for (var fi = 0; fi < familyInTown.length; fi++) {
            var fId = familyInTown[fi].npcId;
            player.relationships[fId] = player.relationships[fId] || { level: 0, type: 'family' };
            player.relationships[fId].level = Math.min(100, player.relationships[fId].level + 5);
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.family_dinner || 10);
        return { success: true, message: 'Family dinner! +5 relationship with ' + familyInTown.length + ' family members.' };
    }

    function teachFamilyTrade(npcId) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId; });
        if (!member) return { success: false, message: 'Not a family member.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Family member not found.' };
        person._familyTrainingSessions = (person._familyTrainingSessions || 0) + 1;
        person.workerSkill = Math.min(100, (person.workerSkill || 0) + 5);
        if (person._familyTrainingSessions >= 10) {
            person._familyTrained = true;
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.teach_family_trade || 5);
        return { success: true, message: 'Teaching session with ' + member.name + '. Skill: ' + person.workerSkill + ' (' + person._familyTrainingSessions + '/10 sessions).' };
    }

    function askFamilyAdvice() {
        if (player.familyMembers.length === 0) return { success: false, message: 'No family.' };
        var tips = [
            'Buy low in farming towns, sell high in cities.',
            'The king values merchants who supply the military.',
            'Building a warehouse early saves money on storage fees.',
            'Reputation opens doors that gold cannot.',
            'Watch the seasonal price changes — winter wheat is expensive!',
            'Making friends with the tavern keeper reveals trade secrets.',
            'Don\'t carry too much gold when traveling through bandit territory.',
            'A good spouse can boost your business significantly.'
        ];
        var rng = Engine.getRng();
        var tip = tips[rng.randInt(0, tips.length - 1)];
        var parent = player.familyMembers.find(function(m) { return m.role === 'father' || m.role === 'mother'; });
        var name = parent ? parent.name : 'Your family';
        if (parent) {
            player.relationships[parent.npcId] = player.relationships[parent.npcId] || { level: 0, type: 'family' };
            player.relationships[parent.npcId].level = Math.min(100, player.relationships[parent.npcId].level + 2);
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.ask_family_advice || 2);
        return { success: true, message: name + ' says: "' + tip + '"' };
    }

    function borrowFamilyConnections(npcId) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId; });
        if (!member) return { success: false, message: 'Not a family member.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Family member not found.' };
        var day = Engine.getDay();
        if (person._lastConnectionDay && day - person._lastConnectionDay < 60) {
            return { success: false, message: 'Must wait 60 days between connection requests.' };
        }
        // Find an NPC the family member knows well
        var townPeople = Engine.getPeople(person.townId);
        var candidates = townPeople.filter(function(p) {
            return p.id !== npcId && !player.relationships[p.id] && (p.isEliteMerchant || p.occupation === 'merchant');
        });
        if (candidates.length === 0) return { success: false, message: 'No useful connections available.' };
        var rng = Engine.getRng();
        var target = rng.pick(candidates);
        player.relationships[target.id] = { level: 15, type: 'introduction' };
        person._lastConnectionDay = day;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.borrow_family_connections || 3);
        return { success: true, message: member.name + ' introduced you to ' + target.firstName + '! +15 relationship.' };
    }

    function familyCelebration() {
        if (!player.houses || player.houses.length === 0) return { success: false, message: 'Need a house.' };
        var houseInTown = player.houses.find(function(h) { return h.townId === player.townId; });
        if (!houseInTown) return { success: false, message: 'No house in this town.' };
        var ht = CONFIG.HOUSING_TYPES.find(function(h) { return h.id === houseInTown.type; });
        var cost = ht ? Math.floor(20 + (ht.comfort || 0)) : 50;
        if (player.gold < cost) return { success: false, message: 'Need ' + cost + 'g for celebration.' };
        player.gold -= cost;
        player.stats.totalGoldSpent += cost;
        for (var fi = 0; fi < player.familyMembers.length; fi++) {
            var fId = player.familyMembers[fi].npcId;
            player.relationships[fId] = player.relationships[fId] || { level: 0, type: 'family' };
            player.relationships[fId].level = Math.min(100, player.relationships[fId].level + 10);
        }
        var town = Engine.findTown(player.townId);
        if (town) {
            player.townReputation = player.townReputation || {};
            player.townReputation[player.townId] = Math.min(100, (player.townReputation[player.townId] || 0) + 5);
        }
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.family_celebration || 15);
        return { success: true, message: 'Family celebration! +10 family relationship, +5 town reputation. Cost: ' + cost + 'g.' };
    }

    function giveFamilyGift(npcId, resourceId, qty) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId; });
        if (!member) return { success: false, message: 'Not a family member.' };
        if (!player.inventory[resourceId] || player.inventory[resourceId] < qty) return { success: false, message: 'Not enough resources.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Family member not found.' };
        player.inventory[resourceId] -= qty;
        var res = findResource(resourceId);
        var value = res ? res.basePrice * qty : qty;
        var relBoost = Math.min(20, Math.floor(value / 10));
        player.relationships[npcId] = player.relationships[npcId] || { level: 0, type: 'family' };
        player.relationships[npcId].level = Math.min(100, player.relationships[npcId].level + relBoost);
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.give_family_gift || 2);
        return { success: true, message: 'Gave ' + qty + 'x ' + (res ? res.name : resourceId) + ' to ' + member.name + '. +' + relBoost + ' relationship.' };
    }

    function inviteFamilyToLive(npcId) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId; });
        if (!member) return { success: false, message: 'Not a family member.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Family member not found.' };
        var houseInTown = player.houses.find(function(h) { return h.townId === player.townId; });
        if (!houseInTown) return { success: false, message: 'No house in this town.' };
        var ht = CONFIG.HOUSING_TYPES.find(function(h) { return h.id === houseInTown.type; });
        var maxOcc = ht ? ht.maxOccupants : 2;
        if (houseInTown.occupants.length >= maxOcc) return { success: false, message: 'House is full.' };
        person.townId = player.townId;
        houseInTown.occupants.push(npcId);
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.invite_family_live || 2);
        return { success: true, message: member.name + ' has moved to your town!' };
    }

    function familyBusiness(npcId) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId && (m.role === 'brother' || m.role === 'sister'); });
        if (!member) return { success: false, message: 'Must be a sibling.' };
        var person = Engine.findPerson(npcId);
        if (!person || !person.alive) return { success: false, message: 'Family member not found.' };
        if (person._familyBusinessActive) return { success: false, message: 'Already in a family business partnership.' };
        var sibGold = Math.floor((person.gold || 0) * 0.5);
        person.gold -= sibGold;
        person._familyBusinessActive = true;
        person._familyBusinessInvestment = sibGold;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.family_business || 5);
        return { success: true, message: 'Business partnership with ' + member.name + '! They invested ' + sibGold + 'g. Profits split 60/40.' };
    }

    function confideInFamily(npcId) {
        var member = player.familyMembers.find(function(m) { return m.npcId === npcId; });
        if (!member) return { success: false, message: 'Not a family member.' };
        var rel = (player.relationships[npcId] && player.relationships[npcId].level) || 0;
        if (rel < 70) return { success: false, message: 'Need 70+ relationship to confide.' };
        player.relationships[npcId].level = Math.min(100, player.relationships[npcId].level + 3);
        var rng = Engine.getRng();
        var secrets = [
            'I heard the market for wheat is about to surge.',
            'The king is planning new taxes on luxury goods.',
            'A new trade route may open soon.',
            'Watch out for bandits on the southern road.',
            'The harvest looks poor this season.',
            'A wealthy merchant is looking for business partners.'
        ];
        var secret = secrets[rng.randInt(0, secrets.length - 1)];
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.confide_family || 3);
        return { success: true, message: member.name + ' shares: "' + secret + '" +3 relationship.' };
    }

    function askFamilyToCaretake() {
        if (player.familyMembers.length === 0) return { success: false, message: 'No family.' };
        var available = player.familyMembers.find(function(m) {
            var p = Engine.findPerson(m.npcId);
            return p && p.alive && p.townId === player.townId;
        });
        if (!available) return { success: false, message: 'No family member in town.' };
        var rel = (player.relationships[available.npcId] && player.relationships[available.npcId].level) || 0;
        var cost = rel >= 60 ? 0 : 5;
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(CONFIG.ACTION_TICK_COSTS.ask_family_caretake || 2);
        return { success: true, message: available.name + ' agrees to caretake.' + (cost > 0 ? ' Cost: ' + cost + 'g/day.' : ' Free!') };
    }

    // Shipwrecked price modifier (called from trade functions)
    function getShipwreckedPriceModifier() {
        if (!player.shipwrecked || !player.shipwrecked.active) return 1.0;
        var lang = player.shipwrecked.languageSkill;
        if (lang < 30) return 1.40;
        if (lang < 60) return 1.20;
        if (lang < 90) return 1.10;
        return 1.0;
    }

    // Artifact luck bonus check
    function hasArtifactLuckBonus() {
        return player.shipwrecked && player.shipwrecked.artifactKept && player.inventory.exotic_artifact > 0;
    }

    // ========================================================
    // §12F BANKRUPTCY SYSTEM
    // ========================================================

    function checkBankruptcy() {
        // Don't check during special states that already manage the player's finances
        if (player.bankruptcy && player.bankruptcy.active) return;
        if (!player.alive) return;
        if (player.regencyMode) return;

        if (player.gold <= 0) {
            player.bankruptDays = (player.bankruptDays || 0) + 1;

            // Warning at day 3
            if (player.bankruptDays === 3) {
                Engine.logEvent('⚠️ WARNING: You have been in debt for 3 days. If you remain broke for 4 more days, the kingdom will intervene!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('⚠️ Debt warning! 4 days until bankruptcy.', 'warning', 'critical');
            }
            // Warning at day 5
            if (player.bankruptDays === 5) {
                Engine.logEvent('⚠️ CRITICAL: 2 days until bankruptcy! Find gold immediately!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('🚨 2 days until bankruptcy!', 'danger', 'critical');
            }

            // Trigger bankruptcy at 7 days
            if (player.bankruptDays >= 7) {
                triggerBankruptcy();
            }
        } else {
            if (player.bankruptDays > 0) {
                player.bankruptDays = 0;
            }
        }
    }

    function triggerBankruptcy() {
        if (typeof Game !== 'undefined' && Game.setSpeed) Game.setSpeed(0);

        var assetValue = calculateAssetValue();

        if (assetValue > 0) {
            // Phase 1: Seize assets, give 25% back
            var returnedGold = seizeBankruptAssets();
            player.gold += returnedGold;
            player.bankruptDays = 0;

            Engine.logEvent('💸 BANKRUPTCY! The kingdom has seized all your assets. You received ' + returnedGold + 'g (25% of value) in compensation.');
            if (typeof UI !== 'undefined' && UI.toast) {
                UI.toast('💸 Assets seized! ' + returnedGold + 'g returned.', 'danger', 'critical');
            }

            if (typeof Game !== 'undefined' && Game.setSpeed) Game.setSpeed(1);
        } else {
            // Phase 2: No assets — show choice dialog
            Engine.logEvent('💸 BANKRUPTCY! You own nothing and cannot pay your debts. The kingdom demands you choose your fate.');

            var choices = getBankruptcyChoices();

            if (typeof UI !== 'undefined' && UI.showBankruptcyDialog) {
                UI.showBankruptcyDialog(Math.abs(player.gold), choices);
            } else {
                handleBankruptcyChoice('indenture');
            }
        }
    }

    function calculateAssetValue() {
        var value = 0;

        for (var i = 0; i < player.buildings.length; i++) {
            var bld = player.buildings[i];
            if (!bld.active) continue;
            var bt = Engine.findBuildingType(bld.type);
            if (bt) value += bt.cost * (bld.level || 1);
        }

        for (var resId in player.inventory) {
            var qty = player.inventory[resId];
            if (qty <= 0) continue;
            var res = findResource(resId);
            if (res) value += res.basePrice * qty;
        }

        for (var townId in player.townStorage) {
            var storage = player.townStorage[townId];
            for (var resId2 in storage) {
                var qty2 = storage[resId2];
                if (qty2 <= 0) continue;
                var res2 = findResource(resId2);
                if (res2) value += res2.basePrice * qty2;
            }
        }

        if (player.houses) {
            for (var h = 0; h < player.houses.length; h++) {
                value += 200;
            }
        }

        if (player.ships) {
            for (var s = 0; s < player.ships.length; s++) {
                var ship = player.ships[s];
                var st = CONFIG.SHIP_TYPES ? CONFIG.SHIP_TYPES[ship.type] : null;
                if (st) value += st.cost * ((ship.condition || 100) / 100);
            }
        }

        for (var c = 0; c < player.caravans.length; c++) {
            var caravan = player.caravans[c];
            if (!caravan.active) continue;
            if (caravan.goods) {
                for (var gResId in caravan.goods) {
                    var gQty = caravan.goods[gResId];
                    var gRes = findResource(gResId);
                    if (gRes) value += gRes.basePrice * gQty;
                }
            }
        }

        if (player.weapon) value += 50;
        if (player.armor) value += 75;

        return Math.floor(value);
    }

    function seizeBankruptAssets() {
        var totalValue = 0;

        // Seize buildings and fire their workers
        for (var i = player.buildings.length - 1; i >= 0; i--) {
            var bld = player.buildings[i];
            if (!bld.active) continue;
            var bt = Engine.findBuildingType(bld.type);
            if (bt) totalValue += bt.cost * (bld.level || 1);
            bld.active = false;
            if (bld.workers) {
                for (var w = 0; w < bld.workers.length; w++) {
                    var wPerson = Engine.findPerson(bld.workers[w]);
                    if (wPerson) wPerson.employerId = null;
                }
                bld.workers = [];
            }
        }

        // Fire all remaining employees
        for (var e = 0; e < player.employees.length; e++) {
            var emp = Engine.findPerson(player.employees[e]);
            if (emp) emp.employerId = null;
        }
        player.employees = [];

        // Seize inventory
        for (var resId in player.inventory) {
            var qty = player.inventory[resId];
            if (qty <= 0) continue;
            var res = findResource(resId);
            if (res) totalValue += res.basePrice * qty;
        }
        player.inventory = {};

        // Seize town storage
        for (var townId in player.townStorage) {
            var storage = player.townStorage[townId];
            for (var resId2 in storage) {
                var qty2 = storage[resId2];
                if (qty2 <= 0) continue;
                var res2 = findResource(resId2);
                if (res2) totalValue += res2.basePrice * qty2;
            }
        }
        player.townStorage = {};

        // Seize houses
        if (player.houses && player.houses.length > 0) {
            totalValue += player.houses.length * 200;
            player.houses = [];
            player.primaryHouseId = null;
        }

        // Seize ships
        if (player.ships && player.ships.length > 0) {
            for (var s = 0; s < player.ships.length; s++) {
                var ship = player.ships[s];
                var st = CONFIG.SHIP_TYPES ? CONFIG.SHIP_TYPES[ship.type] : null;
                if (st) totalValue += st.cost * ((ship.condition || 100) / 100);
            }
            player.ships = [];
        }

        // Seize caravans and their goods
        for (var c = player.caravans.length - 1; c >= 0; c--) {
            var caravan = player.caravans[c];
            if (!caravan.active) continue;
            if (caravan.goods) {
                for (var gResId in caravan.goods) {
                    var gQty = caravan.goods[gResId];
                    var gRes = findResource(gResId);
                    if (gRes) totalValue += gRes.basePrice * gQty;
                }
            }
            caravan.active = false;
        }
        player.caravans = player.caravans.filter(function(c) { return c.active; });

        // Seize weapon and armor
        if (player.weapon) { totalValue += 50; player.weapon = null; }
        if (player.armor) { totalValue += 75; player.armor = null; }

        return Math.floor(totalValue * 0.25);
    }

    function getBankruptcyChoices() {
        var choices = [];

        // Option 1: Indenture to elite merchant (always available if merchants exist)
        var people = Engine.getPeople();
        var eliteMerchants = people.filter(function(p) { return p.isEliteMerchant && p.alive; });
        choices.push({
            id: 'indenture',
            available: eliteMerchants.length > 0,
            label: '⛓️ Indentured Servant',
            description: 'An elite merchant pays off your debt. You owe them your debt plus 1,000g. Serve until you can pay it off or find another way out.',
            detail: 'Debt: ' + (Math.abs(player.gold) + 1000) + 'g | Same escape options as servant start'
        });

        // Option 2: Military enlistment (requires active war)
        var wars = Engine.getActiveWars ? Engine.getActiveWars() : {};
        var hasWar = false;
        var warKingdomId = null;

        // Check player's citizenship kingdom
        for (var wId in wars) {
            var w = wars[wId];
            if (w.kingdomA === player.citizenshipKingdomId || w.kingdomB === player.citizenshipKingdomId) {
                hasWar = true;
                warKingdomId = player.citizenshipKingdomId;
                break;
            }
        }

        // Fallback: check player's current town's kingdom
        if (!hasWar && player.townId) {
            var bkTown = Engine.findTown(player.townId);
            var bkTownKingdom = bkTown ? bkTown.kingdomId : null;
            if (bkTownKingdom && bkTownKingdom !== player.citizenshipKingdomId) {
                for (var wId1b in wars) {
                    var w1b = wars[wId1b];
                    if (w1b.kingdomA === bkTownKingdom || w1b.kingdomB === bkTownKingdom) {
                        hasWar = true;
                        warKingdomId = bkTownKingdom;
                        break;
                    }
                }
            }
        }

        // Fallback: check kingdom atWar sets directly
        if (!hasWar) {
            var bkKingdoms = Engine.getKingdoms ? Engine.getKingdoms() : [];
            var playerKIds = [player.citizenshipKingdomId];
            if (player.townId) {
                var bkT2 = Engine.findTown(player.townId);
                if (bkT2 && bkT2.kingdomId) playerKIds.push(bkT2.kingdomId);
            }
            for (var pki = 0; pki < playerKIds.length && !hasWar; pki++) {
                if (!playerKIds[pki]) continue;
                for (var bki = 0; bki < bkKingdoms.length; bki++) {
                    if (bkKingdoms[bki].id === playerKIds[pki] && bkKingdoms[bki].atWar && bkKingdoms[bki].atWar.size > 0) {
                        hasWar = true;
                        warKingdomId = playerKIds[pki];
                        break;
                    }
                }
            }
        }

        // Last resort: any war at all
        if (!hasWar) {
            for (var wId2 in wars) {
                hasWar = true;
                warKingdomId = wars[wId2].kingdomA;
                break;
            }
        }
        choices.push({
            id: 'military',
            available: hasWar,
            warKingdomId: warKingdomId,
            label: '⚔️ Military Enlistment',
            description: 'The army forgives your debt in exchange for 4 years of mandatory military service. Risk death in battle but earn soldier\'s pay.',
            detail: 'Service: 4 years | Debt: forgiven' + (!hasWar ? ' | ⚠️ No active wars — unavailable' : '')
        });

        // Option 3: Join the church (always available)
        choices.push({
            id: 'priest',
            available: true,
            label: '🙏 Join the Church',
            description: 'Take holy vows as a priest. Your debt is forgiven, but you cannot own businesses, hire workers, or own buildings until you complete a pilgrimage.',
            detail: 'Debt: forgiven | Must complete pilgrimage to regain full freedoms'
        });

        return choices;
    }

    function handleBankruptcyChoice(choice) {
        var debtAmount = Math.abs(player.gold);
        player.bankruptDays = 0;

        if (choice === 'indenture') {
            initBankruptcyIndenture(debtAmount);
        } else if (choice === 'military') {
            initBankruptcyMilitary();
        } else if (choice === 'priest') {
            initBankruptcyPriest();
        }

        player.bankruptcy = {
            active: true,
            type: choice,
            debtAmount: debtAmount,
            startDay: Engine.getDay(),
            assetSeizureDay: Engine.getDay()
        };
    }

    function initBankruptcyIndenture(debtAmount) {
        var rng = Engine.getRng();
        var people = Engine.getPeople();
        var eliteMerchants = people.filter(function(p) { return p.isEliteMerchant && p.alive; });
        var masterId = eliteMerchants.length > 0 ? rng.pick(eliteMerchants).id : null;

        var pool = CONFIG.INDENTURED_ESCAPE_POOL.slice();
        var numEscapes = rng.randInt(8, 10);
        var selected = [];
        for (var i = 0; i < numEscapes && pool.length > 0; i++) {
            var idx = rng.randInt(0, pool.length - 1);
            selected.push(pool[idx].id);
            pool.splice(idx, 1);
        }

        var totalDebt = debtAmount + 1000;
        var contractDays = Math.max(365, Math.floor(totalDebt / 2000 * 365));

        player.indentured = {
            active: true,
            masterId: masterId,
            startDay: Engine.getDay(),
            contractDays: contractDays,
            debtRemaining: totalDebt,
            discoveredEscapes: [],
            availableEscapes: selected,
            currentTask: null,
            taskHistory: [],
            consecutiveFailures: 0,
            totalTasksCompleted: 0,
            totalTasksFailed: 0,
            lastTaskDay: Engine.getDay(),
            nextTaskDay: Engine.getDay() + 15,
            masterRelationship: 30
        };

        player.gold = 0;

        if (masterId) {
            var master = Engine.findPerson(masterId);
            if (master && master.townId) {
                player.townId = master.townId;
                var masterTown = Engine.findTown(master.townId);
                var masterName = master.firstName + ' ' + master.lastName;
                Engine.logEvent('⛓️ ' + masterName + ' has paid off your debts. You now owe them ' + totalDebt + 'g. You must serve as their indentured servant in ' + (masterTown ? masterTown.name : 'their town') + '.');
            }
        }

        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast('⛓️ You are now an indentured servant. Debt: ' + totalDebt + 'g', 'danger');
        }
    }

    function initBankruptcyMilitary() {
        var wars = Engine.getActiveWars ? Engine.getActiveWars() : {};
        var kingdomId = null;

        for (var wId in wars) {
            var w = wars[wId];
            if (w.kingdomA === player.citizenshipKingdomId || w.kingdomB === player.citizenshipKingdomId) {
                kingdomId = player.citizenshipKingdomId;
                break;
            }
        }
        if (!kingdomId) {
            for (var wId2 in wars) {
                kingdomId = wars[wId2].kingdomA;
                break;
            }
        }

        if (!kingdomId) {
            Engine.logEvent('⚠️ No wars available for enlistment. Defaulting to church.');
            initBankruptcyPriest();
            return;
        }

        player.gold = 0;

        player.militaryActive = true;
        player.militaryKingdomId = kingdomId;
        player.militaryDayEnlisted = Engine.getDay();
        if (!player.militaryRank) player.militaryRank = 'militiaman';
        player.militaryMandatory = true;
        player.militaryServiceEndDay = Engine.getDay() + 1460;

        var rng = Engine.getRng();
        player.militaryNextBattleDay = Engine.getDay() + (rng ? rng.randInt(3, 5) : 4);

        var kName = Engine.findKingdom(kingdomId) ? Engine.findKingdom(kingdomId).name : 'the kingdom';
        Engine.logEvent('⚔️ ' + player.fullName + ' has been conscripted into ' + kName + '\'s army to pay off debts. 4 years of mandatory military service begins.');
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast('⚔️ Conscripted! 4-year military service. Debt forgiven.', 'warning', 'critical');
        }
    }

    function initBankruptcyPriest() {
        player.gold = 0;

        var rng = Engine.getRng();
        var towns = Engine.getTowns();

        var numSites = rng.randInt(5, 8);
        var holySiteIds = [];
        var kingdoms = Engine.getKingdoms();
        var shuffledTowns = towns.slice().sort(function() { return rng.random() - 0.5; });
        var usedKingdoms = {};
        for (var ti = 0; ti < shuffledTowns.length && holySiteIds.length < numSites; ti++) {
            var t = shuffledTowns[ti];
            if (!usedKingdoms[t.kingdomId] || holySiteIds.length >= kingdoms.length) {
                t.holySite = true;
                holySiteIds.push(t.id);
                usedKingdoms[t.kingdomId] = true;
            }
        }

        var allGoals = ['visit_all_sites', 'convert_50_followers', 'build_temple'];
        var goals = [];
        var shuffledGoals = allGoals.slice().sort(function() { return rng.random() - 0.5; });
        goals.push(shuffledGoals[0], shuffledGoals[1]);

        player.pilgrim = {
            active: true,
            holySites: holySiteIds,
            visitedSites: [],
            followers: 0,
            sermonsGiven: 0,
            conversionAttempts: 0,
            goals: goals,
            followerNpcs: {},
            goalsCompleted: 0,
            templeBuilt: false,
            donations: 0,
            bankruptcyPriest: true
        };

        Engine.logEvent('🙏 ' + player.fullName + ' has taken holy vows as a priest. Your debts are forgiven, but you must complete a pilgrimage before owning businesses, hiring workers, or owning buildings.');
        if (typeof UI !== 'undefined' && UI.toast) {
            UI.toast('🙏 Joined the church. Complete pilgrimage to regain freedoms.', 'warning');
        }
    }

    function isBankruptcyPriestRestricted() {
        return player.pilgrim && player.pilgrim.active && player.pilgrim.bankruptcyPriest === true;
    }

    // ========================================================
    // §12G  COMBAT LEVEL SYSTEM
    // ========================================================
    function getCombatLevel() {
        var level = 0;
        // Combat job experience contributes
        var arenaExp = player.jobExperience.arena_fighter || 0;
        var tournExp = player.jobExperience.tournament || 0;
        var guardExp = (player.jobExperience.town_guard || 0) + (player.jobExperience.castle_guard || 0);
        var soldierExp = player.jobExperience.temp_soldier || 0;
        var privateerExp = player.jobExperience.privateer || 0;
        var nightWatchExp = player.jobExperience.night_watchman || 0;
        level += Math.min(30, arenaExp * 0.8);       // up to 30 from arena (cap ~37 days)
        level += Math.min(20, tournExp * 1.5);        // up to 20 from tournament
        level += Math.min(15, guardExp * 0.3);        // up to 15 from guard work
        level += Math.min(10, soldierExp * 0.3);
        level += Math.min(15, privateerExp * 0.5);
        level += Math.min(5, nightWatchExp * 0.2);

        // Military rank contributes
        if (player.militaryRank) {
            var ri = MILITARY_RANKS.indexOf(player.militaryRank);
            level += (ri + 1) * 8; // militiaman: 8, footman: 16, sergeant: 24, knight: 32
        }
        // Battles survived contribute
        level += Math.min(20, (player.battlesSurvived || 0) * 0.5);

        // Combat skills contribute
        if (hasSkill('combat_trained')) level += 10;
        if (hasSkill('battle_hardened')) level += 15; // replaces combat_trained in effect, stacks for level
        if (hasSkill('street_smart')) level += 3;
        if (hasSkill('intimidating_presence')) level += 5;

        // Equipment contributes
        if (player.weapon) level += (player.weapon.combatBonus || 0.2) * 30; // ~6 for basic, higher for quality
        if (player.armor) level += (player.armor.combatBonus || 0.3) * 25;   // ~7.5 for basic

        return Math.min(100, Math.round(level));
    }

    // ========================================================
    // §12H  PRIVATEER LOOT SYSTEM
    // ========================================================
    var PRIVATEER_LOOT_TABLE = [
        // Common loot (60% total chance, lower value)
        { id: 'cloth', qty: [2, 6], weight: 20, name: 'Bolts of cloth' },
        { id: 'wine', qty: [1, 4], weight: 15, name: 'Barrels of wine' },
        { id: 'salt', qty: [3, 8], weight: 10, name: 'Sacks of salt' },
        { id: 'rope', qty: [2, 5], weight: 8, name: 'Coils of rope' },
        { id: 'fish', qty: [3, 10], weight: 7, name: 'Crates of fish' },
        // Uncommon loot (25% total chance, medium value)
        { id: 'iron', qty: [1, 3], weight: 8, name: 'Iron bars' },
        { id: 'leather', qty: [2, 5], weight: 6, name: 'Fine leather' },
        { id: 'silk', qty: [1, 3], weight: 5, name: 'Silk fabric' },
        { id: 'tools', qty: [1, 2], weight: 4, name: 'Toolsets' },
        { id: 'perfume', qty: [1, 2], weight: 2, name: 'Exotic perfume' },
        // Rare loot (12% total chance, high value)
        { id: 'jewelry', qty: [1, 2], weight: 4, name: 'Stolen jewelry' },
        { id: 'swords', qty: [1, 3], weight: 3, name: 'Enemy swords' },
        { id: 'armor', qty: [1, 2], weight: 2, name: 'Enemy armor' },
        { id: 'gold_ore', qty: [1, 3], weight: 2, name: 'Gold ore' },
        { id: 'pearls', qty: [1, 3], weight: 1, name: 'Pearls' },
        // Legendary loot (3% total chance, very high value)
        { id: 'swords_good', qty: [1, 1], weight: 1, name: 'A fine enemy blade' },
        { id: 'armor_good', qty: [1, 1], weight: 0.5, name: 'Quality captured armor' },
        { id: 'gold_goblet', qty: [1, 2], weight: 0.5, name: 'Gold goblets' },
        { id: 'pearl_jewelry', qty: [1, 1], weight: 0.5, name: 'Pearl jewelry' },
        { id: 'tapestry', qty: [1, 1], weight: 0.5, name: 'A fine tapestry' },
    ];

    function rollPrivateerLoot(rng) {
        // Base chance of finding loot: 40%, up to 70% with skills
        var lootChance = 0.40;
        if (hasSkill('expert_navigator') || hasSkill('fleet_admiral')) lootChance += 0.10;
        if (hasSkill('street_smart')) lootChance += 0.05;
        if (hasSkill('war_profiteer')) lootChance += 0.10;
        if (hasSkill('combat_trained') || hasSkill('battle_hardened')) lootChance += 0.05;

        if (rng.random() > lootChance) return ''; // no loot this time

        // Pick loot using weighted random
        var totalWeight = 0;
        for (var i = 0; i < PRIVATEER_LOOT_TABLE.length; i++) totalWeight += PRIVATEER_LOOT_TABLE[i].weight;
        var roll = rng.random() * totalWeight;
        var cumulative = 0;
        var loot = PRIVATEER_LOOT_TABLE[0];
        for (var j = 0; j < PRIVATEER_LOOT_TABLE.length; j++) {
            cumulative += PRIVATEER_LOOT_TABLE[j].weight;
            if (roll <= cumulative) { loot = PRIVATEER_LOOT_TABLE[j]; break; }
        }

        var qty = rng.randInt(loot.qty[0], loot.qty[1]);

        // Bonus pay roll: 10-40% of base pay as extra gold (affected by war_profiteer)
        var bonusPay = 0;
        var bonusChance = 0.30;
        if (hasSkill('war_profiteer')) bonusChance = 0.50;
        if (rng.random() < bonusChance) {
            bonusPay = rng.randInt(5, 25);
            if (hasSkill('war_profiteer')) bonusPay = Math.round(bonusPay * 1.25);
            player.gold += bonusPay;
            player.stats.totalGoldEarned += bonusPay;
        }

        // Try to give the loot to the player
        var placed = givePlayerLoot(loot.id, qty);
        var res = findResource(loot.id);
        var resName = res ? res.name : loot.id;

        var msg = ' 🏴‍☠️ Loot: ' + qty + 'x ' + resName;
        if (!placed) {
            var goldValue = res ? Math.round(res.basePrice * qty * 0.75) : qty * 10;
            player.gold += goldValue;
            player.stats.totalGoldEarned += goldValue;
            msg += ' (sold for ' + goldValue + 'g — no storage room)';
        }
        if (bonusPay > 0) msg += ' + ' + bonusPay + 'g bonus plunder';

        Engine.logEvent('🏴‍☠️ Privateer loot: ' + qty + 'x ' + resName + (bonusPay > 0 ? ' + ' + bonusPay + 'g bonus' : '') + (!placed ? ' (converted to gold)' : ''));
        if (typeof UI !== 'undefined' && UI.toast) UI.toast('🏴‍☠️ Found loot: ' + qty + 'x ' + resName + '!', 'success', 'combat');

        return msg;
    }

    function givePlayerLoot(resourceId, qty) {
        var res = findResource(resourceId);
        var weight = res ? (res.weight || 1) : 1;
        var totalWeight = qty * weight;

        // Try 1: Player inventory (if has carry capacity)
        var carriedWeight = getCarriedWeight();
        var carryCapacity = getCarryCapacity();
        if (carriedWeight + totalWeight <= carryCapacity) {
            player.inventory[resourceId] = (player.inventory[resourceId] || 0) + qty;
            return true;
        }

        // Try 2: Town storage in current town
        if (player.townId) {
            var storageCap = getTownStorageCapacity(player.townId);
            var storageUsed = getTownStorageUsed(player.townId);
            if (storageUsed + totalWeight <= storageCap) {
                if (!player.townStorage[player.townId]) player.townStorage[player.townId] = {};
                player.townStorage[player.townId][resourceId] = (player.townStorage[player.townId][resourceId] || 0) + qty;
                return true;
            }
        }

        // Try 3: Any town storage the player has
        for (var tid in player.townStorage) {
            var cap = getTownStorageCapacity(tid);
            var used = getTownStorageUsed(tid);
            if (used + totalWeight <= cap) {
                player.townStorage[tid][resourceId] = (player.townStorage[tid][resourceId] || 0) + qty;
                return true;
            }
        }

        // Try 4: Check all towns where player has buildings with storage
        for (var bi = 0; bi < player.buildings.length; bi++) {
            var bld = player.buildings[bi];
            var bTid = bld.townId;
            if (player.townStorage[bTid]) continue; // already checked
            var bCap = getTownStorageCapacity(bTid);
            if (bCap > 0) {
                if (!player.townStorage[bTid]) player.townStorage[bTid] = {};
                var bUsed = getTownStorageUsed(bTid);
                if (bUsed + totalWeight <= bCap) {
                    player.townStorage[bTid][resourceId] = (player.townStorage[bTid][resourceId] || 0) + qty;
                    return true;
                }
            }
        }

        // Try 5: Home storage
        for (var hi = 0; hi < (player.houses || []).length; hi++) {
            var house = player.houses[hi];
            if (house.homeStorage) {
                var htInfo = CONFIG.HOUSING_TYPES ? CONFIG.HOUSING_TYPES.find(function(x) { return x.id === house.type; }) : null;
                var hCap = htInfo ? (htInfo.storage || 0) : 10;
                var hUsed = 0;
                for (var hRes in house.homeStorage) hUsed += (house.homeStorage[hRes] || 0);
                if (hUsed + qty <= hCap) {
                    house.homeStorage[resourceId] = (house.homeStorage[resourceId] || 0) + qty;
                    return true;
                }
            }
        }

        // No room anywhere — caller will convert to gold
        return false;
    }

    // ========================================================
    // §12H-2  SPY EVENT SYSTEM
    // ========================================================
    function rollSpyEvent(rng) {
        var town = Engine.findTown(player.townId);
        if (!town) return '';
        var kingdom = Engine.findKingdom(town.kingdomId);
        if (!kingdom) return '';

        // Event chances — skills increase odds
        var eventChance = 0.25; // 25% base chance of a special event
        if (hasSkill('discrete')) eventChance += 0.05;
        if (hasSkill('master_smuggler')) eventChance += 0.05;
        if (hasSkill('combat_trained') || hasSkill('battle_hardened')) eventChance += 0.03;
        if (hasSkill('political_connections')) eventChance += 0.05;

        if (rng.random() > eventChance) return ''; // no event

        // Roll which event type (weighted)
        // Common events: reputation boost, military intel
        // Uncommon: bonus gold, enemy plans
        // Rare: king's favor (5% of events that happen)
        var roll = rng.random();

        if (roll < 0.30) {
            // EVENT: Reputation boost — uncovered plot against the kingdom
            var repBoost = rng.randInt(5, 12);
            player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + repBoost);
            if (kingdom.king) modifyRelationship(kingdom.king.id, rng.randInt(3, 8), 'spy_success');
            modifyTownReputation(town.id, rng.randInt(2, 5));
            Engine.logEvent('🕵️ Your spy work uncovered a plot against ' + kingdom.name + '! The crown is grateful. (Kingdom rep +' + repBoost + ')');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🕵️ Uncovered a plot! Reputation boosted.', 'success');
            return ' 🕵️ Uncovered plot — rep +' + repBoost;

        } else if (roll < 0.55) {
            // EVENT: Military advantage — found enemy troop positions
            var wars = Engine.getActiveWars ? Engine.getActiveWars() : {};
            var enemyKingdomId = null;
            for (var wId in wars) {
                var w = wars[wId];
                if (w.kingdomA === town.kingdomId) { enemyKingdomId = w.kingdomB; break; }
                if (w.kingdomB === town.kingdomId) { enemyKingdomId = w.kingdomA; break; }
            }
            // Weaken enemy army or boost friendly garrison
            if (enemyKingdomId) {
                var enemyK = Engine.findKingdom(enemyKingdomId);
                var enemyTowns = Engine.getTowns().filter(function(t) { return t.kingdomId === enemyKingdomId; });
                if (enemyTowns.length > 0) {
                    var targetTown = enemyTowns[rng.randInt(0, enemyTowns.length - 1)];
                    var garrisonLoss = rng.randInt(3, 8);
                    targetTown.garrison = Math.max(0, (targetTown.garrison || 0) - garrisonLoss);
                    Engine.logEvent('🕵️ Your intel allowed ' + kingdom.name + ' to stage a raid on ' + targetTown.name + '! Enemy garrison reduced by ' + garrisonLoss + '.');
                }
            }
            // Also boost a friendly garrison
            var friendlyTowns = Engine.getTowns().filter(function(t) { return t.kingdomId === town.kingdomId; });
            if (friendlyTowns.length > 0) {
                var boostTown = friendlyTowns[rng.randInt(0, friendlyTowns.length - 1)];
                boostTown.garrison = (boostTown.garrison || 0) + rng.randInt(2, 5);
            }
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🕵️ Military intel delivered! Enemy weakened.', 'success', 'military');
            return ' 🕵️ Military intel — enemy weakened';

        } else if (roll < 0.75) {
            // EVENT: Intercepted enemy gold/supplies
            var bonusGold = rng.randInt(30, 80);
            if (hasSkill('war_profiteer')) bonusGold = Math.round(bonusGold * 1.5);
            player.gold += bonusGold;
            player.stats.totalGoldEarned += bonusGold;
            Engine.logEvent('🕵️ Intercepted enemy supplies during spy mission. Found ' + bonusGold + 'g worth of valuables!');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🕵️ Intercepted enemy supplies! +' + bonusGold + 'g', 'success');
            return ' 🕵️ Intercepted supplies — +' + bonusGold + 'g';

        } else if (roll < 0.95) {
            // EVENT: Discovered enemy war plans — reputation + kingdom benefit
            var planRepBoost = rng.randInt(8, 15);
            player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + planRepBoost);
            if (kingdom.king) modifyRelationship(kingdom.king.id, rng.randInt(5, 12), 'spy_war_plans');
            // Give the kingdom a stockpile boost (as if they captured supplies)
            kingdom.gold += rng.randInt(200, 500);
            kingdom.militaryStockpile = kingdom.militaryStockpile || {};
            kingdom.militaryStockpile.swords = (kingdom.militaryStockpile.swords || 0) + rng.randInt(5, 15);
            kingdom.militaryStockpile.armor = (kingdom.militaryStockpile.armor || 0) + rng.randInt(3, 8);
            Engine.logEvent('🕵️ MAJOR DISCOVERY: ' + player.fullName + ' uncovered the enemy\'s war plans! ' + kingdom.name + ' gains a decisive advantage. (Rep +' + planRepBoost + ')');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🕵️ MAJOR: Enemy war plans discovered!', 'success');
            return ' 🕵️ MAJOR — enemy war plans discovered, rep +' + planRepBoost;

        } else {
            // EVENT: KING'S FAVOR — the rarest and most powerful (~5% of events)
            // Store pending favor for player to choose
            player.pendingSpyFavor = {
                kingdomId: town.kingdomId,
                townId: town.id,
                day: Engine.getDay()
            };
            Engine.logEvent('🕵️👑 EXTRAORDINARY SERVICE: ' + player.fullName + '\'s spy mission was so successful that the King of ' + kingdom.name + ' wishes to grant a personal favor!');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('👑 The King offers you a ROYAL FAVOR! Check your notifications.', 'success');
            // Show the favor dialog
            if (typeof UI !== 'undefined' && UI.showSpyFavorDialog) {
                setTimeout(function() { UI.showSpyFavorDialog(town.kingdomId); }, 500);
            }
            return ' 👑 KING\'S FAVOR EARNED!';
        }
    }

    // Customs Inspector: player chooses to turn in or keep contraband
    function handleCustomsChoice(choice) {
        var find = player._pendingCustomsFind;
        if (!find) return { success: false, message: 'No pending contraband.' };
        player._pendingCustomsFind = null;

        if (choice === 'turn_in') {
            player.gold += 10;
            player.stats.totalGoldEarned += 10;
            player.reputation[find.kingdomId] = Math.min(100, (player.reputation[find.kingdomId] || 50) + 2);
            Engine.logEvent('🔍 Turned in contraband ' + find.name + ' — received 10g bounty and kingdom approval.');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🔍 Turned in ' + find.name + ' for 10g bounty.', 'success');
            return { success: true, message: 'Turned in ' + find.name + '. +10g, +2 rep.' };
        } else {
            // Keep the item — smuggling risk!
            player.inventory[find.resourceId] = (player.inventory[find.resourceId] || 0) + 1;
            // Small notoriety increase for pocketing contraband
            player.notoriety = Math.min(100, (player.notoriety || 0) + 5);
            Engine.logEvent('🔍 Pocketed contraband ' + find.name + '. Be careful — someone might notice.');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🔍 Kept ' + find.name + '. Notoriety +5.', 'warning');
            return { success: true, message: 'Pocketed ' + find.name + '. Notoriety +5.' };
        }
    }

    function getSpyFavorChoices(kingdomId) {
        var kingdom = Engine.findKingdom(kingdomId);
        if (!kingdom) return [];
        var choices = [];

        // 1. Social rank promotion (guaranteed)
        var currentRank = player.socialRank[kingdomId] || 0;
        if (currentRank < 6) {
            var nextRank = CONFIG.SOCIAL_RANKS[currentRank + 1];
            choices.push({
                id: 'rank_promotion',
                label: '👑 Social Rank Promotion',
                description: 'The king elevates you to ' + (nextRank ? nextRank.name : 'the next rank') + '. All requirements waived.',
                detail: 'Current: ' + (CONFIG.SOCIAL_RANKS[currentRank] ? CONFIG.SOCIAL_RANKS[currentRank].name : 'Peasant') + ' → ' + (nextRank ? nextRank.name : 'Higher rank')
            });
        }

        // 2. Royal marriage — marry into the king's family
        choices.push({
            id: 'royal_marriage',
            label: '💒 Royal Marriage',
            description: 'The king offers the hand of an eligible member of the royal family in marriage.',
            detail: 'Marriage + rank boost + king relationship +25'
        });

        // 3. Tax exemption
        choices.push({
            id: 'tax_exemption',
            label: '💰 Tax Exemption',
            description: 'Complete exemption from all taxes in ' + kingdom.name + ' for one full year.',
            detail: 'No trade, property, or income taxes for 365 days'
        });

        // 4. Land grant — free building
        choices.push({
            id: 'land_grant',
            label: '🏗️ Land & Building Grant',
            description: 'The king grants you a prime building of your choice, fully constructed, in the capital.',
            detail: 'Free building (any type) + 3 free workers'
        });

        // 5. Military commission — instant high rank
        if (!player.militaryRank || MILITARY_RANKS.indexOf(player.militaryRank) < 2) {
            choices.push({
                id: 'military_commission',
                label: '⚔️ Military Commission',
                description: 'The king grants you the rank of Sergeant. Bypass normal promotion requirements.',
                detail: 'Instant Sergeant rank + combat_trained skill'
            });
        }

        // 6. Treasury reward — large gold payment
        choices.push({
            id: 'treasury_reward',
            label: '🪙 Treasury Reward',
            description: 'A generous payment from the royal treasury for your extraordinary service.',
            detail: 'Receive 500-1500g depending on kingdom wealth'
        });

        // 7. Guaranteed petition — any petition auto-approved
        choices.push({
            id: 'guaranteed_petition',
            label: '📜 Royal Decree',
            description: 'The king will fulfill any one petition of your choice immediately, no signatures needed.',
            detail: 'Choose: build road, lower/raise taxes, ban/unban goods, declare war, seek peace, etc.'
        });

        // 8. Criminal pardon
        if (player.criminalRecord && player.criminalRecord[kingdomId] && Object.keys(player.criminalRecord[kingdomId]).length > 0) {
            choices.push({
                id: 'criminal_pardon',
                label: '⚖️ Full Pardon',
                description: 'All criminal charges in ' + kingdom.name + ' are dropped and your record is cleared.',
                detail: 'Clean criminal record + reputation restored'
            });
        }

        // 9. Trade monopoly
        choices.push({
            id: 'trade_monopoly',
            label: '📊 Trade Monopoly',
            description: 'Exclusive rights to trade a specific good in ' + kingdom.name + ' for 180 days. 20% price bonus.',
            detail: '180 days exclusive trading rights + price bonus'
        });

        return choices;
    }

    function handleSpyFavor(favorId) {
        if (!player.pendingSpyFavor) return { success: false, message: 'No pending favor.' };
        var kingdomId = player.pendingSpyFavor.kingdomId;
        var townId = player.pendingSpyFavor.townId;
        var kingdom = Engine.findKingdom(kingdomId);
        var town = Engine.findTown(townId);
        var rng = Engine.getRng();
        player.pendingSpyFavor = null;

        switch (favorId) {
            case 'rank_promotion': {
                var currentRank = player.socialRank[kingdomId] || 0;
                if (currentRank < 6) {
                    player.socialRank[kingdomId] = currentRank + 1;
                    player.rankSince[kingdomId] = Engine.getDay();
                    var newRank = CONFIG.SOCIAL_RANKS[currentRank + 1];
                    Engine.logEvent('👑 By royal decree, ' + player.fullName + ' is elevated to ' + (newRank ? newRank.name : 'higher rank') + ' in ' + kingdom.name + '!');
                    if (typeof UI !== 'undefined' && UI.toast) UI.toast('👑 Promoted to ' + (newRank ? newRank.name : 'higher rank') + '!', 'success', 'military');
                }
                return { success: true, message: 'Promoted by royal decree!' };
            }
            case 'royal_marriage': {
                var w = Engine.getWorld();
                var kingPerson = kingdom.king ? Engine.findPerson(kingdom.king) : null;
                if (!w || !kingPerson) {
                    return { success: false, message: 'No king found for this kingdom.' };
                }
                var playerSex = player.sex;
                var oppSex = playerSex === 'M' ? 'F' : 'M';

                // Find king's siblings (shared parentIds)
                var kingSiblingIds = [];
                if (kingPerson.parentIds && kingPerson.parentIds.length > 0) {
                    var sibs = w.people.filter(function(p) {
                        return p.alive && p.id !== kingPerson.id &&
                            p.parentIds && p.parentIds.some(function(pid) { return kingPerson.parentIds.indexOf(pid) !== -1; });
                    });
                    for (var sbi = 0; sbi < sibs.length; sbi++) kingSiblingIds.push(sibs[sbi].id);
                }

                // Determine heir apparent: king's eldest living adult son
                var heirApparentId = null;
                if (kingPerson.childrenIds && kingPerson.childrenIds.length > 0) {
                    var heirCandidates = kingPerson.childrenIds
                        .map(function(cid) { return Engine.findPerson(cid); })
                        .filter(function(c) { return c && c.alive && c.sex === 'M' && c.age >= 18; })
                        .sort(function(a, b) { return b.age - a.age; });
                    if (heirCandidates.length > 0) heirApparentId = heirCandidates[0].id;
                }

                // Build pool of eligible royal family members
                var eligiblePool = [];

                // King's children
                if (kingPerson.childrenIds) {
                    for (var kci = 0; kci < kingPerson.childrenIds.length; kci++) {
                        var kc = Engine.findPerson(kingPerson.childrenIds[kci]);
                        if (kc && kc.alive && kc.sex === oppSex && kc.age >= 18 && !kc.spouseId && kc.id !== heirApparentId) {
                            eligiblePool.push(kc);
                        }
                    }
                }

                // King's siblings
                for (var ksi = 0; ksi < kingSiblingIds.length; ksi++) {
                    var ksib = Engine.findPerson(kingSiblingIds[ksi]);
                    if (ksib && ksib.alive && ksib.sex === oppSex && ksib.age >= 18 && !ksib.spouseId && ksib.id !== heirApparentId) {
                        eligiblePool.push(ksib);
                    }
                }

                // Nieces/nephews: children of king's siblings
                for (var nsi = 0; nsi < kingSiblingIds.length; nsi++) {
                    var nsib = Engine.findPerson(kingSiblingIds[nsi]);
                    if (nsib && nsib.childrenIds) {
                        for (var nci = 0; nci < nsib.childrenIds.length; nci++) {
                            var nephew = Engine.findPerson(nsib.childrenIds[nci]);
                            if (nephew && nephew.alive && nephew.sex === oppSex && nephew.age >= 18 && !nephew.spouseId && nephew.id !== heirApparentId) {
                                eligiblePool.push(nephew);
                            }
                        }
                    }
                }

                var matchPerson = null;
                if (eligiblePool.length > 0) {
                    // Pick closest in age to player
                    eligiblePool.sort(function(a, b) {
                        return Math.abs(a.age - player.age) - Math.abs(b.age - player.age);
                    });
                    matchPerson = eligiblePool[0];
                    player.spouseId = matchPerson.id;
                    matchPerson.spouseId = player.id || 'player';
                    if (kingdom.king) modifyRelationship(kingdom.king, 25, 'royal_favor');
                    var cr2 = player.socialRank[kingdomId] || 0;
                    if (cr2 < 4) player.socialRank[kingdomId] = Math.min(4, cr2 + 1);
                    player.rankSince[kingdomId] = Engine.getDay();
                    player.reputation[kingdomId] = Math.min(100, (player.reputation[kingdomId] || 50) + 15);
                    Engine.logEvent('💒 ' + player.fullName + ' has married ' + matchPerson.firstName + ' ' + matchPerson.lastName + ' of the royal family of ' + kingdom.name + '!');
                    if (typeof UI !== 'undefined' && UI.toast) UI.toast('💒 Married ' + matchPerson.firstName + ' ' + matchPerson.lastName + '!', 'success', 'my_actions');
                    return { success: true, message: 'Married ' + matchPerson.firstName + ' ' + matchPerson.lastName + ' of the royal family!' };
                } else {
                    // Fallback: create a distant royal cousin
                    var cousinAge = Math.max(18, Math.min(65, player.age + (rng.randInt(-5, 5))));
                    var cousin = {
                        id: uid('p'),
                        firstName: oppSex === 'M' ? rng.pick(NAMES.male) : rng.pick(NAMES.female),
                        lastName: kingPerson.lastName,
                        age: cousinAge,
                        sex: oppSex,
                        alive: true,
                        townId: kingPerson.townId,
                        kingdomId: kingPerson.kingdomId,
                        occupation: 'noble',
                        employerId: null,
                        needs: { food: rng.randInt(50, 80), shelter: rng.randInt(55, 85), safety: rng.randInt(50, 80), wealth: rng.randInt(40, 70), happiness: rng.randInt(50, 75) },
                        gold: rng.randInt(50, 100),
                        skills: { farming: 5, mining: 5, crafting: 5, trading: rng.randInt(10, 30), combat: rng.randInt(10, 30) },
                        workerSkill: 0,
                        spouseId: player.id || 'player',
                        childrenIds: [],
                        parentIds: [],
                        wealthClass: 'upper',
                        houseType: rng.pick(['manor', 'townhouse']),
                        personality: {
                            loyalty: Math.floor((rng.random()+rng.random()+rng.random())/3*100),
                            ambition: Math.floor((rng.random()+rng.random()+rng.random())/3*100),
                            frugality: Math.floor((rng.random()+rng.random()+rng.random())/3*100),
                            intelligence: Math.floor((rng.random()+rng.random()+rng.random())/3*100),
                            warmth: Math.floor((rng.random()+rng.random()+rng.random())/3*100),
                            honesty: Math.floor((rng.random()+rng.random()+rng.random())/3*100),
                        },
                        quirks: [],
                        foodPreferences: { bread: 1, meat: 1, poultry: 1, fish: 1, eggs: 1, preserved_food: 1 },
                        recentFoods: [],
                    };
                    w.people.push(cousin);
                    player.spouseId = cousin.id;
                    if (kingdom.king) modifyRelationship(kingdom.king, 25, 'royal_favor');
                    var cr3 = player.socialRank[kingdomId] || 0;
                    if (cr3 < 4) player.socialRank[kingdomId] = Math.min(4, cr3 + 1);
                    player.rankSince[kingdomId] = Engine.getDay();
                    player.reputation[kingdomId] = Math.min(100, (player.reputation[kingdomId] || 50) + 15);
                    Engine.logEvent('💒 ' + player.fullName + ' has married ' + cousin.firstName + ' ' + kingPerson.lastName + ', a distant cousin of the royal family of ' + kingdom.name + '!');
                    if (typeof UI !== 'undefined' && UI.toast) UI.toast('💒 Married ' + cousin.firstName + ' ' + kingPerson.lastName + '!', 'success', 'my_actions');
                    return { success: true, message: 'Married ' + cousin.firstName + ' ' + kingPerson.lastName + ', a distant cousin of the royal family!' };
                }
            }
            case 'tax_exemption': {
                if (!kingdom.taxHolidays) kingdom.taxHolidays = [];
                // Give player-specific tax exemption
                player.taxExemption = player.taxExemption || {};
                player.taxExemption[kingdomId] = Engine.getDay() + 365;
                Engine.logEvent('💰 The King of ' + kingdom.name + ' grants ' + player.fullName + ' a full tax exemption for one year!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('💰 Tax exempt for 1 year!', 'success');
                return { success: true, message: 'Tax exemption for 365 days!' };
            }
            case 'land_grant': {
                // Give a warehouse building + 3 workers
                var capitalTown = null;
                for (var tid of (kingdom.territories || [])) {
                    var t = Engine.findTown(tid);
                    if (t && t.isCapital) { capitalTown = t; break; }
                }
                if (!capitalTown) capitalTown = town;
                // Add a warehouse building
                player.buildings.push({
                    id: buildingUid(), type: 'warehouse', townId: capitalTown.id,
                    level: 1, condition: 'new', workers: [], ownerId: 'player',
                    storage: 100, autoBuy: {}, autoSell: {},
                    buildDay: Engine.getDay()
                });
                // Grant gold for hiring workers
                player.gold += 300;
                player.stats.totalGoldEarned += 300;
                Engine.logEvent('🏗️ The King grants ' + player.fullName + ' a warehouse in ' + capitalTown.name + ' and 300g to hire workers!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('🏗️ Granted a warehouse + 300g!', 'success');
                return { success: true, message: 'Received warehouse in ' + capitalTown.name + ' + 300g!' };
            }
            case 'military_commission': {
                player.militaryRank = 'sergeant';
                if (!hasSkill('combat_trained')) player.skills.combat_trained = true;
                player.reputation[kingdomId] = Math.min(100, (player.reputation[kingdomId] || 50) + 5);
                Engine.logEvent('⚔️ The King of ' + kingdom.name + ' commissions ' + player.fullName + ' as a Sergeant!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('⚔️ Commissioned as Sergeant!', 'success');
                return { success: true, message: 'Commissioned as Sergeant + combat_trained skill!' };
            }
            case 'treasury_reward': {
                var goldReward = Math.min(1500, Math.max(500, Math.round(kingdom.gold * 0.05)));
                player.gold += goldReward;
                player.stats.totalGoldEarned += goldReward;
                kingdom.gold -= goldReward;
                Engine.logEvent('🪙 The King rewards ' + player.fullName + ' with ' + goldReward + 'g from the royal treasury!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('🪙 Treasury reward: ' + goldReward + 'g!', 'success');
                return { success: true, message: 'Received ' + goldReward + 'g from the treasury!' };
            }
            case 'guaranteed_petition': {
                // Store a guaranteed petition token
                player.guaranteedPetition = player.guaranteedPetition || {};
                player.guaranteedPetition[kingdomId] = true;
                Engine.logEvent('📜 The King of ' + kingdom.name + ' grants ' + player.fullName + ' a Royal Decree — your next petition will be automatically approved!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('📜 Royal Decree granted! Next petition auto-approved.', 'success');
                return { success: true, message: 'Next petition in ' + kingdom.name + ' will be guaranteed!' };
            }
            case 'criminal_pardon': {
                if (player.criminalRecord && player.criminalRecord[kingdomId]) {
                    delete player.criminalRecord[kingdomId];
                }
                player.reputation[kingdomId] = Math.min(100, (player.reputation[kingdomId] || 50) + 10);
                Engine.logEvent('⚖️ The King of ' + kingdom.name + ' grants ' + player.fullName + ' a full pardon! Criminal record cleared.');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('⚖️ Full pardon! Record cleared.', 'success');
                return { success: true, message: 'Criminal record in ' + kingdom.name + ' cleared! Rep +10.' };
            }
            case 'trade_monopoly': {
                // Grant monopoly on a valuable trade good
                var monopolyGoods = ['silk', 'jewelry', 'wine', 'perfume', 'fine_clothes', 'tools'];
                var monopolyGood = monopolyGoods[rng.randInt(0, monopolyGoods.length - 1)];
                var res = findResource(monopolyGood);
                player.tradeMonopoly = player.tradeMonopoly || {};
                player.tradeMonopoly[kingdomId] = {
                    resourceId: monopolyGood,
                    expiresDay: Engine.getDay() + 180,
                    priceBonus: 0.20
                };
                Engine.logEvent('📊 The King grants ' + player.fullName + ' exclusive trading rights for ' + (res ? res.name : monopolyGood) + ' in ' + kingdom.name + ' for 180 days!');
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('📊 Trade monopoly: ' + (res ? res.name : monopolyGood) + '!', 'success');
                return { success: true, message: 'Trade monopoly on ' + (res ? res.name : monopolyGood) + ' for 180 days! +20% price bonus.' };
            }
            default:
                return { success: false, message: 'Unknown favor.' };
        }
    }

    // ========================================================
    // §12I  TOURNAMENT SYSTEM
    // ========================================================
    function enterTournament(job) {
        var rng = Engine.getRng();
        if (!rng) return { success: false, message: 'RNG not available.' };

        var entryFee = job.entryFee;
        if (player.gold < entryFee) return { success: false, message: 'Cannot afford the ' + entryFee + 'g entry fee.' };

        // Deduct entry fee
        player.gold -= entryFee;

        // Set up tournament state
        var town = Engine.findTown(player.townId);
        player.tournamentState = {
            round: 1,
            entryFee: entryFee,
            kingdomId: town ? town.kingdomId : null,
            townId: player.townId,
        };

        // Track job experience
        trackJobExperience('tournament', 1);
        grantXP(5, 'Tournament Entry');

        // Advance some time for the first round
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(5);

        // Fight round 1
        return fightTournamentRound();
    }

    function fightTournamentRound() {
        var rng = Engine.getRng();
        if (!player.tournamentState) return { success: false, message: 'Not in a tournament.' };

        var round = player.tournamentState.round;
        var entryFee = player.tournamentState.entryFee;
        var combatLvl = getCombatLevel();

        // Win probability based on combat level (0-100) and round
        // Low combat (0): R1=50%, R2=10%, R3=2%
        // High combat (100): R1=95%, R2=70%, R3=40%
        var winChances = [
            { low: 0.50, high: 0.95 }, // Round 1
            { low: 0.10, high: 0.70 }, // Round 2
            { low: 0.02, high: 0.40 }, // Round 3
        ];
        var rc = winChances[round - 1];
        var winChance = rc.low + (rc.high - rc.low) * (combatLvl / 100);

        // Injury risk per round (decreases with combat level)
        var injuryChance = Math.max(0.02, 0.08 - combatLvl * 0.0004);

        // Roll for injury first (happens win or lose)
        if (rng.random() < injuryChance) {
            inflictRandomInjury('Tournament Round ' + round);
        }

        var won = rng.random() < winChance;

        if (!won) {
            // Lost — tournament over, no prize for this round
            var ts = player.tournamentState;
            player.tournamentState = null;
            trackJobExperience('tournament', 1);
            grantXP(3, 'Tournament Round ' + round + ' (loss)');

            // Advance time
            if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(5);

            Engine.logEvent('🏟️ ' + player.fullName + ' was defeated in Round ' + round + ' of the tournament. Entry fee ' + entryFee + 'g lost.');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🏟️ Defeated in Round ' + round + '! Lost ' + entryFee + 'g entry fee.', 'warning', 'my_actions');
            return { success: true, message: 'Defeated in Round ' + round + '. Lost ' + entryFee + 'g entry fee. (Combat Level: ' + combatLvl + ', Win chance: ' + Math.round(winChance * 100) + '%)' };
        }

        // Won this round!
        var prizeMultipliers = [4, 10, 40]; // Round 1: 4x, Round 2: 10x, Round 3: 40x
        var prize = entryFee * prizeMultipliers[round - 1];

        grantXP(5 + round * 5, 'Tournament Round ' + round + ' (win)');
        trackJobExperience('tournament', 1);

        if (round === 3) {
            // WON THE WHOLE TOURNAMENT!
            player.gold += prize;
            player.stats.totalGoldEarned += prize;
            player.tournamentsWon = (player.tournamentsWon || 0) + 1;
            player.tournamentState = null;

            // Reputation boosts
            var town = Engine.findTown(player.townId);
            if (town) {
                player.reputation[town.kingdomId] = Math.min(100, (player.reputation[town.kingdomId] || 50) + 8);
                modifyTownReputation(town.id, 10);
            }
            // King relationship boost
            var kingdom = town ? Engine.findKingdom(town.kingdomId) : null;
            if (kingdom && kingdom.king) {
                modifyRelationship(kingdom.king.id, 15, 'tournament_champion');
            }

            // Advance time
            if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(10);

            Engine.logEvent('🏆 ' + player.fullName + ' has won the Royal Tournament! Champion\'s prize: ' + prize + 'g! The crowd roars!');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('🏆 TOURNAMENT CHAMPION! Won ' + prize + 'g!', 'success', 'my_actions');
            return { success: true, message: '🏆 TOURNAMENT CHAMPION! Won all 3 rounds! Prize: ' + prize + 'g. Kingdom reputation +8, King relationship +15. (Combat Level: ' + combatLvl + ')' };
        }

        // Won round but tournament continues — player can choose to continue
        player.gold += prize;
        player.stats.totalGoldEarned += prize;
        player.tournamentState.round = round + 1;

        // Advance time between rounds
        if (typeof Game !== 'undefined' && Game.advanceTicks) Game.advanceTicks(5);

        var nextPrize = entryFee * prizeMultipliers[round]; // next round's prize
        var nextRc = winChances[round];
        var nextWinChance = Math.round((nextRc.low + (nextRc.high - nextRc.low) * (combatLvl / 100)) * 100);

        Engine.logEvent('🏟️ ' + player.fullName + ' won Round ' + round + ' of the tournament! Prize: ' + prize + 'g. Advancing to Round ' + (round + 1) + '...');
        if (typeof UI !== 'undefined' && UI.toast) UI.toast('🏟️ Won Round ' + round + '! ' + prize + 'g earned!', 'success', 'my_actions');

        return {
            success: true,
            tournamentContinue: true,
            message: 'Won Round ' + round + '! Earned ' + prize + 'g. (Combat Level: ' + combatLvl + ', Win chance: ' + Math.round(winChance * 100) + '%)\nNext: Round ' + (round + 1) + ' — Prize: ' + nextPrize + 'g, Est. win chance: ' + nextWinChance + '%',
            nextRound: round + 1,
            nextPrize: nextPrize,
            nextWinChance: nextWinChance,
        };
    }

    function continueTournament() {
        if (!player.tournamentState) return { success: false, message: 'Not in a tournament.' };
        return fightTournamentRound();
    }

    function forfeitTournament() {
        if (!player.tournamentState) return { success: false, message: 'Not in a tournament.' };
        var round = player.tournamentState.round;
        player.tournamentState = null;
        Engine.logEvent('🏟️ ' + player.fullName + ' has withdrawn from the tournament after Round ' + (round - 1) + '.');
        if (typeof UI !== 'undefined' && UI.toast) UI.toast('🏟️ Withdrew from tournament.', 'info', 'my_actions');
        return { success: true, message: 'Withdrew from tournament. Keeping winnings from previous rounds.' };
    }

    // ========================================================
    // §12K  MUSICAL INSTRUMENT SYSTEM
    // ========================================================

    // Determine a town's preferred instrument based on its characteristics (deterministic)
    function getTownPreferredInstrument(town) {
        if (!town) return 'lute';
        // Use town characteristics to pick preference
        if (town.isCapital || town.category === 'capital_city') return 'harp';
        if (town.isPort) return 'hurdy_gurdy';
        if (town.category === 'village') return 'flute';
        // Towns — hash town id to pick between lute and drum
        var hash = 0;
        for (var i = 0; i < (town.id || '').length; i++) hash += town.id.charCodeAt(i);
        return (hash % 2 === 0) ? 'lute' : 'drum';
    }

    // Check if player has an instrument in inventory
    function getPlayerInstruments() {
        var owned = [];
        var ids = typeof INSTRUMENT_IDS !== 'undefined' ? INSTRUMENT_IDS : ['drum', 'flute', 'lute', 'hurdy_gurdy', 'harp'];
        for (var i = 0; i < ids.length; i++) {
            if ((player.inventory[ids[i]] || 0) > 0) {
                owned.push(ids[i]);
            }
        }
        return owned;
    }

    // Get best instrument for current town (highest effective bonus)
    function getBestInstrumentForTown(townId) {
        var instruments = getPlayerInstruments();
        if (instruments.length === 0) return null;
        var town = Engine.findTown(townId || player.townId);
        var preferred = getTownPreferredInstrument(town);
        var best = null;
        var bestScore = 0;

        var cfgInstruments = typeof INSTRUMENTS !== 'undefined' ? INSTRUMENTS : {};
        var cfgTiers = typeof INSTRUMENT_SKILL_TIERS !== 'undefined' ? INSTRUMENT_SKILL_TIERS : [{ min: 0, multiplier: 1.0 }];
        var prefBonus = typeof INSTRUMENT_PREFERENCE_BONUS !== 'undefined' ? INSTRUMENT_PREFERENCE_BONUS : 0.50;
        var fatigueThreshold = typeof INSTRUMENT_FATIGUE_THRESHOLD !== 'undefined' ? INSTRUMENT_FATIGUE_THRESHOLD : 50;

        for (var i = 0; i < instruments.length; i++) {
            var instId = instruments[i];
            var inst = cfgInstruments[instId];
            if (!inst) continue;

            var skill = player.instrumentSkill[instId] || 0;
            var tierMult = 1.0;
            for (var t = cfgTiers.length - 1; t >= 0; t--) {
                if (skill >= cfgTiers[t].min) { tierMult = cfgTiers[t].multiplier; break; }
            }

            var prefMod = 1.0;
            if (instId === preferred) {
                // Check fatigue
                var fatigue = (player.instrumentFatigue[townId || player.townId] || {})[instId] || 0;
                if (fatigue < fatigueThreshold) {
                    prefMod = 1.0 + prefBonus;
                } else {
                    prefMod = 0.8; // town is tired of this instrument
                }
            }

            var score = inst.baseBonus * tierMult * prefMod;
            if (score > bestScore) {
                bestScore = score;
                best = { id: instId, inst: inst, skill: skill, tierMult: tierMult, prefMod: prefMod, bonus: score };
            }
        }
        return best;
    }

    // Calculate entertainment pay multiplier
    function getEntertainmentPayMultiplier(townId) {
        var best = getBestInstrumentForTown(townId);
        if (!best) return { multiplier: 0.7, instrumentName: null, skillTier: null }; // No instrument = reduced pay
        var tierName = 'Novice';
        var cfgTiers = typeof INSTRUMENT_SKILL_TIERS !== 'undefined' ? INSTRUMENT_SKILL_TIERS : [];
        for (var t = cfgTiers.length - 1; t >= 0; t--) {
            if (best.skill >= cfgTiers[t].min) { tierName = cfgTiers[t].name; break; }
        }
        return {
            multiplier: 1.0 + best.bonus,
            instrumentName: best.inst.name,
            instrumentIcon: best.inst.icon,
            skillTier: tierName,
            preferred: best.prefMod > 1.0,
            fatigued: best.prefMod < 1.0
        };
    }

    // Record a performance (increases skill, adds fatigue)
    function recordPerformance(instrumentId, townId) {
        if (!instrumentId) return;
        // Increase skill (diminishing returns as you get higher)
        var currentSkill = player.instrumentSkill[instrumentId] || 0;
        var skillGain = Math.max(0.5, 3.0 - (currentSkill / 40)); // 3.0 at 0, ~0.5 at 100
        if (hasSkill('musician')) skillGain *= 1.5; // musician skill speeds learning
        player.instrumentSkill[instrumentId] = Math.min(100, currentSkill + skillGain);

        // Track fatigue at this town
        if (!player.instrumentFatigue[townId]) player.instrumentFatigue[townId] = {};
        player.instrumentFatigue[townId][instrumentId] = (player.instrumentFatigue[townId][instrumentId] || 0) + 1;

        // If fatigue hits threshold, shift town preference (simulated by the fatigue check in getBestInstrumentForTown)
    }
    // Auto-travel jobs are multi-leg missions. The player automatically
    // travels between towns, performs work at each stop, then returns home.
    // Hybrid between normal jobs (tick shifts) and military (background processing).

    // Generate mission legs based on job type
    function generateAutoTravelMission(job) {
        var rng = Engine.getRng();
        var town = Engine.findTown(player.townId);
        if (!town || !rng) return null;
        var kingdom = Engine.findKingdom(town.kingdomId);
        var allTowns = Engine.getTowns();
        var homeTownId = player.townId;

        switch (job.jobTypeKey) {

            case 'royal_messenger': {
                // Deliver letters to 2-4 towns in the same kingdom
                var kingdomTowns = allTowns.filter(function(t) {
                    return t.kingdomId === town.kingdomId && t.id !== homeTownId;
                });
                if (kingdomTowns.length === 0) return null;
                shuffleArray(kingdomTowns, rng);
                var numLetters = Math.min(kingdomTowns.length, rng.randInt(2, 4));
                var legs = [];
                var letters = [];
                for (var li = 0; li < numLetters; li++) {
                    var dest = kingdomTowns[li];
                    // Pick a random NPC in the destination town for flavor
                    var townPeople = Engine.getPeople().filter(function(p) { return p.townId === dest.id; });
                    var recipientName = townPeople.length > 0 ? townPeople[rng.randInt(0, townPeople.length - 1)].fullName : 'the local magistrate';
                    letters.push({ townId: dest.id, townName: dest.name, recipientName: recipientName, delivered: false });
                    legs.push({
                        townId: dest.id,
                        stayTicks: 8,
                        stayDays: 1,
                        description: '📮 Deliver letter to ' + recipientName + ' in ' + dest.name,
                        payAmount: Math.round(8 * (job.payScale || 1)),
                        arrived: false,
                        workDone: false,
                        stayUntilDay: 0
                    });
                }
                // Return home
                legs.push({
                    townId: homeTownId,
                    stayTicks: 5,
                    stayDays: 0,
                    description: '📮 Return to ' + town.name + ' to report',
                    payAmount: Math.round(5 * (job.payScale || 1)),
                    arrived: false,
                    workDone: false,
                    isReturn: true,
                    stayUntilDay: 0
                });
                return {
                    type: 'royal_messenger',
                    name: '📮 Royal Messenger',
                    kingdomId: town.kingdomId,
                    homeTownId: homeTownId,
                    startDay: Engine.getDay(),
                    currentLeg: 0,
                    legs: legs,
                    letters: letters,
                    totalPaid: 0,
                    status: 'traveling',
                    xpReward: 10,
                    repGain: 4,
                    risks: { deathRisk: 0, injuryRisk: 0.002 },
                    jobTypeKey: 'royal_messenger'
                };
            }

            case 'spy': {
                // Travel to 2-3 towns in an enemy kingdom
                var wars = Engine.getActiveWars ? Engine.getActiveWars() : {};
                var enemyKingdomId = null;
                for (var wId in wars) {
                    var w = wars[wId];
                    if (w.kingdomA === town.kingdomId) { enemyKingdomId = w.kingdomB; break; }
                    if (w.kingdomB === town.kingdomId) { enemyKingdomId = w.kingdomA; break; }
                }
                if (!enemyKingdomId) return null;
                var enemyTowns = allTowns.filter(function(t) { return t.kingdomId === enemyKingdomId; });
                if (enemyTowns.length === 0) return null;
                shuffleArray(enemyTowns, rng);
                var spyStops = Math.min(enemyTowns.length, rng.randInt(2, 3));
                var spyLegs = [];
                var spyActivities = [
                    'Infiltrate the market district and observe troop movements',
                    'Make contact with local informants',
                    'Map the garrison defenses and supply stores',
                    'Monitor enemy supply caravans',
                    'Gather intelligence from tavern conversations',
                    'Observe the military barracks and training grounds'
                ];
                shuffleArray(spyActivities, rng);
                for (var si = 0; si < spyStops; si++) {
                    spyLegs.push({
                        townId: enemyTowns[si].id,
                        stayTicks: 20,
                        stayDays: rng.randInt(2, 4),
                        description: '🕵️ ' + spyActivities[si % spyActivities.length] + ' in ' + enemyTowns[si].name,
                        payAmount: Math.round(30 * (job.payScale || 1)),
                        arrived: false,
                        workDone: false,
                        stayUntilDay: 0
                    });
                }
                spyLegs.push({
                    townId: homeTownId,
                    stayTicks: 10,
                    stayDays: 0,
                    description: '🕵️ Return to ' + town.name + ' to deliver intelligence report',
                    payAmount: Math.round(15 * (job.payScale || 1)),
                    arrived: false,
                    workDone: false,
                    isReturn: true,
                    stayUntilDay: 0
                });
                return {
                    type: 'spy',
                    name: '🕵️ Spy for the Crown',
                    kingdomId: town.kingdomId,
                    enemyKingdomId: enemyKingdomId,
                    homeTownId: homeTownId,
                    startDay: Engine.getDay(),
                    currentLeg: 0,
                    legs: spyLegs,
                    totalPaid: 0,
                    status: 'traveling',
                    xpReward: 15,
                    repGain: 5,
                    risks: { deathRisk: 0.0013, injuryRisk: 0.008 },
                    bonusEvents: true,
                    jobTypeKey: 'spy'
                };
            }

            case 'weapons_courier': {
                // Deliver weapons to 1-2 friendly towns near the border
                var friendlyTowns = allTowns.filter(function(t) {
                    return t.kingdomId === town.kingdomId && t.id !== homeTownId;
                });
                if (friendlyTowns.length === 0) return null;
                // Prefer towns with garrisons (border towns)
                friendlyTowns.sort(function(a, b) { return (b.garrison || 0) - (a.garrison || 0); });
                var courierStops = Math.min(friendlyTowns.length, rng.randInt(1, 2));
                var courierLegs = [];
                for (var ci = 0; ci < courierStops; ci++) {
                    courierLegs.push({
                        townId: friendlyTowns[ci].id,
                        stayTicks: 15,
                        stayDays: 1,
                        description: '📦 Deliver weapons shipment to garrison at ' + friendlyTowns[ci].name,
                        payAmount: Math.round(15 * (job.payScale || 1)),
                        arrived: false,
                        workDone: false,
                        stayUntilDay: 0
                    });
                }
                courierLegs.push({
                    townId: homeTownId,
                    stayTicks: 5,
                    stayDays: 0,
                    description: '📦 Return to ' + town.name + ' for next assignment',
                    payAmount: Math.round(5 * (job.payScale || 1)),
                    arrived: false,
                    workDone: false,
                    isReturn: true,
                    stayUntilDay: 0
                });
                return {
                    type: 'weapons_courier',
                    name: '📦 Weapons Courier',
                    kingdomId: town.kingdomId,
                    homeTownId: homeTownId,
                    startDay: Engine.getDay(),
                    currentLeg: 0,
                    legs: courierLegs,
                    totalPaid: 0,
                    status: 'traveling',
                    xpReward: 7,
                    repGain: 2,
                    risks: { deathRisk: 0, injuryRisk: 0.008 },
                    jobTypeKey: 'weapons_courier'
                };
            }

            case 'privateer': {
                // Sail to 1-2 enemy port towns, raid, return
                var pvtWars = Engine.getActiveWars ? Engine.getActiveWars() : {};
                var pvtEnemyId = null;
                for (var pwId in pvtWars) {
                    var pw = pvtWars[pwId];
                    if (pw.kingdomA === town.kingdomId) { pvtEnemyId = pw.kingdomB; break; }
                    if (pw.kingdomB === town.kingdomId) { pvtEnemyId = pw.kingdomA; break; }
                }
                var raidTargets = allTowns.filter(function(t) {
                    return t.isPort && ((pvtEnemyId && t.kingdomId === pvtEnemyId) || t.kingdomId !== town.kingdomId);
                });
                if (raidTargets.length === 0) {
                    // Fall back to any port
                    raidTargets = allTowns.filter(function(t) { return t.isPort && t.id !== homeTownId; });
                }
                if (raidTargets.length === 0) return null;
                shuffleArray(raidTargets, rng);
                var raidStops = Math.min(raidTargets.length, rng.randInt(1, 2));
                var pvtLegs = [];
                for (var pi = 0; pi < raidStops; pi++) {
                    pvtLegs.push({
                        townId: raidTargets[pi].id,
                        stayTicks: 25,
                        stayDays: rng.randInt(2, 3),
                        description: '🏴‍☠️ Raid enemy shipping near ' + raidTargets[pi].name,
                        payAmount: Math.round(25 * (job.payScale || 1)),
                        arrived: false,
                        workDone: false,
                        rollLoot: true,
                        stayUntilDay: 0
                    });
                }
                pvtLegs.push({
                    townId: homeTownId,
                    stayTicks: 5,
                    stayDays: 0,
                    description: '🏴‍☠️ Return to port with plunder',
                    payAmount: Math.round(10 * (job.payScale || 1)),
                    arrived: false,
                    workDone: false,
                    isReturn: true,
                    stayUntilDay: 0
                });
                return {
                    type: 'privateer',
                    name: '🏴‍☠️ Privateer',
                    kingdomId: town.kingdomId,
                    homeTownId: homeTownId,
                    startDay: Engine.getDay(),
                    currentLeg: 0,
                    legs: pvtLegs,
                    totalPaid: 0,
                    status: 'traveling',
                    xpReward: 12,
                    repGain: 2,
                    risks: { deathRisk: 0.0013, injuryRisk: 0.011 },
                    bonusLoot: true,
                    jobTypeKey: 'privateer'
                };
            }

            case 'caravan_guard': {
                // Guard a merchant caravan to 1-2 towns and back
                var guardDests = allTowns.filter(function(t) {
                    return t.id !== homeTownId && (t.category === 'city' || t.category === 'capital_city' || t.category === 'town');
                });
                if (guardDests.length === 0) return null;
                shuffleArray(guardDests, rng);
                var guardStops = Math.min(guardDests.length, rng.randInt(1, 2));
                var guardLegs = [];
                for (var gi = 0; gi < guardStops; gi++) {
                    guardLegs.push({
                        townId: guardDests[gi].id,
                        stayTicks: 10,
                        stayDays: 1,
                        description: '🛡️ Guard caravan to ' + guardDests[gi].name + ' — unload goods',
                        payAmount: Math.round(12 * (job.payScale || 1)),
                        arrived: false,
                        workDone: false,
                        stayUntilDay: 0
                    });
                }
                guardLegs.push({
                    townId: homeTownId,
                    stayTicks: 5,
                    stayDays: 0,
                    description: '🛡️ Return to ' + town.name + ' with the caravan',
                    payAmount: Math.round(5 * (job.payScale || 1)),
                    arrived: false,
                    workDone: false,
                    isReturn: true,
                    stayUntilDay: 0
                });
                return {
                    type: 'caravan_guard',
                    name: '🛡️ Caravan Guard',
                    kingdomId: town.kingdomId,
                    homeTownId: homeTownId,
                    startDay: Engine.getDay(),
                    currentLeg: 0,
                    legs: guardLegs,
                    totalPaid: 0,
                    status: 'traveling',
                    xpReward: 6,
                    repGain: 1,
                    risks: { deathRisk: 0, injuryRisk: 0.005 },
                    jobTypeKey: 'caravan_guard'
                };
            }

            case 'traveling_merchant': {
                // Buy/sell at 2-3 towns for an NPC merchant
                var tradeDests = allTowns.filter(function(t) {
                    return t.id !== homeTownId && (t.category === 'city' || t.category === 'capital_city' || t.category === 'town');
                });
                if (tradeDests.length === 0) return null;
                shuffleArray(tradeDests, rng);
                var tradeStops = Math.min(tradeDests.length, rng.randInt(2, 3));
                var tradeLegs = [];
                var tradeActions = ['Buy silk and spices', 'Sell surplus tools and cloth', 'Negotiate trade agreements', 'Appraise exotic goods'];
                for (var ti = 0; ti < tradeStops; ti++) {
                    tradeLegs.push({
                        townId: tradeDests[ti].id,
                        stayTicks: 15,
                        stayDays: rng.randInt(1, 2),
                        description: '🏪 ' + tradeActions[ti % tradeActions.length] + ' in ' + tradeDests[ti].name,
                        payAmount: Math.round(12 * (job.payScale || 1)),
                        arrived: false,
                        workDone: false,
                        stayUntilDay: 0
                    });
                }
                tradeLegs.push({
                    townId: homeTownId,
                    stayTicks: 10,
                    stayDays: 0,
                    description: '🏪 Return to ' + town.name + ' with trade profits',
                    payAmount: Math.round(8 * (job.payScale || 1)),
                    arrived: false,
                    workDone: false,
                    isReturn: true,
                    stayUntilDay: 0
                });
                return {
                    type: 'traveling_merchant',
                    name: '🏪 Traveling Merchant\'s Agent',
                    kingdomId: town.kingdomId,
                    homeTownId: homeTownId,
                    startDay: Engine.getDay(),
                    currentLeg: 0,
                    legs: tradeLegs,
                    totalPaid: 0,
                    status: 'traveling',
                    xpReward: 10,
                    repGain: 2,
                    risks: { deathRisk: 0, injuryRisk: 0.002 },
                    jobTypeKey: 'traveling_merchant'
                };
            }

            case 'itinerant_healer': {
                // Travel to 2-3 villages/small towns healing the sick
                var healDests = allTowns.filter(function(t) {
                    return t.id !== homeTownId && (t.category === 'village' || t.category === 'town');
                });
                if (healDests.length === 0) return null;
                shuffleArray(healDests, rng);
                var healStops = Math.min(healDests.length, rng.randInt(2, 3));
                var healLegs = [];
                var healActivities = ['Treat the sick and wounded', 'Tend to plague survivors', 'Prepare herbal remedies for the village', 'Set broken bones and dress wounds'];
                for (var hi = 0; hi < healStops; hi++) {
                    healLegs.push({
                        townId: healDests[hi].id,
                        stayTicks: 20,
                        stayDays: rng.randInt(2, 3),
                        description: '🏥 ' + healActivities[hi % healActivities.length] + ' in ' + healDests[hi].name,
                        payAmount: Math.round(10 * (job.payScale || 1)),
                        arrived: false,
                        workDone: false,
                        stayUntilDay: 0
                    });
                }
                healLegs.push({
                    townId: homeTownId,
                    stayTicks: 5,
                    stayDays: 0,
                    description: '🏥 Return to ' + town.name,
                    payAmount: Math.round(5 * (job.payScale || 1)),
                    arrived: false,
                    workDone: false,
                    isReturn: true,
                    stayUntilDay: 0
                });
                return {
                    type: 'itinerant_healer',
                    name: '🏥 Itinerant Healer',
                    kingdomId: town.kingdomId,
                    homeTownId: homeTownId,
                    startDay: Engine.getDay(),
                    currentLeg: 0,
                    legs: healLegs,
                    totalPaid: 0,
                    status: 'traveling',
                    xpReward: 8,
                    repGain: 4,
                    risks: { deathRisk: 0, injuryRisk: 0, illnessRisk: 0.01 },
                    jobTypeKey: 'itinerant_healer'
                };
            }

            default:
                return null;
        }
    }

    // Shuffle array in place using seeded RNG
    function shuffleArray(arr, rng) {
        for (var i = arr.length - 1; i > 0; i--) {
            var j = rng.randInt(0, i);
            var tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
        }
    }

    // Start an auto-travel mission
    function startAutoTravelJob(job) {
        if (player.autoTravelJob) return { success: false, message: 'Already on an auto-travel mission. Quit first.' };
        if (player.militaryActive) return { success: false, message: 'Cannot take jobs while enlisted.' };
        if (player.traveling) return { success: false, message: 'Cannot start while traveling.' };

        var mission = generateAutoTravelMission(job);
        if (!mission) return { success: false, message: 'Could not generate mission — no valid destinations.' };

        player.autoTravelJob = mission;

        // Start traveling to first leg
        if (!mission.legs || mission.legs.length === 0) {
            player.autoTravelJob = null;
            return { success: false, message: 'Mission has no destinations.' };
        }
        var firstLeg = mission.legs[0];
        var travelResult = travelTo(firstLeg.townId);
        if (!travelResult.success) {
            // Can't reach destination — abort
            player.autoTravelJob = null;
            return { success: false, message: 'Cannot reach ' + (Engine.findTown(firstLeg.townId) || { name: 'unknown' }).name + ': ' + travelResult.message };
        }

        var totalStops = mission.legs.length - 1; // -1 for return leg
        Engine.logEvent('🗺️ ' + mission.name + ' mission started! ' + totalStops + ' stops before returning home.');
        if (typeof UI !== 'undefined' && UI.toast) UI.toast('🗺️ ' + mission.name + ' mission started!', 'success');

        return {
            success: true,
            message: mission.name + ' — ' + totalStops + ' deliveries. Traveling to ' + (Engine.findTown(firstLeg.townId) || { name: 'unknown' }).name + '...',
            autoTravelStarted: true
        };
    }

    // Tick processor — called every game day from playerTick
    function tickAutoTravelJob() {
        if (!player.autoTravelJob || !player.alive) return;
        var mission = player.autoTravelJob;
        var day = Engine.getDay();
        var rng = Engine.getRng();

        // Safety: if somehow stuck, abort after 120 days
        if (day - mission.startDay > 120) {
            Engine.logEvent('🗺️ ' + mission.name + ' mission timed out. Returning home.');
            completeAutoTravelMission(false);
            return;
        }

        var leg = mission.legs[mission.currentLeg];
        if (!leg) { completeAutoTravelMission(true); return; }

        if (mission.status === 'traveling') {
            // Check if we've arrived (travel completed)
            if (!player.traveling && player.townId === leg.townId) {
                leg.arrived = true;
                mission.status = 'working';
                leg.stayUntilDay = day + (leg.stayDays || 0);
                var destTown = Engine.findTown(leg.townId);
                Engine.logEvent('🗺️ Arrived at ' + (destTown ? destTown.name : 'destination') + '. ' + leg.description);
                if (typeof UI !== 'undefined' && UI.toast) UI.toast('📍 Arrived: ' + (destTown ? destTown.name : '?'), 'info');

                // If no stay required, immediately process work
                if (leg.stayDays <= 0) {
                    processAutoTravelWork(leg, mission);
                }
            }
            // If not traveling and not at destination, something went wrong — restart travel
            else if (!player.traveling && player.townId !== leg.townId) {
                var retryTravel = travelTo(leg.townId);
                if (!retryTravel.success) {
                    Engine.logEvent('🗺️ ' + mission.name + ' mission aborted — cannot reach destination.');
                    completeAutoTravelMission(false);
                }
            }
        }

        else if (mission.status === 'working') {
            // Risk checks during stay (once per day)
            if (mission.risks && rng) {
                if (mission.risks.deathRisk && rng.random() < mission.risks.deathRisk && !window._godInvincible) {
                    player.alive = false;
                    player.autoTravelJob = null;
                    Engine.logEvent('☠️ ' + player.fullName + ' was killed during ' + mission.name + ' mission.');
                    return;
                }
                if (mission.risks.injuryRisk && rng.random() < mission.risks.injuryRisk) {
                    inflictRandomInjury(mission.name);
                }
                if (mission.risks.illnessRisk && rng.random() < mission.risks.illnessRisk) {
                    inflictRandomIllness(mission.name);
                }
            }

            // Check if stay period is over
            if (day >= leg.stayUntilDay && !leg.workDone) {
                processAutoTravelWork(leg, mission);
            }
        }

        else if (mission.status === 'advancing') {
            // Move to next leg
            mission.currentLeg++;
            if (mission.currentLeg >= mission.legs.length) {
                completeAutoTravelMission(true);
                return;
            }
            var nextLeg = mission.legs[mission.currentLeg];
            if (player.townId === nextLeg.townId) {
                // Already at next destination
                nextLeg.arrived = true;
                mission.status = 'working';
                nextLeg.stayUntilDay = day + (nextLeg.stayDays || 0);
                Engine.logEvent('🗺️ ' + nextLeg.description);
                if (nextLeg.stayDays <= 0) {
                    processAutoTravelWork(nextLeg, mission);
                }
            } else {
                mission.status = 'traveling';
                var nextTravel = travelTo(nextLeg.townId);
                if (!nextTravel.success) {
                    Engine.logEvent('🗺️ Cannot reach next stop. Mission ending early.');
                    completeAutoTravelMission(false);
                }
            }
        }
    }

    // Process work at current stop — advance ticks, pay, events
    function processAutoTravelWork(leg, mission) {
        var rng = Engine.getRng();
        leg.workDone = true;

        // Advance ticks for the work shift
        if (leg.stayTicks > 0 && typeof Game !== 'undefined' && Game.advanceTicks) {
            Game.advanceTicks(leg.stayTicks);
        }

        // Pay for this leg
        if (leg.payAmount > 0) {
            var efficiency = getWorkEfficiencyModifier();
            var legPay = Math.round(leg.payAmount * efficiency);

            if (player.conquestServitude && player.conquestServitude.active) {
                var servK = Engine.findKingdom(player.conquestServitude.kingdomId);
                if (servK) servK.gold += legPay;
            } else {
                player.gold += legPay;
                player.stats.totalGoldEarned += legPay;
            }
            mission.totalPaid += legPay;
            Engine.logEvent('🪙 Earned ' + legPay + 'g for work at ' + (Engine.findTown(leg.townId) || { name: 'unknown' }).name);
        }

        // Track job experience
        if (mission.jobTypeKey) {
            trackJobExperience(mission.jobTypeKey, 1);
        }

        // Privateer loot at this stop
        if (leg.rollLoot && mission.bonusLoot && rng) {
            var lootMsg = rollPrivateerLoot(rng);
            if (lootMsg) Engine.logEvent('🏴‍☠️ Loot from raid: ' + lootMsg);
        }

        // Spy events at final work stop (not return leg)
        if (mission.bonusEvents && mission.type === 'spy' && !leg.isReturn && rng) {
            var spyMsg = rollSpyEvent(rng);
            if (spyMsg) Engine.logEvent('🕵️ Spy event: ' + spyMsg);
        }

        // Messenger: mark letter delivered
        if (mission.type === 'royal_messenger' && mission.letters) {
            for (var i = 0; i < mission.letters.length; i++) {
                if (mission.letters[i].townId === leg.townId && !mission.letters[i].delivered) {
                    mission.letters[i].delivered = true;
                    Engine.logEvent('📮 Letter delivered to ' + mission.letters[i].recipientName + ' in ' + mission.letters[i].townName);
                    break;
                }
            }
        }

        // Advance to next leg
        mission.status = 'advancing';
    }

    // Complete the entire mission
    function completeAutoTravelMission(success) {
        var mission = player.autoTravelJob;
        if (!mission) return;

        // Bonus XP and reputation on completion
        if (success) {
            if (mission.xpReward) grantXP(mission.xpReward, mission.name);
            if (mission.repGain && mission.kingdomId) {
                player.reputation[mission.kingdomId] = Math.min(100,
                    (player.reputation[mission.kingdomId] || 50) + mission.repGain);
            }
            var daysElapsed = Engine.getDay() - mission.startDay;
            Engine.logEvent('✅ ' + mission.name + ' mission complete! Earned ' + mission.totalPaid + 'g total over ' + daysElapsed + ' days.');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('✅ ' + mission.name + ' complete! ' + mission.totalPaid + 'g earned.', 'success');
        } else {
            var partialPay = mission.totalPaid;
            Engine.logEvent('⚠️ ' + mission.name + ' mission ended early. Earned ' + partialPay + 'g for completed legs.');
            if (typeof UI !== 'undefined' && UI.toast) UI.toast('⚠️ Mission ended early. ' + partialPay + 'g earned.', 'warning');
        }

        player.autoTravelJob = null;
    }

    // Quit an auto-travel job
    function quitAutoTravelJob() {
        if (!player.autoTravelJob) return { success: false, message: 'No active auto-travel mission.' };
        var mission = player.autoTravelJob;

        // Cancel any in-progress travel
        if (player.traveling) {
            player.traveling = false;
            player.travelProgress = 0;
            player.travelDestination = null;
            player.travelRoute = null;
            player.travelTotalDist = 0;
        }

        // Messenger penalty: undelivered letters need to be handed off
        if (mission.type === 'royal_messenger' && mission.letters) {
            var undelivered = mission.letters.filter(function(l) { return !l.delivered; }).length;
            if (undelivered > 0) {
                // Small gold penalty for handing off letters to another messenger
                var penalty = Math.min(player.gold, undelivered * 3);
                player.gold -= penalty;
                Engine.logEvent('📮 Handed off ' + undelivered + ' undelivered letter(s) to a local messenger. Courier fee: ' + penalty + 'g.');
            }
        }

        var earnedSoFar = mission.totalPaid;
        Engine.logEvent('🗺️ Quit ' + mission.name + ' mission. Kept ' + earnedSoFar + 'g from completed stops.');
        if (typeof UI !== 'undefined' && UI.toast) UI.toast('Quit ' + mission.name + '. Kept ' + earnedSoFar + 'g.', 'info');
        player.autoTravelJob = null;

        return { success: true, message: 'Quit ' + mission.name + '. Earned ' + earnedSoFar + 'g for completed legs.' };
    }

    // Get auto-travel job status for UI
    function getAutoTravelStatus() {
        if (!player.autoTravelJob) return null;
        var m = player.autoTravelJob;
        var completedLegs = 0;
        for (var i = 0; i < m.legs.length; i++) {
            if (m.legs[i].workDone) completedLegs++;
        }
        var currentLeg = m.legs[m.currentLeg] || null;
        var currentTown = currentLeg ? Engine.findTown(currentLeg.townId) : null;
        var daysElapsed = Engine.getDay() - m.startDay;

        return {
            type: m.type,
            name: m.name,
            status: m.status,
            currentLeg: m.currentLeg,
            totalLegs: m.legs.length,
            completedLegs: completedLegs,
            currentDescription: currentLeg ? currentLeg.description : '',
            currentDestination: currentTown ? currentTown.name : '?',
            totalPaid: m.totalPaid,
            daysElapsed: daysElapsed,
            isReturn: currentLeg ? currentLeg.isReturn || false : false,
            letters: m.letters || null
        };
    }

    // Get special start status info (for UI)
    function getSpecialStartStatus() {
        var status = null;
        if (player.indentured && player.indentured.active) {
            var daysRemaining = Math.max(0, player.indentured.contractDays - (Engine.getDay() - (player.indentured.startDay || 0)));
            status = { type: 'indentured', icon: '⛓️', label: 'Indentured Servant',
                info: 'Days Remaining: ' + daysRemaining + ' | Debt: ' + player.indentured.debtRemaining + 'g' };
        }
        // Show mandatory military service bar (replaces servitude bar when freed via enlistment)
        if (player.militaryMandatory && player.militaryActive) {
            var milDaysLeft = Math.max(0, (player.militaryServiceEndDay || 0) - Engine.getDay());
            var milYearsLeft = (milDaysLeft / 365).toFixed(1);
            status = { type: 'military_mandatory', icon: '⚔️', label: 'Mandatory Military Service',
                info: 'Service Remaining: ' + milDaysLeft + ' days (' + milYearsLeft + ' years) | Rank: ' + (MILITARY_RANK_LABELS[player.militaryRank] || 'Soldier') };
        }
        if (player.pilgrim && player.pilgrim.active) {
            status = { type: 'pilgrim', icon: '🙏', label: 'Pilgrim',
                info: 'Holy Sites: ' + player.pilgrim.visitedSites.length + '/' + player.pilgrim.holySites.length +
                    ' | Followers: ' + player.pilgrim.followers };
        }
        if (player.shipwrecked && player.shipwrecked.active) {
            status = { type: 'shipwrecked', icon: '🌊', label: 'Shipwrecked',
                info: 'Language: ' + player.shipwrecked.languageSkill + '% | Artifact: ' + (player.shipwrecked.artifactKept ? 'Kept' : 'Sold') };
        }
        if (player.musician && player.musician.active) {
            var maxFame = 0; var maxFameK = '';
            var kingdoms = Engine.getKingdoms();
            for (var ki = 0; ki < kingdoms.length; ki++) {
                var f = player.musician.fame[kingdoms[ki].id] || 0;
                if (f > maxFame) { maxFame = f; maxFameK = kingdoms[ki].name; }
            }
            var totalFans = Object.keys(player.musician.fans).length;
            status = { type: 'musician', icon: '🎵', label: 'Musician',
                info: 'Fame: ' + Math.floor(maxFame) + ' (' + maxFameK + ') | Fans: ' + totalFans + ' | Songs: ' + player.musician.songsComposed.length };
        }
        if (player.militaryLeader && player.militaryLeader.active) {
            var rankLabel = player.militaryLeader.rank;
            var rl = CONFIG.MILITARY_LEADER_RANKS.find(function(r) { return r.id === player.militaryLeader.rank; });
            if (rl) rankLabel = rl.name;
            status = { type: 'military', icon: '⚔️', label: 'Military Leader',
                info: 'Rank: ' + rankLabel + ' | Battles: ' + (player.militaryLeader.battlesAsLeader || 0) + ' | Faint: ' + player.militaryLeader.faintCount };
        }
        if (player.scholar && player.scholar.active) {
            var totalTowns = Engine.getTowns().length;
            var visited = Object.keys(player.scholar.townsVisited).length;
            status = { type: 'scholar', icon: '📚', label: 'Scholar',
                info: 'Towns: ' + visited + '/' + totalTowns + ' | Knowledge: ' + player.scholar.totalKnowledge +
                    ' | Book: ' + (player.scholar.greatBookWritten ? 'Complete!' : 'Not Started') };
        }
        // Show bankruptcy state
        if (player.bankruptcy && player.bankruptcy.active) {
            var bType = player.bankruptcy.type;
            if (bType === 'priest' && player.pilgrim && player.pilgrim.active) {
                status = { type: 'bankruptcy_priest', icon: '🙏', label: 'Bankrupt Priest',
                    info: 'Holy Sites: ' + player.pilgrim.visitedSites.length + '/' + player.pilgrim.holySites.length +
                        ' | Complete pilgrimage to regain freedoms' };
            } else if (bType === 'indenture') {
                // Handled by existing indentured status above
            } else if (bType === 'military') {
                // Handled by existing mandatory military status above
            }
        }
        return status;
    }

