        // Initialization (call after Engine.generate())
        init(world, firstName, lastName, sex, startTownId, startConfig) {
            initPlayer(world, firstName, lastName, sex);
            // Override starting town if specified (from kingdom/town selection)
            if (startTownId) {
                player.townId = startTownId;
                const startTown = Engine.findTown(startTownId);
                if (startTown) {
                    player.citizenshipKingdomId = startTown.kingdomId;
                    player.startingKingdomId = startTown.kingdomId;
                    if (player.citizenshipKingdomId) {
                        player.socialRank[player.citizenshipKingdomId] = 0;
                        player.rankSince[player.citizenshipKingdomId] = 0;
                        player.kingdomResidencyStart[player.citizenshipKingdomId] = 0;
                    }
                }
            }
            initAIMerchants();
            // Apply game start scenario
            if (startConfig) {
                applyGameStart(startConfig);
            }
        },

